-- Poems batch 271
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('ac6b19f0-b591-49be-9249-0febf0007f67','涉世','王鎡','宋','宋诗','song-poetry','','[]','甘苦炎凉已遍經，少年磨洗晚年成。',64,'全唐诗/poet.song.240000.json','["甘苦炎凉已遍經，少年磨洗晚年成。", "脚行險處人都錯，心放寬時事自明。", "閲世興衰天有眼，隨時消長水無情。", "一身收拾歸繩墨，纔動千條萬緒生。"]'),
('40655f7c-b2d7-4f7c-9321-34e1361f229e','吳山旅樓秋望','王鎡','宋','宋诗','song-poetry','','[]','桂香風老鬢颼颼，添著湘羅小夾裘。',64,'全唐诗/poet.song.240000.json','["桂香風老鬢颼颼，添著湘羅小夾裘。", "烟鎖亭臺青嶂曉，露寒簾幕畫堂秋。", "雁來花發芙蓉浦，燕去影疏楊柳樓。", "隔岸梧桐易憔悴，未霜葉落滿河舟。"]'),
('465a012c-d466-48e7-b9f5-28733cec726e','初夏','王鎡','宋','宋诗','song-poetry','','[]','杜鵑啼老萬山紅，天氣於春便不同。',64,'全唐诗/poet.song.240000.json','["杜鵑啼老萬山紅，天氣於春便不同。", "半壁蕉雲收暑雨，一簾絮雪撲晴風。", "燕巢子出雕梁暖，蠶繭蛾生翠箔空。", "閒却香車無採處，欲隨簑笠看田翁。"]'),
('8f7eaf84-57d1-4a66-b82c-29612fc06819','梅雨','王鎡','宋','宋诗','song-poetry','','[]','簷雨篩珠響未休，梅黄天色淡於秋。',64,'全唐诗/poet.song.240000.json','["簷雨篩珠響未休，梅黄天色淡於秋。", "蟲依草褥牆腰語，魚弄荷錢水面遊。", "浸酒藥苗重石甕，濕書松氣入山樓。", "晚晴閒趁漁人去，學把絲竿坐釣舟。"]'),
('a7605e5d-3523-478b-b770-1895e3b8847f','送友竹弟入京','王鎡','宋','宋诗','song-poetry','','[]','送君去作江湖客，我亦心飛逐海鴉。',64,'全唐诗/poet.song.240000.json','["送君去作江湖客，我亦心飛逐海鴉。", "有竹有梅須歇舫，可詩可酒便爲家。", "秦樓夜月聽傳曲，輦路春風看賣花。", "吊古須瞻岳王墓，留題好句入棲霞。"]'),
('1cbbb32b-907e-4c46-b0cd-5b8820eb7a25','客路晚春','王鎡','宋','宋诗','song-poetry','','[]','年年吟帽客他鄉，柳絮飛時日漸長。',64,'全唐诗/poet.song.240000.json','["年年吟帽客他鄉，柳絮飛時日漸長。", "遠樹雲生殘照沒，近梅風重早晨凉。", "桑條带露歸蠶室，花片隨泥上燕梁。", "歷日又催春色去，田家便有插秧忙。"]'),
('96de369b-b495-43f9-832c-45294ac8c249','月洞書屋','王鎡','宋','宋诗','song-poetry','','[]','自詠自書粘壁上，何須古畫與名碑。',32,'全唐诗/poet.song.240000.json','["自詠自書粘壁上，何須古畫與名碑。", "隔牆風落閒花片，日日飛來入硯池。"]'),
('1de9530a-31a3-4cbd-954b-699d464ff10d','高冠獨步','王鎡','宋','宋诗','song-poetry','','[]','棲桀棲塒歲月深，咿咿喔喔放豪音。',32,'全唐诗/poet.song.240000.json','["棲桀棲塒歲月深，咿咿喔喔放豪音。", "九苞彩色丹山鳳，春暖還須報上林。"]'),
('43d11328-e895-41ac-9df1-cfe59493760b','飲散','王鎡','宋','宋诗','song-poetry','','[]','春風吹動漏聲殘，醉後歸來獨倚闌。',32,'全唐诗/poet.song.240000.json','["春風吹動漏聲殘，醉後歸來獨倚闌。", "雨濕落花飛不去，亂紅粘滿石棋盤。"]'),
('781cfd83-8282-4e4a-a820-9646ddcd0d51','凉夜','王鎡','宋','宋诗','song-poetry','','[]','斷階露草濕鳴蛩，桐樹凉生落葉中。',32,'全唐诗/poet.song.240000.json','["斷階露草濕鳴蛩，桐樹凉生落葉中。", "月上小樓人未睡，曲欄敲遍倚西風。"]'),
('0ed90cdc-7991-4d31-a07f-23971c7e15eb','惜別','王鎡','宋','宋诗','song-poetry','','[]','袂分鴛錦夢雙殘，一線啼痕枕未乾。',32,'全唐诗/poet.song.240000.json','["袂分鴛錦夢雙殘，一線啼痕枕未乾。", "門掩青燈人自去，杏花風起落花看。"]'),
('48ecc343-eb40-49ec-8063-3e24ac87a62f','午睡','王鎡','宋','宋诗','song-poetry','','[]','枕書午睡正朦朧，雲翠風凉透葛中。',32,'全唐诗/poet.song.240000.json','["枕書午睡正朦朧，雲翠風凉透葛中。", "喚醒一床蝴蝶夢，軋鴉聲在隔樓東。"]'),
('8137625d-9d51-46e3-b18f-aa7748b840ab','元宵','王鎡','宋','宋诗','song-poetry','','[]','柳院春歸雪未乾，試燈歌巷月痕寒。',32,'全唐诗/poet.song.240000.json','["柳院春歸雪未乾，試燈歌巷月痕寒。", "懶隨翠影紅香走，自買梅花插燭看。"]'),
('4ee3108d-ef60-4434-b4b9-d684aaebe0ec','佳人春思','王鎡','宋','宋诗','song-poetry','','[]','垂鬟不語立花陰，忽向東風淚滿襟。',32,'全唐诗/poet.song.240000.json','["垂鬟不語立花陰，忽向東風淚滿襟。", "長記湖邊寒食節，柳絲曾折贈同心。"]'),
('1f3e0a77-e416-4301-8644-8cbf1aa501cd','春怨','王鎡','宋','宋诗','song-poetry','','[]','倚闌人瘦怨東風，從此吹香夢亦空。',32,'全唐诗/poet.song.240000.json','["倚闌人瘦怨東風，從此吹香夢亦空。", "春色自隨鶑蝶去，楊花飛入畫樓中。"]'),
('63d73e25-d78e-4d26-a30b-ac1dc1c85e6a','春晝','王鎡','宋','宋诗','song-poetry','','[]','晴晝軟風春草香，綠窗人困日初長。',32,'全唐诗/poet.song.240000.json','["晴晝軟風春草香，綠窗人困日初長。", "雙雙燕子飛無力，低傍花陰一带凉。"]'),
('85353887-65b8-406f-a7a2-aedfb116cfb1','春雨','王鎡','宋','宋诗','song-poetry','','[]','綠樹江南啼子規，落花流水洗胭脂。',32,'全唐诗/poet.song.240000.json','["綠樹江南啼子規，落花流水洗胭脂。", "無情風雨朝朝惡，誤却歸來海燕遲。"]'),
('90430b2c-9ad0-420e-abe1-5a77ee5e64dc','春去','王鎡','宋','宋诗','song-poetry','','[]','一簾翠雨柳生烟，金屋無人理管絃。',32,'全唐诗/poet.song.240000.json','["一簾翠雨柳生烟，金屋無人理管絃。", "春去啼鶑留不住，隨花飛過別秋千。"]'),
('3faed394-769f-437c-ad2f-7b6a5ced8e9a','春院','王鎡','宋','宋诗','song-poetry','','[]','柳絲風緊雨痕乾，却怕雙飛燕子寒。',32,'全唐诗/poet.song.240000.json','["柳絲風緊雨痕乾，却怕雙飛燕子寒。", "梨雪吹香春夢遠，有人中酒隔簾看。"]'),
('59908a78-5d06-44a5-9aec-ab9864e36c85','立春','王鎡','宋','宋诗','song-poetry','','[]','泥牛鞭散六街塵，生菜挑來葉葉春。',32,'全唐诗/poet.song.240000.json','["泥牛鞭散六街塵，生菜挑來葉葉春。", "從此雪消風自軟，梅花合讓柳條新。"]'),
('6ba166ea-8a91-4960-86a5-2aa6b07a7369','春日即事','王鎡','宋','宋诗','song-poetry','','[]','清齋飯罷一甌茶，靜聽山蜂報早衙。',32,'全唐诗/poet.song.240000.json','["清齋飯罷一甌茶，靜聽山蜂報早衙。", "日色弄陰雲去住，楮窗香潤落藤花。"]'),
('8b46a33b-464d-4ab9-b6dd-861638110467','春夜家宴','王鎡','宋','宋诗','song-poetry','','[]','燭底裁詞按玉簫，翠宮合唱取腔嬌。',32,'全唐诗/poet.song.240000.json','["燭底裁詞按玉簫，翠宮合唱取腔嬌。", "梨花影護春風暖，不用香薰酒自消。"]'),
('a76ac947-ce86-4650-a272-c9bc0beb4620','暮春即事','王鎡','宋','宋诗','song-poetry','','[]','賣花聲斷雨濛濛，怯酒情懷易得中。',32,'全唐诗/poet.song.240000.json','["賣花聲斷雨濛濛，怯酒情懷易得中。", "燕子自來還自去，胭脂吹老海棠風。"]'),
('9f5948b1-9555-4b6f-9513-9203cfd4bbe9','惜春','王鎡','宋','宋诗','song-poetry','','[]','闌干曲曲柳陰陰，路積殘紅半指深。',32,'全唐诗/poet.song.240000.json','["闌干曲曲柳陰陰，路積殘紅半指深。", "却謝多情雙燕子，飛來飛去說春心。"]'),
('bb6993a2-7395-4365-aa77-a2ebaa8438bf','初夏三首  其一','王鎡','宋','宋诗','song-poetry','','[]','芳歇紅稀蝶懶來，瀟瀟風雨送春回。',32,'全唐诗/poet.song.240000.json','["芳歇紅稀蝶懶來，瀟瀟風雨送春回。", "綠陰如許無人看，軟玉枝頭已有梅。"]'),
('a2047ffe-373a-4c63-95c8-34ada8cd935f','初夏三首  其二','王鎡','宋','宋诗','song-poetry','','[]','牧笛無腔雨似烟，菜花成子日如年。',32,'全唐诗/poet.song.240000.json','["牧笛無腔雨似烟，菜花成子日如年。", "人家火養春蠶快，要趁工夫下早田。"]'),
('9fb89321-86b0-4a36-9ff2-c3b829749990','初夏三首  其三','王鎡','宋','宋诗','song-poetry','','[]','竹鷄啼雨隔林塘，四月山深梅未黄。',32,'全唐诗/poet.song.240000.json','["竹鷄啼雨隔林塘，四月山深梅未黄。", "水近洞門雲氣濕，葛花開上石眠床。"]'),
('019602bc-2c57-4d3a-8524-efd5f57ba4b4','湖邊夏日即事','王鎡','宋','宋诗','song-poetry','','[]','榴花掩映在樓臺，面面軒窗照水開。',32,'全唐诗/poet.song.240000.json','["榴花掩映在樓臺，面面軒窗照水開。", "一路翠萍分未合，採蓮船去釣船來。"]'),
('e53e7318-0262-4f63-9a11-a646172a89fd','水閣納凉','王鎡','宋','宋诗','song-poetry','','[]','雲碧紗厨水閣中，鴛鴦花冷枕玲瓏。',32,'全唐诗/poet.song.240000.json','["雲碧紗厨水閣中，鴛鴦花冷枕玲瓏。", "描金團扇無人用，一陣荷香一陣風。"]'),
('3f418561-893e-4552-a0b2-74c092efd82f','重午','王鎡','宋','宋诗','song-poetry','','[]','絲絲梅雨濕榴花，處處釵符裊鬢鴉。',32,'全唐诗/poet.song.240000.json','["絲絲梅雨濕榴花，處處釵符裊鬢鴉。", "醉聽畫樓思遠曲，艾枝簪滿碧巾紗。"]'),
('373d0104-eff8-40e8-9958-3d9c7fb11917','暑夕三首  其一','王鎡','宋','宋诗','song-poetry','','[]','草蚊聲歇樹鳴螿，碧漢無人夜氣凉。',32,'全唐诗/poet.song.240000.json','["草蚊聲歇樹鳴螿，碧漢無人夜氣凉。", "起向翠爐更宿炭，一絲沉水有殘香。"]'),
('7abd1771-07fd-4b7c-b7ee-fcff6873089e','暑夕三首  其二','王鎡','宋','宋诗','song-poetry','','[]','枕石雲邊睡一場，蘚花泉洞碧松香。',32,'全唐诗/poet.song.240000.json','["枕石雲邊睡一場，蘚花泉洞碧松香。", "朱門正役風車苦，不識山中有此凉。"]'),
('e98b8423-9fca-47b3-9634-e9bcc26b7bd8','暑夕三首  其三','王鎡','宋','宋诗','song-poetry','','[]','夜深月曬碧荷香，傍水亭臺易得凉。',32,'全唐诗/poet.song.240000.json','["夜深月曬碧荷香，傍水亭臺易得凉。", "更剪遮窗蕉葉去，放教山影入藤牀。"]'),
('5787018b-2521-4fdc-bf50-85d9d4c6a78a','立秋','王鎡','宋','宋诗','song-poetry','','[]','西風吹縐碧紗衣，金井梧桐昨夜飛。',32,'全唐诗/poet.song.240000.json','["西風吹縐碧紗衣，金井梧桐昨夜飛。", "自汲井花調藥罷，却簪秋葉滿頭歸。"]'),
('e495eca9-0dfa-4d28-9ae9-dcd710df85b9','秋興','王鎡','宋','宋诗','song-poetry','','[]','水影沉雲冷碧天，自撐小艇摘湖蓮。',32,'全唐诗/poet.song.240000.json','["水影沉雲冷碧天，自撐小艇摘湖蓮。", "忽然吟得西風句，正在斜陽落雁邊。"]'),
('fdc6e586-4197-4324-927e-1abd1f23e846','七夕','王鎡','宋','宋诗','song-poetry','','[]','綵樓簾影夜沉沉，一片篩凉月似金。',32,'全唐诗/poet.song.240000.json','["綵樓簾影夜沉沉，一片篩凉月似金。", "倚得畫欄和袖暖，看人兒女學穿針。"]'),
('daa9128d-6b5c-44ce-91ad-50a6ebece6eb','秋夜','王鎡','宋','宋诗','song-poetry','','[]','桂香吹老月中秋，人在西風雁過樓。',32,'全唐诗/poet.song.240000.json','["桂香吹老月中秋，人在西風雁過樓。", "半夜枕寒清夢斷，銀河影掛玉簾鈎。"]'),
('7bc1e1cf-1a08-4d6e-935b-cf072bfb349b','旅邸秋晚二首  其一','王鎡','宋','宋诗','song-poetry','','[]','夜深玉樹不啼鴉，照影殘燈客夢家。',32,'全唐诗/poet.song.240000.json','["夜深玉樹不啼鴉，照影殘燈客夢家。", "歸計未成秋又去，水邊羞見雁紅花。"]'),
('66ae8e46-e980-4872-9a6c-80247a819cce','旅邸秋晚二首  其二','王鎡','宋','宋诗','song-poetry','','[]','井梧敲盡石闌風，放入斜陽水底紅。',32,'全唐诗/poet.song.240000.json','["井梧敲盡石闌風，放入斜陽水底紅。", "秋思漸消離思長，一聲過雁翠樓東。"]'),
('8734106a-a9b3-4ca3-825c-dd0fd67187e6','冬暮客中','王鎡','宋','宋诗','song-poetry','','[]','典盡寒衣未得歸，客囊惟有带來詩。',32,'全唐诗/poet.song.240000.json','["典盡寒衣未得歸，客囊惟有带來詩。", "夜深月照回家夢，怕殺梅花笛又吹。"]'),
('8bd2ddb5-8d5a-4bb1-bf44-58e2d495d0e4','雪夜二首  其一','王鎡','宋','宋诗','song-poetry','','[]','松屋篝燈伴夜闌，閉門不管雪花寒。',32,'全唐诗/poet.song.240000.json','["松屋篝燈伴夜闌，閉門不管雪花寒。", "調朱旋滴梅瓶水，讀過唐詩再點看。"]'),
('b490fc0b-fbd7-4fee-8580-6ca2bcca245b','雪夜二首  其二','王鎡','宋','宋诗','song-poetry','','[]','落在空中似雨飛，成花因被緊風吹。',32,'全唐诗/poet.song.240000.json','["落在空中似雨飛，成花因被緊風吹。", "銷金帳掩紅嬌處，暖護歌聲醉不知。"]'),
('ddf9751f-3222-40df-b99f-6fecd208a055','冬暄','王鎡','宋','宋诗','song-poetry','','[]','小春氣候不相同，晴却無寒有軟風。',32,'全唐诗/poet.song.240000.json','["小春氣候不相同，晴却無寒有軟風。", "最是湘桃驚暖誤，霜邊偷染一梢紅。"]'),
('2fa2f71b-a659-4634-8aa8-60ccb8217b0b','白雞冠','王鎡','宋','宋诗','song-poetry','','[]','旌陽仙去墜棲籠，竊藥曾歸草木中。',32,'全唐诗/poet.song.240000.json','["旌陽仙去墜棲籠，竊藥曾歸草木中。", "餐了瓊霜因換雪，至今頂內不粘紅。"]'),
('bdfc90c1-8fa0-4f41-949c-4cd3cfb6e025','白蘭','王鎡','宋','宋诗','song-poetry','','[]','楚客曾因葬水中，骨寒化出玉玲瓏。',32,'全唐诗/poet.song.240000.json','["楚客曾因葬水中，骨寒化出玉玲瓏。", "生時不飲香魂醒，難著春風半點紅。"]'),
('38a3074b-c71c-43ff-9480-ae2598ef2d41','山茶','王鎡','宋','宋诗','song-poetry','','[]','蠟包綠萼日纔烘，放出千枝鶴頂紅。',32,'全唐诗/poet.song.240000.json','["蠟包綠萼日纔烘，放出千枝鶴頂紅。", "待得雪晴春信透，翠雲圍繞錦屏風。"]'),
('bcac382d-7bde-4aab-99b5-cc8238ec9001','水仙','王鎡','宋','宋诗','song-poetry','','[]','銀臺香露洗金巵，玉佩飄飄醉欲飛。',32,'全唐诗/poet.song.240000.json','["銀臺香露洗金巵，玉佩飄飄醉欲飛。", "想是龍宮春宴罷，凌波歸早濕綃衣。"]'),
('5767555a-383a-426c-8b1d-3e7a2782a0b3','鳳仙','王鎡','宋','宋诗','song-poetry','','[]','鳳簫聲斷綵鸞來，弄玉仙遊竟不回。',32,'全唐诗/poet.song.240000.json','["鳳簫聲斷綵鸞來，弄玉仙遊竟不回。", "英氣至今留世上，年年化作此花開。"]'),
('db44c13a-1717-4eba-8f13-916ca73faf5d','白杜鵑','王鎡','宋','宋诗','song-poetry','','[]','雪玉層層映翠微，蜀王心事此花知。',32,'全唐诗/poet.song.240000.json','["雪玉層層映翠微，蜀王心事此花知。", "染紅不到枝頭上，想是啼鵑血盡時。"]'),
