('1cdc32c0-a92f-44ac-a9dd-ec0def31f492','蜀葵','王鎡','宋','宋诗','song-poetry','','[]','片片川羅濕露凉，染紅纔了染鵝黄。',32,'全唐诗/poet.song.240000.json','["片片川羅濕露凉，染紅纔了染鵝黄。", "花根疑是忠臣骨，開出傾心向太陽。"]'),
('5aaae42b-f243-47ea-82ed-9e97c2c2aff7','桂','王鎡','宋','宋诗','song-poetry','','[]','金蟲鏤月影玲瓏，璧葉將秋鎖翠櫳。',32,'全唐诗/poet.song.240000.json','["金蟲鏤月影玲瓏，璧葉將秋鎖翠櫳。", "昨夜樓臺風露冷，幾人魂夢入林中。"]'),
('83963ca1-c999-413c-82bd-847ea19db294','敗荷','王鎡','宋','宋诗','song-poetry','','[]','葉無圓影柄無香，收盡蓮歌冷碧塘。',32,'全唐诗/poet.song.240000.json','["葉無圓影柄無香，收盡蓮歌冷碧塘。", "一片傷心雲錦地，也曾遮月宿鴛鴦。"]'),
('b9a00c96-225a-4845-979e-a337ee3af1de','茉莉','王鎡','宋','宋诗','song-poetry','','[]','炎州分得冰花腦，來伴湘波六月凉。',32,'全唐诗/poet.song.240000.json','["炎州分得冰花腦，來伴湘波六月凉。", "醉折一枝簪鬢睡，曉來印却枕痕香。"]'),
('d4cdcc88-601f-4657-93e7-01fa9e6af66a','露荷','王鎡','宋','宋诗','song-poetry','','[]','滿湖雲氣曉生寒，蘸影蒸香潤石闌。',32,'全唐诗/poet.song.240000.json','["滿湖雲氣曉生寒，蘸影蒸香潤石闌。", "萬斛銀珠無用處，翠盤擎到日光乾。"]'),
('46618896-5008-4ecf-a302-99a316f3dfa9','梅花三首  其一','王鎡','宋','宋诗','song-poetry','','[]','茅屋寂寂烟冥冥，紙帳曉眠人未起。',32,'全唐诗/poet.song.240000.json','["茅屋寂寂烟冥冥，紙帳曉眠人未起。", "天風吹動笛聲寒，春滿江南冰雪裏。"]'),
('5cfc9b6e-a1be-443d-bc46-661c93e91caf','梅花三首  其二','王鎡','宋','宋诗','song-poetry','','[]','溪心印影月朦朧，樹剝霜皮一半空。',32,'全唐诗/poet.song.240000.json','["溪心印影月朦朧，樹剝霜皮一半空。", "只見開時冰雪凍，不知花裏有春風。"]'),
('39a29792-e5ce-4164-8db4-cb5c1c79193a','梅花三首  其三','王鎡','宋','宋诗','song-poetry','','[]','野水橋邊折得看，花頭開盡雪痕乾。',32,'全唐诗/poet.song.240000.json','["野水橋邊折得看，花頭開盡雪痕乾。", "剛風摇動仙雲墜，一夜香深玉骨寒。"]'),
