('c4fee624-ecea-43b0-8784-3044dc718bd6','燕','王鎡','宋','宋诗','song-poetry','','[]','野棠開后忽飛來，又趁秋風海上回。',32,'全唐诗/poet.song.240000.json','["野棠開后忽飛來，又趁秋風海上回。", "到國依棲應有夢，巢空月落舊樓臺。"]'),
('cff5df73-8609-4063-955e-526fd587784f','螢','王鎡','宋','宋诗','song-poetry','','[]','竹風吹動草根塵，熠熠高低自照身。',32,'全唐诗/poet.song.240000.json','["竹風吹動草根塵，熠熠高低自照身。", "每夜囊盛光到曉，書齋送與少燈人。"]'),
('bcc4c2f6-224d-47c7-86c5-928c137ac362','秦鏡','王鎡','宋','宋诗','song-poetry','','[]','色带金銅眩怪青，照人心膽已曾靈。',32,'全唐诗/poet.song.240000.json','["色带金銅眩怪青，照人心膽已曾靈。", "鑄時便有山東影，不使秦皇見亂形。"]'),
('93e161cf-bfb8-4fb1-b18b-0c0a5789b1d5','四皓','王鎡','宋','宋诗','song-poetry','','[]','安罷儲宮便又回，商山高卧白雲堆。',32,'全唐诗/poet.song.240000.json','["安罷儲宮便又回，商山高卧白雲堆。", "劉家大事雖能定，也墮留侯計出來。"]'),
('2e47d4ee-a5a7-4405-9378-fce3458ce274','咸陽','王鎡','宋','宋诗','song-poetry','','[]','劫灰飛出祖龍宮，六國强吞總是空。',32,'全唐诗/poet.song.240000.json','["劫灰飛出祖龍宮，六國强吞總是空。", "獨有椒蘭香不散，春風移過草花中。"]'),
('060ee27e-958a-4ce1-a93c-1eba06beca24','馬嵬','王鎡','宋','宋诗','song-poetry','','[]','梨花魂醉草傷秋，玉笛霓裳事已休。',32,'全唐诗/poet.song.240000.json','["梨花魂醉草傷秋，玉笛霓裳事已休。", "誰信一勾羅襪內，能藏天寶許多愁。"]'),
('11007e04-b13c-43ab-88c6-74b5a89e57b1','夢中見','王鎡','宋','宋诗','song-poetry','','[]','鶴髮老人携紫竹，往來花下歌春曲。',32,'全唐诗/poet.song.240000.json','["鶴髮老人携紫竹，往來花下歌春曲。", "春去春來花自開，一聲杜宇巴山綠。"]'),
