('4e32b71b-97e4-4cf5-ac2e-8c8dd173e6b7','遊仙詞三十三首  其二二','王鎡','宋','宋诗','song-poetry','','[]','金光倒射玉樓臺，海上仙人採藥回。',32,'全唐诗/poet.song.240000.json','["金光倒射玉樓臺，海上仙人採藥回。", "花下閒談尸解事，葛翁忽跨白馿來。"]'),
('1f06340f-43e6-4727-a772-95f0b596572d','遊仙詞三十三首  其二三','王鎡','宋','宋诗','song-poetry','','[]','華山九節玉菖蒲，千度秋風葉不枯。',32,'全唐诗/poet.song.240000.json','["華山九節玉菖蒲，千度秋風葉不枯。", "洞裏久餐松乳饜，秦人還識此根無。"]'),
('75a2730e-f978-4f43-b404-d6764924c309','遊仙詞三十三首  其二四','王鎡','宋','宋诗','song-poetry','','[]','三尸魄重藥難醫，一箇丹瓢一劍飛。',32,'全唐诗/poet.song.240000.json','["三尸魄重藥難醫，一箇丹瓢一劍飛。", "歷盡大羅天下路，無人肯喫又藏歸。"]'),
('ff370246-3948-401f-b869-453d3868398c','遊仙詞三十三首  其二五','王鎡','宋','宋诗','song-poetry','','[]','靈液長流滿地香，洞中多是散仙房。',32,'全唐诗/poet.song.240000.json','["靈液長流滿地香，洞中多是散仙房。", "金爐煮就金精汁，欲獻元君未敢嘗。"]'),
('7d20aa58-fcee-43eb-8f72-3bf97becb080','遊仙詞三十三首  其二六','王鎡','宋','宋诗','song-poetry','','[]','天詔旌陽上玉宮，功成鷄犬亦無蹤。',32,'全唐诗/poet.song.240000.json','["天詔旌陽上玉宮，功成鷄犬亦無蹤。", "獨留鐵柱難飛去，要鎖東溟老毒龍。"]'),
('bc6477e3-496d-44f4-9c07-54f34a39d4bb','遊仙詞三十三首  其二七','王鎡','宋','宋诗','song-poetry','','[]','飛佩乘風海上遊，麟洲有路透炎州。',32,'全唐诗/poet.song.240000.json','["飛佩乘風海上遊，麟洲有路透炎州。", "仙人養就千年鼠，時採長毛織火裘。"]'),
('86478b06-6514-42bd-a4dc-d0217ed8e23f','遊仙詞三十三首  其二八','王鎡','宋','宋诗','song-poetry','','[]','金甲雷丁出巽宮，丹幢翠節擁靈童。',32,'全唐诗/poet.song.240000.json','["金甲雷丁出巽宮，丹幢翠節擁靈童。", "五更飛去雌雄劍，一夜鹽池碧水紅。"]'),
('329cee89-f316-4945-8eb1-7f49341416ba','遊仙詞三十三首  其二九','王鎡','宋','宋诗','song-poetry','','[]','仙令王喬面玉墀，天香薰透綠荷衣。',32,'全唐诗/poet.song.240000.json','["仙令王喬面玉墀，天香薰透綠荷衣。", "誰知脚底青絲舄，化作雙鳬傍日飛。"]'),
('f7e07fcd-009b-4b98-9141-722e6435d9df','遊仙詞三十三首  其三○','王鎡','宋','宋诗','song-poetry','','[]','龍腦包薰滿洞香，韓湘酒熟在瑶缸。',32,'全唐诗/poet.song.240000.json','["龍腦包薰滿洞香，韓湘酒熟在瑶缸。", "幾番醉怕春雲暖，閒却鮫綃紫石窗。"]'),
('876d9bf4-5079-44fc-9c3f-2ab1dc4da381','遊仙詞三十三首  其三一','王鎡','宋','宋诗','song-poetry','','[]','天花子落月中樓，香滿三千世界秋。',32,'全唐诗/poet.song.240000.json','["天花子落月中樓，香滿三千世界秋。", "下有老人常斫樹，至今玉斧不曾修。"]'),
('5c5e1ed9-4359-4125-b4fc-0cc3f158927a','遊仙詞三十三首  其三二','王鎡','宋','宋诗','song-poetry','','[]','修成功行滿三千，或在人間或在天。',32,'全唐诗/poet.song.240000.json','["修成功行滿三千，或在人間或在天。", "留下九還丹一粒，城南老樹得昇仙。"]'),
('37021886-54c8-4238-8507-7522d9c40df8','遊仙詞三十三首  其三三','王鎡','宋','宋诗','song-poetry','','[]','月娥樹上赤花香，羽帳瓊樓子夜長。',32,'全唐诗/poet.song.240000.json','["月娥樹上赤花香，羽帳瓊樓子夜長。", "玉兔白蛙身不老，水銀一臼結玄霜。"]'),
('ad0b975c-e881-48c3-b4ed-d853e9e40342','長生草爲葉峭峰賦','王鎡','宋','宋诗','song-poetry','','[]','唐時呂巖叟，換骨成神仙。',163,'全唐诗/poet.song.240000.json','["唐時呂巖叟，換骨成神仙。", "遺丹傳老樹，變化延其年。", "丹香忽融液，散入蒼崖巔。", "長生孕靈草，莖葉何鮮鮮。", "枯根掛碧落，吞吐流虛烟。", "不受水土力，不隨寒暑遷。", "誰能登雲梯，移來此簷邊。", "凡花與群木，麗質徒娟娟。", "彭澤雖愛菊，兩院荒金錢。", "濂溪空愛荷，開落秋風前。", "峭峰山中客，道眼明先天。", "一線同壽眼，萬古長綿延。", "君不見祖龍癡欲採爲藥，海山何處駕樓船。"]'),
('379e7065-23f1-40c0-91b2-bee92630c5f1','宿青草渡','王鎡','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','夜深猶有去來船，長江倒影涵青天。',64,'全唐诗/poet.song.240000.json','["夜深猶有去來船，長江倒影涵青天。", "鶴寒夢覺松梢月，流水殘梅浸香雪。", "山翁呼兒沽酒歸，獨客有感未睡時。", "提劍起舞摇斗宿，醉裏天風生兩袖。"]'),
('7b8091a4-8227-4b65-9651-ed221067a765','句','王鎡','宋','宋诗','song-poetry','','[]','林間望斷松梢路，白鶴真人尚未還。',16,'全唐诗/poet.song.240000.json','["林間望斷松梢路，白鶴真人尚未還。"]'),
('4f0eaf02-abaf-4a1d-8d2c-ede3b735e486','贈月洞先生','葉碧峰','宋','宋诗','song-poetry','','[]','跳出塵關百念輕，大元羽士宋儒生。',64,'全唐诗/poet.song.240000.json','["跳出塵關百念輕，大元羽士宋儒生。", "易參羲聖通玄妙，詩比唐人並駕行。", "咒水灑時天地浄，符文書處鬼神驚。", "洞中靜夜天留月，心與梅花一樣清。"]'),
('d2d82acc-4e62-4994-a60c-00f1a746dfcc','句  其一','李大同','宋','宋诗','song-poetry','','[]','曾上蓬萊第一峰，夕陽留住且從容。',16,'全唐诗/poet.song.240000.json','["曾上蓬萊第一峰，夕陽留住且從容。"]'),
('dbbe3b18-a0f6-4021-8302-d67c2b816a34','句  其二','李大同','宋','宋诗','song-poetry','','[]','鹿脚花去泣關山，回首沉香一夢閒。',16,'全唐诗/poet.song.240000.json','["鹿脚花去泣關山，回首沉香一夢閒。"]'),
('12a112e8-fbc4-4ab9-95d2-e57c74baa367','悼亡女','韋居安','宋','宋诗','song-poetry','','[]','視死如歸不受污，今無彤管爲伊書。',32,'全唐诗/poet.song.240000.json','["視死如歸不受污，今無彤管爲伊書。", "倉皇父子終天訣，菱角塘邊孔氏居。"]'),
('73d7288e-651d-48ff-9015-32f334d064ac','寄魏菊莊慶之','韋居安','宋','宋诗','song-poetry','','[]','一莊純種菊，此地著詩仙。',48,'全唐诗/poet.song.240000.json','["一莊純種菊，此地著詩仙。", "再世陶元亮，三生魏仲先。", "餐英知正味，飲水得長年。", "每見君吟稿，予懷亦灑然。"]'),
('e93329e8-106d-418f-a805-f45e973a50db','景定壬戌冬得數椽于城南慈感渡側詢之故老云距賈耘老舊址不遠因作五言八句','韋居安','宋','宋诗','song-poetry','','[]','卜居求靜處，喜傍碧溪灣。',48,'全唐诗/poet.song.240000.json','["卜居求靜處，喜傍碧溪灣。", "隔岸高低柳，當軒遠近山。", "天開圖畫久，人共水雲閒。", "聞說賈耘老，舊曾居此間。"]'),
('cd79b755-13a3-40d7-a5c1-3136b30886e6','句','方君遇','宋','宋诗','song-poetry','','[]','是有命焉非倖致，不知我者謂何求。',16,'全唐诗/poet.song.240000.json','["是有命焉非倖致，不知我者謂何求。"]'),
('e1fe0b1d-2563-49ab-86e4-3ea849ae3240','溪居夜月','何洪','宋','宋诗','song-poetry','','[]','茅屋瀕溪只數椽，護籬黄犬枕莎眠。',32,'全唐诗/poet.song.240000.json','["茅屋瀕溪只數椽，護籬黄犬枕莎眠。", "柴扉不掩松梢月，恐有山陰訪雪船。"]'),
('dec32210-fc13-42e6-964b-f3102558aada','口占','柯應東','宋','宋诗','song-poetry','','[]','不作棟梁用，偏尋山寺居。',24,'全唐诗/poet.song.240000.json','["不作棟梁用，偏尋山寺居。", "但聞聲似鼓，誰識木爲魚。"]'),
('74c06929-f121-4420-bae7-ecda94f62b94','壺山','柯應東','宋','宋诗','song-poetry','','[]','方壺久伏海中洲，湧出高山不計秋。',64,'全唐诗/poet.song.240000.json','["方壺久伏海中洲，湧出高山不計秋。", "峰上今猶蠔带石，穴邊時有蟹尋湫。", "雲飛巖岫來龍聚，風送潮聲入虎邱。", "景物無窮供眼界，一鈎新月促歸舟。"]'),
('ef2dc5b4-f260-4594-9f80-9e69e1ff3254','武夷','趙時𣓨','宋','宋诗','song-poetry','','[]','千古武夷山，來尋九轉丹。',48,'全唐诗/poet.song.240000.json','["千古武夷山，來尋九轉丹。", "雲封拜章石，月洗步虛壇。", "白玉何勞煮，丹霞自可餐。", "未窮溪九曲，頼有畫圖看。"]'),
('60b72a8b-94db-481e-ab9b-df8bfa6b1dcd','句','倪文一','宋','宋诗','song-poetry','','[]','編籬已種淵明菊，鑿沼還栽茂叔蓮。',16,'全唐诗/poet.song.240000.json','["編籬已種淵明菊，鑿沼還栽茂叔蓮。"]'),
('1e6bb3c6-5a58-4205-a2a8-46da33264189','題三易備遺','葛寅炎','宋','宋诗','song-poetry','','[]','誰鑿混沌竅，龍馬出澄淵。',288,'全唐诗/poet.song.240000.json','["誰鑿混沌竅，龍馬出澄淵。", "篤生羲文聖，立極先後天。", "三三羑所演，兩兩山之連。", "不假人安排，自有天渾全。", "咸陽烈焰起，斯文獨不烟。", "中更九師斸，慘於秦火然。", "言湮道隨裂，爾來千餘年。", "皇乎鉅宋興，奎聚五珠聯。", "天子圖出地，復鍾二鉅賢。", "門外儼立雪，窩中閑弄丸。", "數加一倍法，書得七分傳。", "文後不爲後，羲先不爲先。", "嗚呼中天易，鎖簧透黄軒。", "厥數則用六，是爲歸藏焉。", "觀象歷可紀，聆鳳律相宣。", "芸芸茁九地，終至碩果堅。", "薛野鳦未乳，鼎湖龍已仙。", "敦哉司徒氏，而把五教權。", "滔滔祚其海，始達溜涓涓。", "韜光夏臺出，撥亂南巢遷。", "執中亦建中，道體無些偏。", "義禮兩夾持，以此裕我昆。", "姓別取諸子，世號遽以千。", "甲庚至丁乙，天潢衍慶源。"]'),
('a71e25ea-039f-45cb-bf71-81f007a101d3','題沃洲山字巖','石余亨','宋','宋诗','song-poetry','','[]','前輩高風不可追，自來陵谷互推移。',32,'全唐诗/poet.song.240000.json','["前輩高風不可追，自來陵谷互推移。", "却憐當日題名者，不及征南辦兩碑。"]'),
('899a4923-738d-4907-87d9-926a3ab4b8eb','傷丁氏故基題一絕于太虛堂','莫崙','宋','宋诗','song-poetry','','[]','疏雨斑斑灑葉舟，前山喚客作清游。',32,'全唐诗/poet.song.240000.json','["疏雨斑斑灑葉舟，前山喚客作清游。", "芳華消歇春歸後，野草荒田一片愁。"]'),
('beacfd01-7ec0-4b67-b3bb-bcc813204987','挂冠  其一','李瓘','宋','宋诗','song-poetry','','[]','古云學古斯入官，我見學易而官難。',144,'全唐诗/poet.song.240000.json','["古云學古斯入官，我見學易而官難。", "平生透破夢覺關，本來面目只儒酸。", "吾親不侍若爲歡，不如歸去卧林間。", "殿前三策瀝忠肝，多謝皇恩天地寬。", "戲衫卸下白衣還，扁舟飛過子陵灘。", "前修亦有逋與摶，聖世與之俱空閑。", "何物种放太厚顔，山鬼移文伐其姦。", "此行無復出閩山，休音息影谷之盤。", "今朝釃酒酹雩壇，便向錢塘門挂冠。"]'),
('1f053ea5-f814-4ad9-bfa0-30c4b2b1085e','挂冠  其二','李瓘','宋','宋诗','song-poetry','','[]','有手須搴龍衮衣，有頭須叩九階墀。',71,'全唐诗/poet.song.240000.json','["有手須搴龍衮衣，有頭須叩九階墀。", "有口須讀離騷詞，有腹須飽商山芝。", "有身不願掛綠皮，笑問此身到何之。", "石室山之顛，重湖水之湄，陶公云樂夫天命復奚疑。"]'),
('eed88b0b-93fa-4bf6-9f24-8e3882208564','過臞庵','趙師魯','宋','宋诗','song-poetry','','[]','竹木清華處，林亭曲折開。',48,'全唐诗/poet.song.240000.json','["竹木清華處，林亭曲折開。", "泉聲經雨雜，石勢學雲頹。", "留客煮新茗，敲泥啟舊醅。", "子猷去已久，信宿爲誰來。"]'),
('3a0497fe-ce76-4187-baf9-c68df8fc7236','挽故知容州朝請陶公','危彪','宋','宋诗','song-poetry','','[]','世態紛紛等觸蠻，惟公打透利名關。',64,'全唐诗/poet.song.240000.json','["世態紛紛等觸蠻，惟公打透利名關。", "八州不作士衡夢，三徑謾爲元亮還。", "苦淡平生安北巷，孤高一節照西山。", "想應精爽難埋沒，只在青松白石間。"]'),
('b8219e5a-a656-46ef-b5bd-f1d73f77ccd5','上之回','趙文','宋','宋诗','song-poetry','','[]','動皇輿，回中道。',56,'全唐诗/poet.song.240000.json','["動皇輿，回中道。", "龍爲驅，虎爲導。", "樂蕃釐，祠雍後。", "息甘泉，飫天酒。", "澹穆清，冰熱惱。", "四夷服，咸稽首。", "臣三祝，皇萬壽。"]'),
('d0158ad6-201c-49f5-928f-1466002a1c5b','石留','趙文','宋','宋诗','song-poetry','','[]','江流湯湯，日夜不休。',50,'全唐诗/poet.song.240000.json','["江流湯湯，日夜不休。", "瞿塘灧澦，屹然不流。", "人心人心，反覆難任。", "昨日朱絲琴，今日白頭吟。", "望夫石，留到今。"]'),
('d509aa15-dc39-4bb9-9de8-41eb561c3a39','邯鄲才人嫁爲廝養卒婦','趙文','宋','宋诗','song-poetry','','[]','鴛鴦異野鶩，鳳凰非山鷄。',100,'全唐诗/poet.song.240000.json','["鴛鴦異野鶩，鳳凰非山鷄。", "物生各有偶，非偶不並棲。", "昔爲叢臺人，今爲圉者妻。", "亦知久當棄，無乃太不齊。", "同時歌舞人，何異玉與泥。", "失身已至斯，違天將安歸。", "俛首祇自羞，有聲不敢啼。", "何緣夢到君王側，徹夜不眠聞馬嘶。"]'),
('b3c45039-326a-42fc-bd20-c18787c3ca97','遠如期','趙文','宋','宋诗','song-poetry','','[]','遠如期，近可知。',92,'全唐诗/poet.song.240000.json','["遠如期，近可知。", "如何咫尺間，朝之所約夕背之。", "千言萬語托死生，轉眼已若行路人。", "問之何遽至如許，往往或起秋毫爭。", "財利誠已重，仁義誠已輕。", "昨日弟與兄，今日胡與秦。", "遠如期，古來惟是山陽范巨卿。"]'),
('07765287-c289-4960-9053-466a78b52206','陌上桑','趙文','宋','宋诗','song-poetry','','[]','采采陌上桑，採之不盈筐。',108,'全唐诗/poet.song.240000.json','["采采陌上桑，採之不盈筐。", "云何不盈筐，歡子在中腸。", "車馬從何來，云是大國王。", "呼妾欲共載，恐惕涕沾裳。", "君民分固嚴，敢亂夫婦綱。", "有罪妾當誅，寧當薦匡牀。", "夫君即我天，豈必侍中郎。", "再拜前致詞，蠶饑采桑忙。", "王其早還宮，宮中多艷妝。"]'),
('b81a6200-d564-4542-b7ad-0432094be34d','秋胡行','趙文','宋','宋诗','song-poetry','','[]','五日伉儷情，五年離別腸。',96,'全唐诗/poet.song.240000.json','["五日伉儷情，五年離別腸。", "歸舍不數武，少忍庸何傷。", "如何甘旨費，乃作犯禮償。", "桑者不有躬，何以奉高堂。", "穢行誠已醜，寧復可同牀。", "濯之清泠淵，死之留芬芳。", "念姑詎忍別，引决涕霑裳。", "寄言後來者，好事懷金郎。"]'),
('92012b6f-cf7b-4c04-b3c3-8c514cfbf431','勾踐夫人歌','趙文','宋','宋诗','song-poetry','','[]','君爲王，我爲后，結髮相從期白首。',108,'全唐诗/poet.song.240000.json','["君爲王，我爲后，結髮相從期白首。", "君爲奴，我爲婢，人間反覆何容易。", "爲婢不離家，爲奴去適吳。", "死生未可測，離別在斯須。", "君謂妾勿悲，忍恥乃良圖。", "自憐兒女情，能不啼烏烏。", "仰看庭前樹，一歲一榮枯。", "與君若有重榮日，匆匆未可棄褕翟。"]'),
('df6d97ef-0f0f-4e30-a93a-762c0473950e','河之水','趙文','宋','宋诗','song-poetry','','[]','河之水，深復深。',126,'全唐诗/poet.song.240000.json','["河之水，深復深。", "舟以濟，猶難諶。", "被髮之叟，狂不可鍼。", "豈無一壺，水力難任。", "與公同匡牀，恨不挽公襟。", "亂流欲渡，直下千尋。", "我泣眼爲枯，我哭聲爲瘖。", "投身以從公，豈不畏胥沉。", "同歸尚可忍，獨生亦難禁。", "公死狂，妾死心。", "蛟龍食骨有時盡，惟有妾心無古今。", "河之水，深復深。"]'),
('80862874-7ef3-47a3-b340-308d9ab7d851','上陵','趙文','宋','宋诗','song-poetry','','[]','上古陵，古陵無可上。',64,'全唐诗/poet.song.240000.json','["上古陵，古陵無可上。", "苔雨繡澀，草煙悽愴。", "鴟鴞鳴荒林，狐狸穴空壙。", "豐碑去梁何處津，堲周作竈誰家煬。", "不如東鄰一抔土，樵牧侵陵白官府。"]'),
('c0678493-34ee-4728-a590-04dffd058a1d','昭君詞','趙文','宋','宋诗','song-poetry','','[]','蜀江洗妍姿，萬里獻君王。',172,'全唐诗/poet.song.240000.json','["蜀江洗妍姿，萬里獻君王。", "君王不我幸，棄置何怨傷。", "君王要寧胡，借問誰能行。", "女伴各懼怯，畏此道路長。", "慨然欲自往，詎忍別恩光。", "倘於國有益，尚勝死空房。", "行行涉沙漠，風霜落紅妝。", "得爲胡閼氏，揣分已過當。", "單于感漢恩，邊境得安康。", "一朝所天死，掩泣涕沾裳。", "胡俗或妻母，何異豺與狼。", "仰天自引决，愛此夫婦綱。", "大忠與大義，二者俱堂堂。", "可憐千古無人說，只道琵琶能斷腸。"]'),
('025576b5-6ac9-469a-ab27-b755ebee874e','野鷹來歌','趙文','宋','宋诗','song-poetry','','[]','野鷹來，高臺下。',92,'全唐诗/poet.song.240000.json','["野鷹來，高臺下。", "天寒鳥死狐兔伏，枯梢啄雪何爲者。", "宜城有酒煦爾寒，格高鞲暖肉不乾，終日臂爾夜宿安。", "野鷹來，山中忍饑良獨難。", "天陰日落雪糢糊，有虎有虎雄當塗，兩猿不飽睨我雛。", "鷹不來，將奈何。"]'),
('724699cb-880f-48c6-ad0f-7c9f02f39f87','丁督護曲  其一','趙文','宋','宋诗','song-poetry','','[]','丁督護，爲我行。',32,'全唐诗/poet.song.240000.json','["丁督護，爲我行。", "去時馬上郎，今作野外殤。", "男兒肯斷頭，歸女肯斷腸。"]'),
('20303e42-8ad8-4754-b1ac-d162415c7b07','丁督護曲  其二','趙文','宋','宋诗','song-poetry','','[]','丁督護，聽我語。',28,'全唐诗/poet.song.240000.json','["丁督護，聽我語。", "欲從君，臂不羽。", "嫁時所結髮，剪之隨君去。"]'),
('d4221f16-6961-4140-a1d3-1db1739eae79','丁督護曲  其三','趙文','宋','宋诗','song-poetry','','[]','丁督護，念我苦。',28,'全唐诗/poet.song.240000.json','["丁督護，念我苦。", "未亡人，殤鬼婦。", "古若無銜冤，乾坤無風雨。"]'),
('b2b575c3-ac6b-44ef-91fb-9d2bf35929af','法壽樂歌','趙文','宋','宋诗','song-poetry','','[]','西雲垂天飛流黄，寶鬘百萬隨風揚，帝居摩醯首羅鄉。',136,'全唐诗/poet.song.240000.json','["西雲垂天飛流黄，寶鬘百萬隨風揚，帝居摩醯首羅鄉。", "采女如花侍帝旁，珠啼玉唾天花香，澹然神情無世妝。", "下視邢尹紛醒狂，梵唄琅琅出清吭，天庖供饌薦豆觴。", "帝飲食之壽以康，恒沙世界俱來王，天王神聖臣忠良。", "春風萬里酣耕桑，雨滴可數海可量，無有能知法壽長。", "梵天釋帝萬億歲，歲歲壽杯天下醉。"]'),
('208c63a3-70f2-4e4c-b662-94c16b97781b','雙雁吟','趙文','宋','宋诗','song-poetry','','[]','雲間有雙雁，弋者欲炙之。',122,'全唐诗/poet.song.240000.json','["雲間有雙雁，弋者欲炙之。", "雁飛向南去，雖有矰𥐊將安施。", "山川悠遠霜霰苦，可憐宿食不得時。", "一雁中道死，一雁忍痛鳴且飛。", "黄雲落日天地瘦，惟有影與形相隨。", "歸來故巢亦已毀，朝吟夕怨欲訴誰。", "千古萬古多別離，唯有死者何當歸。", "嗚呼物生有情盍俱死，莫令後死空鳴悲。"]'),
('ce9076ba-e63d-4ae8-9a99-87c7ea7cc55e','前有一尊酒','趙文','宋','宋诗','song-poetry','','[]','前有一尊酒，有酒即無愁。',100,'全唐诗/poet.song.240000.json','["前有一尊酒，有酒即無愁。", "吾評儀狄功，端與神禹侔。", "微禹吾其魚，微狄吾其囚。", "人生十九不如意，一醉之外安所求。", "古來何國非亡社，古來何人不荒丘。", "沉思痛至骨，頼爾可銷憂。", "尊中有酒，無酒乃休。", "飲多作病，酒不可讎。"]'),
('731eb499-56d8-4107-bf24-608913fe1280','采芝','趙文','宋','宋诗','song-poetry','','[]','晨登屋後山，采采山上芝。',120,'全唐诗/poet.song.240000.json','["晨登屋後山，采采山上芝。", "可憐松上雨，滴滴沾我衣。", "盈筐頗磊落，滿意持之歸。", "童子見我來，拍手共笑之。", "薄者實殺人，蕩蕩光陸離。", "厚者不能光，食之有餘滋。", "我感童子言，歎息成漣洏。", "古來用人者，或以薄見奇。", "一時誤采取，後悔那可追。", "乃知古人智，不似童子癡。"]'),
('b4728c96-50e2-437b-8dd7-62de69f7fec5','黄西有以清江李侯書來袁見招不果就既去西有五十韻見寄次其韻','趙文','宋','宋诗','song-poetry','','[]','地僻谷自淳，此世有羲軒。',288,'全唐诗/poet.song.240000.json','["地僻谷自淳，此世有羲軒。", "行携二三子，讀書秋樹根。", "不擬山水窟，忽枉君侯轓。", "携持貴人意，僕口不憚煩。", "居然寒谷底，暖以扶桑暾。", "是時花正濃，主客共清樽。", "欣聞結駟盛，下賁窮巷原。", "恍如神仙人，謁入晉賀元。", "舊谷雖可記，白髮各已拚。", "細論別來事，感愴將何言。", "愁予守破研，石田疲老犍。", "羨君行萬里，天宇橫孤鶱。", "唯思山林寂，頗厭朝市喧。", "夔州華髮女，欲嫁誰能昏。", "堂堂李元禮，今代真龍門。", "胸中有人物，犖然剖籬藩。", "好春播伊耆，神火驚陸渾。", "詞章軼唐人，天馬出大宛。", "翰墨掩晉代，鳳翥龍蛇奔。", "如何肯下顧，草間麞與猿。", "殷勤遠贈我，一紙春風痕。", "空中實自愧，在上安敢援。", "坐對大將軍，有虱不得捫。", "豈不念長饑，終恐成素飱。"]'),
('850d1277-412f-42be-a340-81c322a81deb','次韻張天從','趙文','宋','宋诗','song-poetry','','[]','文字於吾身，有如病枝指。',108,'全唐诗/poet.song.240000.json','["文字於吾身，有如病枝指。", "晚思逃天刑，日自參佛髓。", "近雖迫老病，頗已了生死。", "吾猶說故吾，我已覺今是。", "卿雲從天來，五色光透紙。", "斯文亦厭老，此事盡遜子。", "好秋行當中，明月照白水。", "誰能訪窮山，詩酒相料理。", "惟當吟君詩，永夜對明視。"]'),
('5850d042-3d94-40fe-9be8-9fe9b61061ac','次韻劉耘廬','趙文','宋','宋诗','song-poetry','','[]','江南有故事，極熱介秋夏。',96,'全唐诗/poet.song.240000.json','["江南有故事，極熱介秋夏。", "空齋得幽景，衆綠天所畫。", "對景愜余情，談文及茲暇。", "山風吹池月，不似城中夜。", "百年易過花，萬事庶生蔗。", "羲和如走馬，疾急不可靶。", "何妨奴嚴光，詎肯吏侯霸。", "一笑且披襟，新凉自無價。"]'),
('e5905ffb-3b91-49de-bf82-526671489cf7','次韻歐陽良有高山仰止四首  其一','趙文','宋','宋诗','song-poetry','','[]','少年場屋心，富貴輕秋毫。',96,'全唐诗/poet.song.240000.json','["少年場屋心，富貴輕秋毫。", "如何此偪仄，晚作空山逃。", "世方馳逐好，我獨儒書豪。", "寧甘往教遠，不肯十上勞。", "尚持鵾鷄弦，自愛鳳尾槽。", "紛然凉州曲，誰賞鬰輪袍。", "取之衆棄中，君眼亦已高。", "惜哉君更窮，相看兩蕭騷。"]'),
('a0def472-67de-4141-9b1c-7c78aeff3b56','次韻歐陽良有高山仰止四首  其二','趙文','宋','宋诗','song-poetry','','[]','我携二三子，行此白玉灣。',96,'全唐诗/poet.song.240000.json','["我携二三子，行此白玉灣。", "案頭左章集，古語留人間。", "我昔識此士，風雨滿空山。", "憂愁送日月，不復記容顔。", "自從一別來，乃此再見慳。", "爲客使同邑，造物何其儇。", "豈無城府意，乘馬忽復班。", "還能顧寂寞，山路披荒菅。"]'),
('b1a8fe50-0afc-4040-acf0-1e81c88b6d47','次韻歐陽良有高山仰止四首  其三','趙文','宋','宋诗','song-poetry','','[]','新詩日以多，古意日以往。',96,'全唐诗/poet.song.240000.json','["新詩日以多，古意日以往。", "我欲求玄珠，未易覓象罔。", "中道良獨難，執玉迷俯仰。", "索居無誰語，掩卷起遐想。", "當求古人知，何用世俗賞。", "意到亦偶然，深刻戒斯鞅。", "惟堪自娛戲，非欲互標榜。", "唐公謬見推，薛侯詎宜長。"]'),
('25d55394-7608-4402-befb-5e1ecbbc3322','次韻歐陽良有高山仰止四首  其四','趙文','宋','宋诗','song-poetry','','[]','世變如江河，不知何時止。',96,'全唐诗/poet.song.240000.json','["世變如江河，不知何時止。", "芸芸生其間，有如赴海水。", "乾坤一大甕，歲月等流矢。", "公言信可感，流輩乃爾耳。", "古來文章家，傳者十數子。", "磨滅十八九，誰復知姓氏。", "要爲不朽計，聖賢事在己。", "勗哉立其心，食魚何必鯉。"]'),
('5f310fe4-5257-4c9b-8645-f82f1fd89db5','香逕分韻得江字','趙文','宋','宋诗','song-poetry','','[]','一亭寒碧中，四面空無窗。',84,'全唐诗/poet.song.240000.json','["一亭寒碧中，四面空無窗。", "種荷未有花，清意已滿腔。", "小坐梅樹下，我亦青油幢。", "晚來蟬聲歇，靜境熱自降。", "清風與明月，造物無對樁。", "閑者恣吟取，如瓢分大江。", "欲歸尚未肯，雨濕烟鐘撞。"]'),
('6d6c3093-0572-45eb-9acb-37fa235e19bb','行行江水邊','趙文','宋','宋诗','song-poetry','','[]','朝行江水邊，莫行江水邊。',60,'全唐诗/poet.song.240000.json','["朝行江水邊，莫行江水邊。", "乍與江水別，江水復在前。", "江水勝人心，相隨何纏綿。", "相隨何纏綿，幸勿鳴悲煎。", "我悲爲我弟，君悲亦胡然。"]'),
('41bec625-9fa0-479a-ad42-b9b8c6d72ffe','雨行五嶺下','趙文','宋','宋诗','song-poetry','','[]','天地忽晝晦，四山潑墨濃。',144,'全唐诗/poet.song.240000.json','["天地忽晝晦，四山潑墨濃。", "而我行其間，宛如所翁龍。", "大風吹倒人，欲避無所容。", "有翼不得張，狂走急雨中。", "數里乃一息，如出鮫人宮。", "老樹道邊拜，疑我行雨工。", "過午上五嶺，攀緣入青空。", "仰視萬山巔，有氣如炊籠。", "下視田間白，云此鋤田農。", "茲行豈不苦，奇觀亦已雄。", "惜哉如此山，不與曉景逢。", "不曉韓吏部，登華哭途窮。"]'),
('e76aba59-32b1-4d87-9e2a-8d85a0fe5b7c','銅雀瓦','趙文','宋','宋诗','song-poetry','','[]','曹公築銅臺，氣力雄九有。',72,'全唐诗/poet.song.240000.json','["曹公築銅臺，氣力雄九有。", "咿嚶到香履，千古開笑口。", "猶餘當時瓦，作硯傳不朽。", "涪翁所珍惜，又復落吾手。", "鬼奪與客偷，任運不汝守。", "可憐臺上人，不如此瓦壽。"]'),
('6c09328a-ca65-4ddf-8e54-721aee6144db','抵豫章','趙文','宋','宋诗','song-poetry','','[]','泊舟豫章城，黑潦滿道周。',84,'全唐诗/poet.song.240000.json','["泊舟豫章城，黑潦滿道周。", "街衢未改昔，故舊罕所留。", "行投學子廬，假榻得小休。", "燈前作家書，豈爲兒女謀。", "戒之築土室，弟骨至則收。", "茫茫念三年，此骨知在不。", "置書就我寢，泫然淚雙流。"]'),
('e05425d0-9e1f-4ef1-9bd0-b7a828bb5a7e','倚樹三歎息','趙文','宋','宋诗','song-poetry','','[]','煌煌天上星，墮地化爲石。',60,'全唐诗/poet.song.240000.json','["煌煌天上星，墮地化爲石。", "回思天宮勝，再上那可得。", "臺鬰將誰言，猶能事文墨。", "一落秦王手，已是不完璧。", "秋風吹我衣，倚樹三歎息。"]'),
('c5bf9c71-242d-4b37-9894-2a226f8d0785','白水初程','趙文','宋','宋诗','song-poetry','','[]','天公大惡處，妬我喜晴詩。',108,'全唐诗/poet.song.240000.json','["天公大惡處，妬我喜晴詩。", "當與妻子別，急雨紛交馳。", "小孫送我行，屢止不肯歸。", "老夫骨肉情，能不酸且悲。", "日暮投歷山，倦極不得棲。", "故人情義重，杯酒煦嫗之。", "老友亦適至，良會非所期。", "人生孰非夢，此夢亦已奇。", "我倦欲先睡，徑與主人辭。"]'),
('6e0136f7-36ef-41c7-a9a5-7b5aeeda6f35','入分宜界','趙文','宋','宋诗','song-poetry','','[]','上嶺或如興，下嶺復如拜。',72,'全唐诗/poet.song.240000.json','["上嶺或如興，下嶺復如拜。", "是程多泥塗，拄杖端足頼。", "脫屨去泥淖，停車觀水械。", "偶然得一笑，更以苦爲快。", "田水終夜鳴，江浪怒澎湃。", "聽之不能睡，摩足了詩債。"]'),
('df1653c2-5bba-4e77-a7af-39837d6af40a','得蓮子','趙文','宋','宋诗','song-poetry','','[]','休休得一閑，杯酒聊從容。',96,'全唐诗/poet.song.240000.json','["休休得一閑，杯酒聊從容。", "晚凉過池亭，受用水上風。", "默存即實境，身在蓮花中。", "何况青青盤，磊落堆蓮蓬。", "乍休吟風蟬，又起聒夜蟲。", "乃知天機動，衮衮無終窮。", "如何二三子，不肯勤其躬。", "無已思太康，明當勵新功。"]'),
('38d1e424-834c-46ce-8f95-1e0a58772e7c','寄彭宏濟','趙文','宋','宋诗','song-poetry','','[]','夜枕苦展轉，午睡清且安。',96,'全唐诗/poet.song.240000.json','["夜枕苦展轉，午睡清且安。", "萬事有乘除，滿意良獨難。", "貧居鮮來客，兒女自團圞。", "書聲雜紡響，聒耳亦足歡。", "念我素心友，詩盟久已寒。", "向來適邂逅，杯酒語夜闌。", "如何同所舍，聚散如沙摶。", "百年盡偶爾，棄置何足歎。"]'),
('4c0e1efd-0b28-4fd1-81aa-8ee5378d5473','喜晴','趙文','宋','宋诗','song-poetry','','[]','行行復行行，晴日端可愛。',48,'全唐诗/poet.song.240000.json','["行行復行行，晴日端可愛。", "全勝牆隈老，僅得暖肩背。", "欣欣田間麥，亦與人意會。", "乃知天地間，生意浩如海。"]'),
('e79ef3f0-36ec-4ffd-b84c-fe69d907bdbe','去者日以疏','趙文','宋','宋诗','song-poetry','','[]','去者日以疏，留者日以老。',72,'全唐诗/poet.song.240000.json','["去者日以疏，留者日以老。", "沉憂能傷人，玄髮坐成皓。", "人生固應爾，要亦何太早。", "携持玉雪姿，故敢棄遠道。", "蒼天行悠悠，白日照杲杲。", "安得以妾腸，化作君墓草。"]'),
('d5c045e9-8380-4c23-9e14-e91ba0540252','至白水主人飲至海棠下花已離披','趙文','宋','宋诗','song-poetry','','[]','昨日泥中人，今日花下客。',84,'全唐诗/poet.song.240000.json','["昨日泥中人，今日花下客。", "即時一杯酒，已勝風雨黑。", "我來後花時，不及穠艷色。", "生與天作花，已是花命厄。", "霑茵與墮溷，要亦隨所適。", "誰能長腴紅，而不變衰白。", "惟應感流光，有酒日鼓瑟。"]'),
('5380eb59-4f8d-4cdb-bb7e-9a4a88f7f943','聽請道人念佛','趙文','宋','宋诗','song-poetry','','[]','平生不喜佛，喜聽念佛聲。',132,'全唐诗/poet.song.240000.json','["平生不喜佛，喜聽念佛聲。", "大都止六字，三誦有餘音。", "唱偈類哀切，和聲等低平。", "蟬聯未肯已，綿弱殆不勝。", "餒息僅相屬，柔吭時一鳴。", "聽茲頹闒韻，生我寂滅情。", "坐令喧競中，便欲無所爭。", "乃知象教意，妙覺在聲聞。", "俗人不解此，梵教雜歌行。", "敲鏗鼓笛奏，真與鄭衛并。", "能令婦女悅，未必佛者聽。"]'),
('e56b1491-7b60-40e8-ab54-3e26fd3716da','早禾田','趙文','宋','宋诗','song-poetry','','[]','雨雨不肯止，倒瀉春江濤。',132,'全唐诗/poet.song.240000.json','["雨雨不肯止，倒瀉春江濤。", "可憐龍公苦，甚我行路勞。", "長陂不可涉，攀嶺如猿猱。", "忽然出夷曠，行人何滔滔。", "館定訪我友，醉我軟脚醪。", "翻思昨暮秋，有酒安可逃。", "諸少森玉立，俊秀非兒曹。", "示我近所作，亦復吹其毛。", "人生有乘除，理不差秋毫。", "豈非昨者厄，故有今者遭。", "歸來弛然卧，夢中亦陶陶。"]'),
('b60158ef-8256-447f-8c00-b7f0e2b27cd6','別朝祐','趙文','宋','宋诗','song-poetry','','[]','又與我友別，獨與我子俱。',72,'全唐诗/poet.song.240000.json','["又與我友別，獨與我子俱。", "念彼歸舟疾，眠食今何如。", "愁懷不可遣，頼有牀頭書。", "曲江江上人，摇舟來賣魚。", "亦有妻與子，一飽便有餘。", "我生不如子，多憂化其鬚。"]'),
('cdaf2030-dab0-400e-b6d6-6815105dc0de','銅雀臺','趙文','宋','宋诗','song-poetry','','[]','朝望西陵墓，夕望西陵墓。',72,'全唐诗/poet.song.240000.json','["朝望西陵墓，夕望西陵墓。", "望望不復歸，月朔又十五。", "月朔十五可奈何，更對空帷作歌舞。", "銅雀昂然飛不去，當時美人髮垂素。", "我生不如陵上樹，年年樹根穿入土。"]'),
('b705f647-ca43-47cb-90a7-5d770aa4dafe','曉行','趙文','宋','宋诗','song-poetry','','[]','籃輿拂清露，亦有山花香。',36,'全唐诗/poet.song.240000.json','["籃輿拂清露，亦有山花香。", "平生懶早起，催盥方倒裳。", "不知九州曉，有此清風凉。"]'),
('67c6ba74-d467-448f-b183-4a96a208cc9c','團扇歌','趙文','宋','宋诗','song-poetry','','[]','私夜必見污，葛屨必遭踐。',48,'全唐诗/poet.song.240000.json','["私夜必見污，葛屨必遭踐。", "生世不爲男，托身况微賤。", "悲痛只在心，憔悴更障面。", "出入懷袖中，羨郎白團扇。"]'),
('1c8fc0d5-63a9-444a-8151-d4bb1ce8900c','枕上聞大風','趙文','宋','宋诗','song-poetry','','[]','夢中顛風摇夢魂，老夫起坐心未平。',64,'全唐诗/poet.song.240000.json','["夢中顛風摇夢魂，老夫起坐心未平。", "樹枝上下覺山動，窗戶開闔疑鬼行。", "魚龍翻空江海怒，虎豹入叢道路清。", "溪頭梅花無恙否，爲子展轉難爲情。"]'),
('171b80a8-dc4f-479d-bdc4-d221056de545','海山圖二首  其一','趙文','宋','宋诗','song-poetry','','[]','棧道縈紆如蜀路，我夢曾遊定何處。',48,'全唐诗/poet.song.240000.json','["棧道縈紆如蜀路，我夢曾遊定何處。", "金碧樓臺縹紗裏，員嶠方壺如是爾。", "彼何人者欲問之，翩然抱琴過橋底。"]'),
('b99197d8-1eeb-4a05-a661-4f61e39cd630','海山圖二首  其二','趙文','宋','宋诗','song-poetry','','[]','嵯峨石壁不可梯，列仙之癯實居之。',48,'全唐诗/poet.song.240000.json','["嵯峨石壁不可梯，列仙之癯實居之。", "下視茫茫渺何許，風帆浪舶多積貯。", "舟中賈客莫浪喜，山上高人解笑汝。"]'),
('97d05d1c-1bef-4c38-aec1-2ef49b295fc5','雪','趙文','宋','宋诗','song-poetry','','[]','三更星月寒炯炯，四更霜風吹斷梗。',112,'全唐诗/poet.song.240000.json','["三更星月寒炯炯，四更霜風吹斷梗。", "曉來宇宙忽成空，萬里天河墮無影。", "人間世界積滓穢，化作太清無色境。", "天上何人巧戲劇，笑我癡眠方怯冷。", "溪頭梅花老於我，卧樹生鱗欲誰省。", "飲羔金帳非我事，煎水何妨試雙井。", "眼前清致不可辜，諸公白戰續清潁。"]'),
('21675f8a-2f5b-435e-9669-9965009c9a35','別白水歸大雪','趙文','宋','宋诗','song-poetry','','[]','冰枝壓路不可行，健夫快斧聲丁丁。',96,'全唐诗/poet.song.240000.json','["冰枝壓路不可行，健夫快斧聲丁丁。", "南山未得過車道，北山復作發屋聲。", "低枝叢薄亦可喜，但覺身過琉璃城。", "山高路滑凜欲跌，拄杖頼有青童君。", "平安度嶺笑相賀，榾柮快煖胭脂春。", "夜投野店且熟睡，明日陰晴明日事。"]'),
('844b636d-5ba6-4e31-9734-b8d90cc3fe65','行雪','趙文','宋','宋诗','song-poetry','','[]','夜寒枕席跳霰珠，夜深我睡霰亦無。',128,'全唐诗/poet.song.240000.json','["夜寒枕席跳霰珠，夜深我睡霰亦無。", "未晨僕起索炊火，怪見滿地瓊瑶鋪。", "我行至此不得止，但倚紅酒爲先驅。", "路逢十店九閉戶，苦寒正自無薪芻。", "終然著地即化去，造物何用勞工夫。", "前山欲融未融處，玉龍浮動青珊瑚。", "藤梢竹刺時點綴，寒食野花棲路隅。", "小車行雪真有益，平生看畫無此筆。"]'),
('a6c3a1b3-a56c-4ae3-b1d4-07b805bc5d40','伏虎嶺殘雪','趙文','宋','宋诗','song-poetry','','[]','晴得一霜晴更穩，飽飯不怕伏虎嶺。',112,'全唐诗/poet.song.240000.json','["晴得一霜晴更穩，飽飯不怕伏虎嶺。", "山高積雪凍猶在，昨日空驚雪畫本。", "日烘高樹玉槎牙，時有冰花墮無影。", "紛紛垂絲白海棠，得冷時能略蘇醒。", "可怪此君大曲折，向人雅拜欲求拯。", "擁袍公子亦吟雪，豈識山中有此景。", "笪橋燭下寫詩成，一尊獨酌誰能省。"]'),
('63d78d3d-b402-4226-98a1-9f77d3f7fc81','題畫蟲鳥','趙文','宋','宋诗','song-poetry','','[]','泥行郭索其神全，枯枝獨抱吟風仙。',144,'全唐诗/poet.song.240000.json','["泥行郭索其神全，枯枝獨抱吟風仙。", "細腰追逐相後先，畫眉雙棲鬭嬋娟。", "一鳴一止俱自然，老猴如鬼踞石邊。", "遊蜂何爲過其前，水禽伺魚雙眼穿。", "久而無得倦欲眠，鸜之鵒之高樹巔。", "俯視螳臂爲垂涎，之蟲不作名利牽。", "飲啄之外何所便，人生擾擾真可憐。", "笑談對面森戈鋋，王侯螻蟻俱埃煙。", "大年未可笑小年，世間唯有蟲能天。"]'),
('153c9edb-41d2-431c-9c4e-2a5863a75c72','次韻郭梅邊湯孤松見寄','趙文','宋','宋诗','song-poetry','','[]','杜門却掃馮敬通，何人載酒暖此翁。',224,'全唐诗/poet.song.240000.json','["杜門却掃馮敬通，何人載酒暖此翁。", "晝長書罷啼鳥寂，山水似我清而窮。", "山僧携來兩詩卷，筆勢迅疾如追鋒。", "漁歌風斷郭功父，碧雲暮合湯休公。", "寒梅自照太古雪，孤松壓倒妖春紅。", "一時見此光怪物，丈室忽換化人宮。", "近者重遊寶林寺，山行小辟炎毒攻。", "唱酬坐覺山鬼泣，談笑不知酒海空。", "當時分韻十五客，冠童亦有童非童。", "惜哉梅松不在眼，自與修竹爲吾宗。", "傳聞浄覺更殊勝，極欲往求三日聾。", "補天久已付昨夢，面壁更欲收奇功。", "百年金碧亦塵土，須有好語留山中。", "山中道人許我否，飽飯摩腹聽松風。"]'),
('62d73a37-3181-4350-bcd3-bf01500f5198','題耆英圖','趙文','宋','宋诗','song-poetry','','[]','耆英會上十三人，當時世道如初春。',64,'全唐诗/poet.song.240000.json','["耆英會上十三人，當時世道如初春。", "洛陽牡丹非昔比，妖怪百出年年新。", "我見此圖淚如雨，諸老翩然過何許。", "何時夢見洛陽春，鄭公插花潞公舞。"]'),
('dd695cc5-8365-4c3e-ab63-90fd86f27ed9','食魚江水邊','趙文','宋','宋诗','song-poetry','','[]','食魚江水邊，投骨江水中。',76,'全唐诗/poet.song.240000.json','["食魚江水邊，投骨江水中。", "衆魚逐其腴，踴躍以相從。", "所得僅濡沫，滿意如遊龍。", "焉知此棄骨，與爾類本同。", "人間網羅多，江海不得容。", "小魚得骨莫浪喜，且可慎汝出入蹤。"]'),
('ce8fbe32-5126-450c-b6ef-8a968557878f','三香圖','趙文','宋','宋诗','song-poetry','','[]','梅花瘦而貞，霜磨雪折骨愈奇。',74,'全唐诗/poet.song.240000.json','["梅花瘦而貞，霜磨雪折骨愈奇。", "山礬清而野，桃李場中不肯移。", "梅也似伯夷，礬也似叔齊。", "水僊大似孤竹之中子，不瘦不野含仙姿。", "人生但願水僊福，梅兄礬弟真難爲。"]'),
('592dd0d3-8a10-4402-9f9d-0eb0ad283f66','揚州后土廟瓊花香如蓮花落不著地丙子一夕大雷雨失花所在相傳以爲上天云','趙文','宋','宋诗','song-poetry','','[]','朔風吹沙淮浪白，二十四橋沉冷月。',128,'全唐诗/poet.song.240000.json','["朔風吹沙淮浪白，二十四橋沉冷月。", "顛雷夜半撼蕪城，雪萼瓊絲破空碧。", "金瓶歲歲獻君王，玉罌泛酒蓮花香。", "明光殿閉沙漠遠，人自無情花斷腸。", "落蘂飛天識天路，何如拔樹飛昇去。", "唐昌遊女再歸來，城中只賣瓊花露。", "江南俘客吟如叫，想像裁詞不成調。", "天宮夜宴按霓裳，玉女擎花紫皇笑。"]'),
('bc58d0db-f367-47f3-8674-4963ec06ff0c','明皇遊月宮歌','趙文','宋','宋诗','song-poetry','','[]','鐵龍一擲九萬里，銀橋冉冉行秋水。',96,'全唐诗/poet.song.240000.json','["鐵龍一擲九萬里，銀橋冉冉行秋水。", "霓裳不是世間音，只有嫦娥似妃子。", "恍然一夢酒初醒，依然玉座雲母屏。", "明朝寫出天上曲，却笑羯鼓羊皮腥。", "人間萬事如秋草，離別苦多歡樂少。", "崎嶇萬里錦官城，此身曾作銀橋行。"]'),
('3258c099-803a-4a25-a254-f7eee3065f5f','西江柳氏月江詩','趙文','宋','宋诗','song-poetry','','[]','何人種此玻瓈橘，掛在空高寒露濕。',128,'全唐诗/poet.song.240000.json','["何人種此玻瓈橘，掛在空高寒露濕。", "秋風吹墮清泠中，驚殺神髯夜深蟄。", "钴鉧潭中豈無月，冷光長照衰羈泣。", "何如阿孫屋頭月，時時投取杯中吸。", "吸餘吐向筆墨間，紙上淋漓流月汁。", "前年劫火到詩屋，月走江寒燒不及。", "青山夜起繞皆山，滿地蘆花不堪拾。", "何時短棹釣西江，雪寒一夜無簑笠。"]'),
('a62d4bb2-89a9-4a39-aa22-6e9ca0dec712','羅稚川善畫作此贈之','趙文','宋','宋诗','song-poetry','','[]','吾觀天地間，一一皆是畫與詩。',178,'全唐诗/poet.song.240000.json','["吾觀天地間，一一皆是畫與詩。", "渝川有二羅，畫得天地之英奇。", "大羅詩名撼湖海，小羅天機勃鬰不得已而水墨之。", "摇毫造化已破碎，灑墨元氣爲淋漓。", "嗟余老眼得一見，以手捫摸心然疑。", "問君自古畫有幾，君今此畫師者誰。", "君言我以眼爲手，天地萬物皆吾師。", "吾能得其意與理，貌取色相特其皮。", "畫成正未知似否，人人有眼誰可欺。", "譬之禪宗要透脫，戀戀祖佛寧非癡。", "作詩點出未來眼，一掃徐熙與郭熙。"]'),
('50b95257-5104-456f-bdb7-dbec6caa8c76','相撲兒','趙文','宋','宋诗','song-poetry','','[]','一兒攀肩猿上枝，一兒接臂倒立之。',80,'全唐诗/poet.song.240000.json','["一兒攀肩猿上枝，一兒接臂倒立之。", "立者忽作踞地伏，攀者引頭立其足。", "飛跳倏忽何輕翾，憐爾骨節柔如綿。", "少年屈折支體軟，紅錦纏頭酒論椀。", "此兒巧捷未足稱，江南何限無骨人。"]'),
('16a524eb-b8a0-4b92-8797-8d8930cc57c1','網戶歎','趙文','宋','宋诗','song-poetry','','[]','江南西風粳稻熟，網夫出門網婦哭。',56,'全唐诗/poet.song.240000.json','["江南西風粳稻熟，網夫出門網婦哭。", "天晴黄雀飛苦高，縣吏椎門怒震屋。", "哨聲飛空健鶻過，遲速小誤成蹉跎，君庖不充將奈何。"]'),
('779d6493-b8d6-4b31-8a5f-a92811259f2d','獵戶歎','趙文','宋','宋诗','song-poetry','','[]','江南冬前蟲未蟄，獵師篝火熏穴急。',64,'全唐诗/poet.song.240000.json','["江南冬前蟲未蟄，獵師篝火熏穴急。", "山中玉面何處藏，供奉期程如束濕。", "茅簷十日無炊米，蓬鬢鶉衣瘠如鬼。", "但教得狸何顧爾，易牙奉君尚烹子。"]'),
('55f1244f-b288-4500-b488-a6f788e6bdab','越婦採葛苦','趙文','宋','宋诗','song-poetry','','[]','采采山上葛，攀藤步巖幽。',148,'全唐诗/poet.song.240000.json','["采采山上葛，攀藤步巖幽。", "上山逢虎狼，下山逢獼猴。", "歸來絺綌之，藕絲香且柔。", "織成一片雲，精絕鬼工愁。", "入笥獻君王，貢職民當修。", "君王不自惜，持以奉仇讎。", "西施被服之，俱是越國尤。", "吳王抵掌笑，於越吾何憂。", "飛書益封地，謂越吾諸侯。", "嗟爾采葛伴，辛苦勿嘆愁。", "天道有乘除，苦極行當休。", "吳王沉醉姑蘇上，半夜不知吳國秋。"]'),
('bb32776f-8a1b-4053-ab57-2f4f393c72ac','陳清叔晚菊','趙文','宋','宋诗','song-poetry','','[]','物生何用出世早，春風紅紫今枯槁。',147,'全唐诗/poet.song.240000.json','["物生何用出世早，春風紅紫今枯槁。", "東籬瀟灑一枝秋，向來埋沒不如草。", "人生涉世亦如此，風雪林中要耐老。", "陳君臞然一寒素，清絕誰如叔也好。", "十年竟被先疇役，大袖高冠反顛倒。", "黄金白璧盡辭去，獨與寒花澹相保。", "問君對菊何所得，租藉半空詩富藁。", "百年芳臭終不歇，一時泯滅豈足道。", "君不見淵明對菊無一錢，千古詩名塞穹昊。"]'),
('6be10f6e-f23c-4d31-9ce4-ddb96315069a','贈長沙譚存心','趙文','宋','宋诗','song-poetry','','[]','譚君酒狂，一筆萬字不可當。',157,'全唐诗/poet.song.240000.json','["譚君酒狂，一筆萬字不可當。", "嗟哉胡爲乎，不自貴重也而狂。", "我知君狂不得已，欲倚杯酒呵蒼蒼。", "蒼蒼不識君我識，知君胸有光怪物。", "問君今年其歲幾，四十一矣無何仕。", "光陰誕謾不可恃，我昔行年亦如此。", "相逢一醉令公喜，解劍傾囷無壯士。", "一簦獨行風雨裏，老人夜醉誰汝止。", "丈夫得志行所爲，窮即低頭教童子。", "嗟哉乾坤如此而已矣，歸來歸來歸來是。"]'),
('f6e5075c-8a10-41ac-b527-a65337fe26e9','生日客朱溪主人云今年乃青山真生日也感其語作詩自壽','趙文','宋','宋诗','song-poetry','','[]','人生難得真生日，正使百年才遇一。',192,'全唐诗/poet.song.240000.json','["人生難得真生日，正使百年才遇一。", "我今客裏值斯時，况復主人相款密。", "連宵舉酒爲我壽，滿眼雞豚破梨栗。", "壽牋投贈盛賓友，壽觴拜舞羅弟姪。", "假今家居那有此，米鹽紛糾費爬櫛。", "去年閩山收弟骨，日夜悲啼吟蟋蟀。", "歲晚方能負骨歸，此願已償甘似蜜。", "平生苦遭兒女累，十年求解如沐漆。", "今年二子各成婚，坐看明年婚嫁畢。", "雲邊太史相邂逅，許我行年七十七。", "蓋棺以前日一詩，萬首猶堪劍南匹。", "未知先生竟肯否，不肯便問天公乞。"]'),
('75896bcb-45a0-4d92-931a-71b61e1bb5de','雷震漁所之柱','趙文','宋','宋诗','song-poetry','','[]','瞥然滿屋飛金蛇，樓東樓西號火鴉。',96,'全唐诗/poet.song.240000.json','["瞥然滿屋飛金蛇，樓東樓西號火鴉。", "天鼓百面一手撾，百年老柱神斧加。", "婦女驚倒兒童哇，知君把釣江頭沙。", "明珠赤手龍頷拏，天翁發怒爲此耶。", "向來五鬼千夜叉，寒我饑我生眼花。", "捧頭驚竄如麏麚，從此不作窮詩家。"]'),
('df7ff6b3-cd13-44c8-a34d-e8117a69ff97','銅雀硯','趙文','宋','宋诗','song-poetry','','[]','老瞞智計籠天下，歌舞未終銅雀夜。',128,'全唐诗/poet.song.240000.json','["老瞞智計籠天下，歌舞未終銅雀夜。", "可憐用破一生心，不及當時臺上瓦。", "屑金作瓦費精神，那知身後旋成塵。", "流傳千百僅一二，付與所不知何人。", "快閣仙人諛墓得，品題更費東坡墨。", "研磨辛苦政未休，憐爾何年返真宅。", "摩挲歲月白髮生，建安七子俱彫零。", "安得春醪三萬斛，醉來快寫短歌行。"]'),
('97ef28af-0fe3-44d3-969a-b77fdc90e5d1','劉陽卜氏耕樂堂','趙文','宋','宋诗','song-poetry','','[]','君當學君家君子儒，西河之上可以老，諸侯端拜爲師模。',101,'全唐诗/poet.song.240000.json','["君當學君家君子儒，西河之上可以老，諸侯端拜爲師模。", "君莫學君家老中郎，河南田畜豈不好，上林要牧天子羊。", "祇今樂莫如耕樂，悔我從初不曾學。", "作勞自可操豚蹄，舊讀何妨掛牛角。", "慎勿思成湯聘幣起幡然，伊尹當年已大錯。"]'),
('2591a5f0-6e6e-4d5d-9369-0589e9819c57','題畫','趙文','宋','宋诗','song-poetry','','[]','雲巢草蟲十有七，我言蜂蟻非蟲匹。',48,'全唐诗/poet.song.240000.json','["雲巢草蟲十有七，我言蜂蟻非蟲匹。", "我見二蟲常敬之，爲有君臣天所秩。", "江南此蟲久已無，煩君翦取贈老夫。"]'),
('f6bd5950-bcde-491d-9c0b-9b4ea8b967b6','李士宏得薌林五老石於野人','趙文','宋','宋诗','song-poetry','','[]','薌林醜石何曾醜，化爲五老如此壽。',272,'全唐诗/poet.song.240000.json','["薌林醜石何曾醜，化爲五老如此壽。", "高低俯仰各有意，清潤堅貞皆可友。", "剜劖刻削巧戲劇，誰爲此者鴻蒙叟。", "銅盆古雅出高麗，玉筯清奇原史籀。", "向翁神遊渺何許，此物亦落何人手。", "野人得之安所用，光怪出屋驚田婦。", "天生尤物必有屬，詩老得之端不偶。", "不須拄杖穿寒雲，几案之間有廬阜。", "先生自是五山一，視真廬阜猶培塿。", "如何得此亦驚喜，便欲賦詩爲不朽。", "醉僧癡望作怪供，持此或可博升斗。", "壺中九華竟不得，坡老歎息不離口。", "仇池不借王駙馬，詩卷紛紛愁逆取。", "達人著想亦未免，何異兒童貪餠糗。", "蛾眉山高隔雲霧，此物今知屬誰某。", "世間奇寶雖可玩，鬼奪客偷誰使守。", "先生一笑付偶然，吾欲藏之無何有。"]'),
('82c5b5e3-ca22-47c5-8ecf-f883e5b51851','麥熟','趙文','宋','宋诗','song-poetry','','[]','今年麥熟亦可喜，紫石霏霏落鍾乳。',80,'全唐诗/poet.song.240000.json','["今年麥熟亦可喜，紫石霏霏落鍾乳。", "我從田家慣餠餌，夢想風味今未已。", "箬葉浮浮捲牛舌，甆甌泛泛割龍耳。", "一丸蘿蔔吾豈無，悲歌不怕紅娘子。", "詩成不滿貴公笑，書生豈識餠十字。"]'),
('5e8e38e8-a5c1-43f0-8c36-a4484897a07e','彭海月北遊','趙文','宋','宋诗','song-poetry','','[]','夢跨海風出埃𡏖，萬頃瓊瑶雙履踏。',144,'全唐诗/poet.song.240000.json','["夢跨海風出埃𡏖，萬頃瓊瑶雙履踏。", "四無畔岸水連天，兩椀琉璃自相合。", "當時我外更無人，仙聖往來班雜遝。", "恍然夢覺失清遊，正似明珠埋蚌蛤。", "十年對月心自拜，江南沙土老額塌。", "羨君持月海天遊，萬里乾坤雲一匝。", "乘槎徑到斗牛間，細語星辰相問答。", "知君此行有奇遇，直挾星書扣閶闔。", "羣仙若問青山人，白髮秋深坐蕭颯。"]'),
('2239bdd2-292f-404c-9696-808f58130067','元夕陪須溪野廟觀燈','趙文','宋','宋诗','song-poetry','','[]','豈能狂落魄，只似醉瞢騰。',48,'全唐诗/poet.song.240000.json','["豈能狂落魄，只似醉瞢騰。", "媼拜兒看笑，蠻粧鬼見憎。", "客中猶有酒，亂後此看燈。", "携手沙河路，前身夢裏曾。"]'),
('a13f8ebf-fe5a-4b23-a8fa-5c12267167f1','次分宜','趙文','宋','宋诗','song-poetry','','[]','分得宜春地，東偏一畫屏。',48,'全唐诗/poet.song.240000.json','["分得宜春地，東偏一畫屏。", "洪陽仙洞古，龍姥故祠靈。", "雨過溪痕長，春回草意青。", "道傍聊下馬，剔蘚讀碑銘。"]'),
('1d50e6e1-5f38-4a0d-9b90-bf20b9e7ee92','賀一年年','趙文','宋','宋诗','song-poetry','','[]','總角坐成老，孤生自可憐。',48,'全唐诗/poet.song.240000.json','["總角坐成老，孤生自可憐。", "遂爲衆父父，又賀一年年。", "桃板無新語，屠蘇妨早眠。", "柴門無可掩，來者自蕭然。"]'),
('ef4ba6fe-2b12-4e6e-b84a-f7c910fbea82','哭蕭漁所','趙文','宋','宋诗','song-poetry','','[]','於佛曾聞法，因詩遂得貧。',48,'全唐诗/poet.song.240000.json','["於佛曾聞法，因詩遂得貧。", "若爲三尺喙，不了百年身。", "在昔玄真子，如今主水神。", "飯餘茶又熟，不學淚沾巾。"]'),
('356db575-8301-441d-a22d-fe4dc4c62e3b','哭張文翁同舍  其一','趙文','宋','宋诗','song-poetry','','[]','豈意渴相如，俄爲化子輿。',48,'全唐诗/poet.song.240000.json','["豈意渴相如，俄爲化子輿。", "平生一杯酒，活計百篇書。", "同舍遂欲盡，吾生不願餘。", "如今念夫子，痛飲未全疏。"]'),
('579cd0cd-c222-4edb-b4e9-66cec3bb45d0','哭張文翁同舍  其二','趙文','宋','宋诗','song-poetry','','[]','扶上竹車去，知無再見期。',48,'全唐诗/poet.song.240000.json','["扶上竹車去，知無再見期。", "誰能逃數定，不必恨歸遲。", "白髮扶棺母，青年上學兒。", "亂來朋友少，灑血一題詩。"]'),
('274e2e2f-9025-4f53-8746-80f237b8b0a3','尋郭道士不遇','趙文','宋','宋诗','song-poetry','','[]','問師云已出，杖履水東灣。',48,'全唐诗/poet.song.240000.json','["問師云已出，杖履水東灣。", "世上方多事，山中亦小閑。", "竹光新雨後，禽語夕陽間。", "自出雲關去，鐘聲送我還。"]'),
('ebd6e1c8-fdd4-4988-8afb-fe492234f91e','紀夢','趙文','宋','宋诗','song-poetry','','[]','既不夢于我，胡然無一言。',48,'全唐诗/poet.song.240000.json','["既不夢于我，胡然無一言。", "形容那可認，骨髮想俱存。", "淚盡血猶滴，霧開山尚昏。", "相看憐稚子，老病莫銷魂。"]'),
('c167c94f-da06-46d1-9fbc-a39aa8b10a9c','元日','趙文','宋','宋诗','song-poetry','','[]','又見王正改舊年，此生此去幾新元。',64,'全唐诗/poet.song.240000.json','["又見王正改舊年，此生此去幾新元。", "自無賓客來看歲，不遣兒童苦閉門。", "雨带癡寒禁草色，雪吹殘片上鬚根。", "小孫未省人間事，尚擬今宵守歲樽。"]'),
('edd3bdb6-0fcc-43ea-93d4-66dfd6dbc622','二月十四夜夢中吟云隔溪啼鳥東風軟滿地落花春雨深次日陪謝少府飲章聖寺足成之','趙文','宋','宋诗','song-poetry','','[]','留得餘寒伴客衾，驀然萬感赴沉吟。',64,'全唐诗/poet.song.240000.json','["留得餘寒伴客衾，驀然萬感赴沉吟。", "隔溪啼鳥東風軟，滿地落花春雨深。", "草草一樽聊若下，匆匆千載亦山陰。", "月溪橋上憑欄久，應有游鯈識此心。"]'),
('174e723c-5538-4025-b7fa-93e7c00d64ec','雨過','趙文','宋','宋诗','song-poetry','','[]','雨過山田物物穰，齋庖煮豆喜初嘗。',64,'全唐诗/poet.song.240000.json','["雨過山田物物穰，齋庖煮豆喜初嘗。", "茸茸綠莢牛毛淺，戢戢明珠蚌蛤長。", "不直畫堂擎玉腕，只宜吟客飽藜腸。", "食餘依舊堆盤在，貴賤同歸何有鄉。"]'),
('8f641eba-e8ef-4f43-b041-1d9a674544b1','哭丁千崖教授','趙文','宋','宋诗','song-poetry','','[]','一覽樓頭笑拂衣，今朝何意此歔欷。',64,'全唐诗/poet.song.240000.json','["一覽樓頭笑拂衣，今朝何意此歔欷。", "斷無痛飲歌都護，那得重歸見令威。", "太學廢來同舍盡，清江好在故人非。", "我來豈是無情者，爲哭妻兒無淚揮。"]'),
('5e9880da-fc86-4e9b-93f4-928cd3842c03','寄孫小隠','趙文','宋','宋诗','song-poetry','','[]','恰似東山不見時，我懷如此更能詩。',64,'全唐诗/poet.song.240000.json','["恰似東山不見時，我懷如此更能詩。", "傳聞薦表雖無驗，感激修塗獨見思。", "渝水微茫蓬島外，秋風浩蕩菊花期。", "別來殘錦何堪寄，羞示孫郎帳下兒。"]'),
('8095c9ae-17d1-49b1-b3cb-64308e98c895','寄歐陽振仲','趙文','宋','宋诗','song-poetry','','[]','晚客他州只爲饑，無人可與話心期。',64,'全唐诗/poet.song.240000.json','["晚客他州只爲饑，無人可與話心期。", "前生一念有今日，投老相逢復幾時。", "頭白可知天下事，秋深定有客中詩。", "何當細語梅花下，眼底故人今在誰。"]'),
('da5a46e6-09d1-4e21-89d6-d83cdc286b59','次韻文以正','趙文','宋','宋诗','song-poetry','','[]','家住荒寒野水濱，老來無處避風塵。',64,'全唐诗/poet.song.240000.json','["家住荒寒野水濱，老來無處避風塵。", "裸人至境有不裸，臣族幸然非亂臣。", "鬢影半因憂世白，眉端時爲得詩伸。", "盛衰物理煩君看，舊日錢神今更神。"]'),
('47752f01-0722-47d2-987c-b36b81f87ec5','次韻趙韞玉','趙文','宋','宋诗','song-poetry','','[]','坐擁寒爐酒入肌，偶然談笑勝於詩。',64,'全唐诗/poet.song.240000.json','["坐擁寒爐酒入肌，偶然談笑勝於詩。", "空齋著雨更愁絕，往事如雲勞夢思。", "歲月只供吾輩老，經綸不了古人癡。", "狂來欲碎瓊壺起，忽憶殘鐘禁夜時。"]'),
('8cecb1ab-fbbe-4f3a-a51e-1cfbbf24331e','次韻友人','趙文','宋','宋诗','song-poetry','','[]','相逢小坐芷花秋，絕勝揚鞭并與幽。',64,'全唐诗/poet.song.240000.json','["相逢小坐芷花秋，絕勝揚鞭并與幽。", "世上十年塵轉海，人生萬事博懸投。", "當時對酒曾辭酒，今日言愁始欲愁。", "何不倒囊來一醉，舊題重訪酒邊樓。"]'),
('cc024d92-4f6f-4188-951b-6dea981ca13c','哭文溪  其一','趙文','宋','宋诗','song-poetry','','[]','滿襟和氣任天真，豈意俄成千載人。',64,'全唐诗/poet.song.240000.json','["滿襟和氣任天真，豈意俄成千載人。", "篤厚西都諸老傳，宦游南海宰官身。", "竹君所幸存中子，荀氏何妨有二仁。", "早及相門今白髮，傳來哀訃倍酸辛。"]'),
('9b75883f-f093-4c3d-8b2c-7f772be44bb6','哭文溪  其二','趙文','宋','宋诗','song-poetry','','[]','憶得梅邊載酒時，梅花依舊主君非。',64,'全唐诗/poet.song.240000.json','["憶得梅邊載酒時，梅花依舊主君非。", "春如生客至誰省，人與殘年去不歸。", "銅雀帳存仙似夢，金臺雁到客沾衣。", "清朝庶政須參决，却怕除書出帝畿。"]'),
('4f497ca4-bcd1-463e-aab6-01f60677bfd0','坐睡','趙文','宋','宋诗','song-poetry','','[]','非癡非夢小瞢騰，瞑坐還同入定僧。',64,'全唐诗/poet.song.240000.json','["非癡非夢小瞢騰，瞑坐還同入定僧。", "口似汝陽狂見麯，頭疑季子困懸繩。", "兒來問字幾三退，客苦多言彊一應。", "日日如期不相貸，世情誰似爾堪憑。"]'),
('00815ea9-ca67-4b8f-8be6-562e6c020a36','次韻孫小隠九日','趙文','宋','宋诗','song-poetry','','[]','壯老相催已久知，逢秋正自不須悲。',64,'全唐诗/poet.song.240000.json','["壯老相催已久知，逢秋正自不須悲。", "向來蟻國一場夢，此去牛山幾首詩。", "且共黄花嬉晉晚，嬾携白髮過燕垂。", "江南風景何堪說，却愛新來眼著籬。"]'),
('62542f64-6f9a-486b-940f-14700553bd77','聽雨','趙文','宋','宋诗','song-poetry','','[]','散髮欹眠困鬰蒸，誰推河漢落紅塵。',64,'全唐诗/poet.song.240000.json','["散髮欹眠困鬰蒸，誰推河漢落紅塵。", "電光照雨不可盡，霧氣滿空疑有神。", "駕海怒潮新月夜，繞山腰鼓建溪春。", "此聲此景誰能寫，輸與城中不寐人。"]'),
('42addfea-4abd-4fef-a6de-4903d0e3b334','和簡齋十月','趙文','宋','宋诗','song-poetry','','[]','已慣禁秋不用悲，無情日月去如飛。',64,'全唐诗/poet.song.240000.json','["已慣禁秋不用悲，無情日月去如飛。", "霜晚起風鴉自宿，江南欲雪雁安歸。", "小園梅花照眼在，老子鬢毛如昔非。", "敗絮與官供戰卒，遥憐老婦泣牛衣。"]'),
('6de1c96e-9899-4880-8b22-d06bc8ae4edd','早過歷塘','趙文','宋','宋诗','song-poetry','','[]','細細清風吹月明，筍輿如泛夜舟行。',64,'全唐诗/poet.song.240000.json','["細細清風吹月明，筍輿如泛夜舟行。", "草根带露有蟲語，茅屋閉門唯犬聲。", "鬼燐影寒驚遠去，曜靈睡起亦東征。", "踏車田父莫嗟怨，如此早凉誰與爭。"]'),
('c1ade4aa-180b-4371-9b70-a173835f2cf6','海棠','趙文','宋','宋诗','song-poetry','','[]','纖纖光潤態偏濃，曲曲花蓬暖自融。',64,'全唐诗/poet.song.240000.json','["纖纖光潤態偏濃，曲曲花蓬暖自融。", "嬌淚惱公初著雨，豐肌病酒不宜風。", "人疑欲睡高燒燭，天悔無香剩與紅。", "正使吹殘亦何恨，向來艷艷本空空。"]'),
('4a727471-39db-4418-af50-b2ee68c98fb0','咏梅','趙文','宋','宋诗','song-poetry','','[]','我與梅花別一期，停雲倚樹鬢成絲。',64,'全唐诗/poet.song.240000.json','["我與梅花別一期，停雲倚樹鬢成絲。", "偶于蹊路相逢處，正似故人初見時。", "清裏有和夷惠聖，寒邊带瘦島郊詩。", "客中無酒能消得，共撥寒灰坐欲癡。"]'),
('0e78a057-e8de-4dfe-807e-b9250af11f8b','歐陽時可來訪感而問之故臨別贈此','趙文','宋','宋诗','song-poetry','','[]','二十七年重合并，舊遊回首絕堪驚。',64,'全唐诗/poet.song.240000.json','["二十七年重合并，舊遊回首絕堪驚。", "世間至竟壽多辱，造物不如君有情。", "白苧春風留古意，青燈夜雨話平生。", "子由無復連牀日，頼有秦黄是弟兄。"]'),
('56e40ed8-4f3b-4834-be74-406bae11cf6c','張南溟山長相邀紫極宮西雪樓登高姚南榿言北方異書載大鵬事','趙文','宋','宋诗','song-poetry','','[]','寫韻亭高樓更高，百年登覽著吾曹。',64,'全唐诗/poet.song.240000.json','["寫韻亭高樓更高，百年登覽著吾曹。", "客和月日成三九，我與鯤鵬共一毫。", "山吐南雲飛砲石，江橫西雪湧波濤。", "黄花到眼應多感，不欠黄花插鬢毛。"]'),
('3dcac7e0-7d8a-49ae-a7f3-1dd36796d554','丁酉元日示兒','趙文','宋','宋诗','song-poetry','','[]','新春喜見甲子日，汝輩豈知丁酉科。',64,'全唐诗/poet.song.240000.json','["新春喜見甲子日，汝輩豈知丁酉科。", "酒少亦呼鄰共飲，家寒敢問客能過。", "堆牀萬卷皆可飽，如此一貧吾已多。", "忽憶東坡戲趙叟，明年六十奈君何。"]'),
('acc834df-3fca-45cb-b637-c59c9de22716','富水曾教授夜飲有作','趙文','宋','宋诗','song-poetry','','[]','心齋聽講趁諸生，何意相逢曲豆城。',64,'全唐诗/poet.song.240000.json','["心齋聽講趁諸生，何意相逢曲豆城。", "急雨狂風十年夢，青燈白酒故人情。", "形骸改化悲歡異，歲月銷磨感慨平。", "却恐斗牛驚紫氣，寒爐今夜聚文星。"]'),
('568e984d-0570-4f9a-94bd-a8c6ddeaf2b7','飲袁國宗','趙文','宋','宋诗','song-poetry','','[]','一丈明窗便有餘，四人燕坐小蓬壺。',64,'全唐诗/poet.song.240000.json','["一丈明窗便有餘，四人燕坐小蓬壺。", "可憐一月半晴雨，未省百花今在無。", "眼底是詩皆可賦，樽中有酒不須沽。", "更闌醉後便歸去，頼有門生稚子扶。"]'),
('51f7e427-979e-4ad5-87d5-50dde3f69eb7','捕守宮','趙文','宋','宋诗','song-poetry','','[]','向來上陽人，盡屬沙叱利。',24,'全唐诗/poet.song.240000.json','["向來上陽人，盡屬沙叱利。", "長門不用守，蜥蜴草間戲。"]'),
('dc9824cf-b0ae-4b0b-99d1-5bab86485753','村行所見','趙文','宋','宋诗','song-poetry','','[]','良苗未成實，綠色相交加。',24,'全唐诗/poet.song.240000.json','["良苗未成實，綠色相交加。", "南風噓拂之，奔走如驚蛇。"]'),
('862c15e4-1a17-48f3-b51f-59fa9eb72219','晨起三首  其一','趙文','宋','宋诗','song-poetry','','[]','晨起出門去，江聲自悲咽。',24,'全唐诗/poet.song.240000.json','["晨起出門去，江聲自悲咽。", "滿目無行人，前山霧如雪。"]'),
('413aa8e9-a874-48f3-b5e8-1cda86815c89','晨起三首  其二','趙文','宋','宋诗','song-poetry','','[]','山寒日不光，舉目斷人腸。',24,'全唐诗/poet.song.240000.json','["山寒日不光，舉目斷人腸。", "兒童莫問路，怕是小篔簹。"]'),
('6150c524-9bc0-4c26-828b-d520ef162a8f','晨起三首  其三','趙文','宋','宋诗','song-poetry','','[]','三人相對眠，眠中各自夢。',24,'全唐诗/poet.song.240000.json','["三人相對眠，眠中各自夢。", "覺起偶開門，老樹綠不動。"]'),
('c91fa384-bbb5-44ac-91ea-2efca504a716','書扇二首  其一','趙文','宋','宋诗','song-poetry','','[]','明月何時掇，秋風幾日還。',24,'全唐诗/poet.song.240000.json','["明月何時掇，秋風幾日還。", "若教人不熱，敢怨我長閑。"]'),
('0fa440e3-f81b-4e79-b5c0-2bd24c553383','書扇二首  其二','趙文','宋','宋诗','song-poetry','','[]','牆外數莖新竹，樓西一抹斜陽。',28,'全唐诗/poet.song.240000.json','["牆外數莖新竹，樓西一抹斜陽。", "偶遊蟻穴初覺，細聽蟬聲自凉。"]'),
('aa1cc385-2e51-48c3-84c2-91dd75b6cfbd','睡起','趙文','宋','宋诗','song-poetry','','[]','小窗午熱倦如柳，睡起雨來江浪聲。',32,'全唐诗/poet.song.240000.json','["小窗午熱倦如柳，睡起雨來江浪聲。", "快意百年渾似此，不須浮海覓長生。"]'),
('b8ac5a74-10d8-477a-9e0a-c72c0f8f528b','竹枝詞  其一','趙文','宋','宋诗','song-poetry','','[]','終日望君君不來，爲誰猶住鬰孤臺。',32,'全唐诗/poet.song.240000.json','["終日望君君不來，爲誰猶住鬰孤臺。", "幸自一年無夢到，誰教昨日有書回。"]'),
('1b1ccca3-d5fc-49a3-9c0a-8babd1a99ba4','竹枝詞  其二','趙文','宋','宋诗','song-poetry','','[]','江南女兒善踏歌，桑落酒熟黄金波。',32,'全唐诗/poet.song.240000.json','["江南女兒善踏歌，桑落酒熟黄金波。", "洗壺日日望君至，君不來兮可奈何。"]'),
('3cc56d53-d989-451f-a527-9f62b7c8e6ca','聽兒童歌船作竹枝助之','趙文','宋','宋诗','song-poetry','','[]','田舍兒童走似麞，踏歌椎鼓鬭顛狂。',32,'全唐诗/poet.song.240000.json','["田舍兒童走似麞，踏歌椎鼓鬭顛狂。", "元宵乞汝閑幾日，元宵過後種田忙。"]'),
('4c19866d-e1e7-489e-aa2f-9f232898e801','哭亦周  其一','趙文','宋','宋诗','song-poetry','','[]','去日相携涉畏塗，歸來形影自相扶。',32,'全唐诗/poet.song.240000.json','["去日相携涉畏塗，歸來形影自相扶。", "倦行小憩荒山道，怕聽深叢叫鷓鴣。"]'),
('6f8d056f-4587-4300-8308-6ef94530cc0d','哭亦周  其二','趙文','宋','宋诗','song-poetry','','[]','堂上華顛泣欲枯，哭聲那解到黄壚。',32,'全唐诗/poet.song.240000.json','["堂上華顛泣欲枯，哭聲那解到黄壚。", "千般欲解郄公意，難得嘉賓一篋書。"]'),
('7b3b690e-8135-48cb-a3ba-ddf943cbde1f','哭亦周  其三','趙文','宋','宋诗','song-poetry','','[]','擢第君王與袍笏，蓋棺丞相辦深衣。',32,'全唐诗/poet.song.240000.json','["擢第君王與袍笏，蓋棺丞相辦深衣。", "江南仕宦堪車載，如此全歸似汝稀。"]'),
('39b66f97-d1bb-41bc-9a71-089288dc62db','哭亦周  其四','趙文','宋','宋诗','song-poetry','','[]','二十年來黍一炊，英風惟有塚纍纍。',32,'全唐诗/poet.song.240000.json','["二十年來黍一炊，英風惟有塚纍纍。", "兒童躑躅牛羊戲，陌上行人謂此誰。"]'),
('902b5d6f-38f1-4912-b397-85d25f84af43','皆山夜起  其一','趙文','宋','宋诗','song-poetry','','[]','上田下田水嘵嘵，南嶺北嶺蟲啁啁。',32,'全唐诗/poet.song.240000.json','["上田下田水嘵嘵，南嶺北嶺蟲啁啁。", "如此月明誰管領，可憐滿壁海棠梢。"]'),
('97180181-7876-48b9-b962-3bde40c94b1d','皆山夜起  其二','趙文','宋','宋诗','song-poetry','','[]','鄰家閉門月色好，籬落參差殘雪中。',32,'全唐诗/poet.song.240000.json','["鄰家閉門月色好，籬落參差殘雪中。", "想見老農方鼾睡，不知門外有清風。"]'),
('51b4e119-e0c9-4d56-8aee-5aab5016b284','正月十四日大雪上信國公冢  其一','趙文','宋','宋诗','song-poetry','','[]','哭得愁雲轉不晴，山風吹淚欲成冰。',32,'全唐诗/poet.song.240000.json','["哭得愁雲轉不晴，山風吹淚欲成冰。", "兩年不過西州路，今日來登下馬陵。"]'),
('c72d0098-860c-46f9-a63d-b2cba53865b0','正月十四日大雪上信國公冢  其二','趙文','宋','宋诗','song-poetry','','[]','氣概堂堂壓九州，誰知零落此荒丘。',32,'全唐诗/poet.song.240000.json','["氣概堂堂壓九州，誰知零落此荒丘。", "却煩野老編松葉，怕有牛羊上冢頭。"]'),
('ab8b40dc-bb3b-46fb-935f-30e2d8b3373f','正月十四日大雪上信國公冢  其三','趙文','宋','宋诗','song-poetry','','[]','共出長汀恰此朝，荒山露宿草蕭蕭。',32,'全唐诗/poet.song.240000.json','["共出長汀恰此朝，荒山露宿草蕭蕭。", "如今踏雪來看冢，回首當時未寂寥。"]'),
('07353782-41ce-43d7-9ae9-ef6596c2b414','正月十四日大雪上信國公冢  其四','趙文','宋','宋诗','song-poetry','','[]','十年目與腸俱斷，不見延平病雁回。',32,'全唐诗/poet.song.240000.json','["十年目與腸俱斷，不見延平病雁回。", "若不從公天上去，定應隨我雪中來。"]'),
('c97ac010-a351-4b9a-9ae9-d2135f9a64bb','讀史','趙文','宋','宋诗','song-poetry','','[]','夾寨功名節節奇，門高事起更堪悲。',32,'全唐诗/poet.song.240000.json','["夾寨功名節節奇，門高事起更堪悲。", "身亡家破英雄笑，恰似伶官戲罷時。"]'),
('25f6c086-3de8-478a-afcd-0fbcbf9d64bb','傷逝三首  其一','趙文','宋','宋诗','song-poetry','','[]','昨日相扶尚自存，今朝痛哭奠清尊。',32,'全唐诗/poet.song.240000.json','["昨日相扶尚自存，今朝痛哭奠清尊。", "如何一夜音容隔，便有紛紛說夢魂。"]'),
