('94498185-68c6-41fa-a608-212e6823c1f1','朱湖','趙文','宋','宋诗','song-poetry','','[]','高低櫸柳綠如苔，三兩柴門傍竹開。',32,'全唐诗/poet.song.240000.json','["高低櫸柳綠如苔，三兩柴門傍竹開。", "此處定無人挾彈，青青乳燕出溪來。"]'),
('df35991a-744c-4234-a2da-411bb53ef906','汶歸舟中','趙文','宋','宋诗','song-poetry','','[]','咿咿軋軋櫓聲歇，凄凄切切寒蛩鳴。',32,'全唐诗/poet.song.240000.json','["咿咿軋軋櫓聲歇，凄凄切切寒蛩鳴。", "滿空星斗不解語，時與漁火爭晶熒。"]'),
('a33881b8-76aa-4524-b967-8c45557ccf52','送春','趙文','宋','宋诗','song-poetry','','[]','曉起裁詩擬送春，臨池把筆意殷勤。',32,'全唐诗/poet.song.240000.json','["曉起裁詩擬送春，臨池把筆意殷勤。", "何人送得春曾去，只見春風解送君。"]'),
('44028bf3-aa9c-427e-8425-f6f61c1e0cff','次韻感舊','趙文','宋','宋诗','song-poetry','','[]','人間歲月如江波，歡樂苦少哀情多。',32,'全唐诗/poet.song.240000.json','["人間歲月如江波，歡樂苦少哀情多。", "千曲箜篌彈不盡，公無渡河公渡河。"]'),
('e6495233-8503-4057-b2fa-163120ad30f4','秋雨','趙文','宋','宋诗','song-poetry','','[]','秋雨沉沉酒醒遲，小窗燈火對唐詩。',32,'全唐诗/poet.song.240000.json','["秋雨沉沉酒醒遲，小窗燈火對唐詩。", "是誰隔屋鳴絃管，恰似吳山夢覺時。"]'),
