('84d16eb8-d2c0-4c01-9462-07c2e74ee127','水石圖贊','趙文','宋','宋诗','song-poetry','','[]','故園松菊，歸步月明。',20,'全唐诗/poet.song.240000.json','["故園松菊，歸步月明。", "蕭然獨往，百世之英。"]'),
('eab50069-4a17-4184-bf02-c555317c6f3f','遊虞山興福寺','周才','宋','宋诗','song-poetry','','[]','興福相傳古道場，杖藜乘興訪支郎。',64,'全唐诗/poet.song.240000.json','["興福相傳古道場，杖藜乘興訪支郎。", "案翻梵貝烟消篆，院寂棋聲日轉廊。", "玉版參師多古意，石梅問訊幾時香。", "禪家識得詩風味，清供杯茶熟煮湯。"]'),
('d5ea90d3-5425-44be-bf82-8c0291c3237c','遊虞山頂維摩院','周才','宋','宋诗','song-poetry','','[]','西風近重陽，青女作奇釀。',132,'全唐诗/poet.song.240000.json','["西風近重陽，青女作奇釀。", "高人事幽討，木落秋可望。", "山溪步屈曲，策以九節杖。", "林空眼界寬，雲深開法藏。", "歡迎雜鐘鼓，舞躍駭龍象。", "載酒得良友，靈山拉尋訪。", "同來八九輩，俱能尚疏曠。", "具饌擊紅鮮，折花泛新釀。", "修竹當翠袖，泉聲代清唱。", "徘徊欲盡歡，更上層巔上。", "要知本色人，方具六通相。"]'),
('0e7e32e6-43fa-4b60-afc7-8d881224a41b','題夫人石','單庚金','宋','宋诗','song-poetry','','[]','造化斲出蒼雲骨，娉婷如人更奇突。',64,'全唐诗/poet.song.240000.json','["造化斲出蒼雲骨，娉婷如人更奇突。", "千秋獨立日嶺頭，黛眉空翠含嬌羞。", "訪諸故老不可識，或是當年望夫石。", "當年望夫夫未歸，山頭化石空相憶。"]'),
('7bf91d1b-2176-4fb4-9ab4-f916ca8f1c9a','希文枕邊談詩謂律詩易工夢中與之辯詩以折其非既覺忘數字因足成之','洪德章','宋','宋诗','song-poetry','','[]','七步成詩語近諧，壇荒李杜乏奇才。',32,'全唐诗/poet.song.240000.json','["七步成詩語近諧，壇荒李杜乏奇才。", "僧敲未敢一言定，鳥過曾安幾字來。"]'),
('0166b8ac-b13f-4954-9646-65d07451a31a','遊白雲山','趙鞏','宋','宋诗','song-poetry','','[]','半生心事澹悠悠，應樂高卧白雲稠。',48,'全唐诗/poet.song.240000.json','["半生心事澹悠悠，應樂高卧白雲稠。", "青山影裏春酲解，黄雀聲中午夢休。", "好景隨處堪行樂，浮世何人免得愁。"]'),
('697ea049-538d-4b68-8b00-c52be9bc0cea','鴻門舞劍歌','汪宗臣','宋','宋诗','song-poetry','','[]','黑雲壓壘騅嘶風，荆軻聶政粗豪同。',160,'全唐诗/poet.song.240000.json','["黑雲壓壘騅嘶風，荆軻聶政粗豪同。", "舞筵閃動青蛇影，焉知火帝生真龍。", "一劍剡剡匹夫勇，一劍翼翼隨西東。", "壯士長戈氣罥虹，掃開霾曀曦光融。", "尊前張膽不爲屈，生彘臠割吞羣兇。", "子房笑語指顧頃，奚啻脫車深淖中。", "平陽帝譜炎精動，玉蜿蜒夜當其鋒。", "秦關恍服湯武出，赤幟彌張天下雄。", "金刀赫靈漢劍奮，烏江落日楚劍空。", "美人沒草騅沒水，項莊何處鳴秋蛩。"]'),
('750a1566-3eb0-42cf-9a9a-10d31f3bdba4','嘲賈似道','汪宗臣','宋','宋诗','song-poetry','','[]','賈秋壑，魏公爵，台州鬼，揚州鶴。',136,'全唐诗/poet.song.240000.json','["賈秋壑，魏公爵，台州鬼，揚州鶴。", "氣盈色驕逞才略，欺天罔人無愧怍。", "帷幄不能籌，金湯弗能作。", "費盡世間鐵，鑄此一大錯。", "關子形模賈字同，生兒德祐紀元中。", "甚慚嬰杵心莽卓，十可斬書真諤諤。", "鑼聲三下東江頭，鐵鞭一揮南海角。", "假賈僞魏至於斯，嗚呼似道道奚若。", "宋亡感激忠義多，遺臭如君梟獍惡。"]'),
('c7c978f4-20d0-49ee-8ce3-3265d64f587a','金陵鳳凰臺','汪宗臣','宋','宋诗','song-poetry','','[]','龍虎勢稱雄，鳳凰臺望濃。',48,'全唐诗/poet.song.240000.json','["龍虎勢稱雄，鳳凰臺望濃。", "潮翻江漢轉，地扼楚淮衝。", "平野頻烽火，孤城半稑穜。", "丹楹傍蕭寺，塵扆識高宗。"]'),
('0c476c01-5283-4989-899d-17a536afa5c7','稼穡','汪宗臣','宋','宋诗','song-poetry','','[]','稼穡病多雨，蕪菁種待晴。',48,'全唐诗/poet.song.240000.json','["稼穡病多雨，蕪菁種待晴。", "壘空驚燕去，池淨襯鷗明。", "野碓鳴秋杵，風簷響夜箏。", "山中凉意早，蚊蚋已無聲。"]'),
('a2fb512d-07b1-4bc5-8f08-38a36b52bc50','乙亥避地橫槎山中','汪宗臣','宋','宋诗','song-poetry','','[]','仙槎移到此，杳杳白雲根。',120,'全唐诗/poet.song.240000.json','["仙槎移到此，杳杳白雲根。", "石乳漏崖響，山腰界雨昏。", "徑幽盤過險，橋斷涉驚渾。", "百匝回峰曲，數家臨水村。", "芋瓜青繞屋，桑柘綠當門。", "鶻突兒迎客，龍鍾叟抱孫。", "澗舂分注沼，田穫半樊園。", "地僻衣巾古，人稀耕鑿溫。", "尚懷文杏館，且擬小桃源。", "嶺外風波別，摇頭勿復言。"]'),
('182404f0-93d2-4d3d-a514-014e4abd2af9','半山寺','汪宗臣','宋','宋诗','song-poetry','','[]','往事空求佛，當年誤買鄰。',24,'全唐诗/poet.song.240000.json','["往事空求佛，當年誤買鄰。", "悠悠思舐犢，烟雨暗松筠。"]'),
('a4824462-1962-4d28-9457-5e074d2ebe02','沖陶山中','汪宗臣','宋','宋诗','song-poetry','','[]','侵牀綠意多，過牖松花落。',24,'全唐诗/poet.song.240000.json','["侵牀綠意多，過牖松花落。", "草堂一編詩，送客不下閣。"]'),
('f642cddc-a22f-45f7-acd1-58461b89a9c3','新秋池上曉望','汪宗臣','宋','宋诗','song-poetry','','[]','淨植香來水北，殘蟬聲度橋東。',28,'全唐诗/poet.song.240000.json','["淨植香來水北，殘蟬聲度橋東。", "清沚金鱗漾綠，夕陽白鷺翻紅。"]'),
('8c0fa0ea-d3af-4ae0-95fe-8440b1083436','十一月宿於潛','汪宗臣','宋','宋诗','song-poetry','','[]','蜂迷蜜甕朮絲香，蟻泛花甆碧玉漿。',32,'全唐诗/poet.song.240000.json','["蜂迷蜜甕朮絲香，蟻泛花甆碧玉漿。", "縣僻人稀寒日晚，古松樛翠出危牆。"]'),
('76014e2c-3f07-4272-a4fe-9c23125c9291','燕雁','汪宗臣','宋','宋诗','song-poetry','','[]','秋來春去雁賓熟，秋去春來燕子忙。',32,'全唐诗/poet.song.240000.json','["秋來春去雁賓熟，秋去春來燕子忙。", "寒暑自分人事信，不須禽類互炎涼。"]'),
('1b4c2e13-2946-4407-b398-257dd5b7e63f','晚望','汪宗臣','宋','宋诗','song-poetry','','[]','野岸松杉暝色沉，漁翁收釣碧潭深。',32,'全唐诗/poet.song.240000.json','["野岸松杉暝色沉，漁翁收釣碧潭深。", "衝雲點點鷺飛疾，何處呼牛尚遠林。"]'),
('7036a3a0-133f-4292-aa80-842d89f44b5d','謁雲藍山先越公墓','汪宗臣','宋','宋诗','song-poetry','','[]','此生未展雲藍墓，鬰鬰甘棠孫子情。',64,'全唐诗/poet.song.240000.json','["此生未展雲藍墓，鬰鬰甘棠孫子情。", "今度忽爲寒食客，欣欣喬木歲時榮。", "堯天日月重光顯，越國江山幾變更。", "回首千年有歸鶴，練溪新漲匝春城。"]'),
('a7d79761-d233-4c32-8842-add999f788d2','弔鶴集詩句','汪宗臣','宋','宋诗','song-poetry','','[]','有鶴在林，翽翽其鳴。',62,'全唐诗/poet.song.240000.json','["有鶴在林，翽翽其鳴。", "風雨所漂摇，求其友生。", "不狩不獵，麾之以肱。", "宛其死矣，寧莫之懲。", "英英白雲，毋金玉爾音。", "如可贖兮，實勞我心。"]'),
('a52dd568-a4d0-4064-9084-3b13cef5deae','游老君洞  其一','劉子薦','宋','宋诗','song-poetry','','[]','第一真巖豈浪名，高明洞達窈而深。',64,'全唐诗/poet.song.240000.json','["第一真巖豈浪名，高明洞達窈而深。", "冠天下神仙勝境，副我生山水知音。", "崖激湍流騰雪玉，燈摇石瑩燦星金。", "少焉月出東山上，何必蓬萊海上尋。"]'),
('52698b0b-910f-4b0c-99c8-5958592b2637','游老君洞  其二','劉子薦','宋','宋诗','song-poetry','','[]','怪怪奇奇畫不如，最難得者近城郛。',64,'全唐诗/poet.song.240000.json','["怪怪奇奇畫不如，最難得者近城郛。", "他仙皆遜老君有，此洞可知天下無。", "徐甲青牛驂左侍，六丁白鶴導前驅。", "老仙笑我來何晚，一樣鬚眉一樣臞。"]'),
('c2f3eb81-d46f-4885-9b16-065cce44da56','楊梅洲別墅','燮元圃','宋','宋诗','song-poetry','','[]','枯桑敗葉集寒鴉，籬落芙蓉晚見花。',32,'全唐诗/poet.song.240000.json','["枯桑敗葉集寒鴉，籬落芙蓉晚見花。", "有客歸來新作主，釣魚灣處是生涯。"]'),
('86a90c39-7d1f-41d4-84ce-34357c67a8f6','過錦灣望嶽亭','燮元圃','宋','宋诗','song-poetry','','[]','十載重來一凭欄，光陰不改舊江山。',64,'全唐诗/poet.song.240000.json','["十載重來一凭欄，光陰不改舊江山。", "亭高下瞰龍藏室，天遠遥瞻虎拜班。", "耕釣每懷生處樂，馳驅未許老來閒。", "雄風入座披襟好，靜看漁舟上錦灣。"]'),
('0be25053-8ded-4da8-9495-843f1788a068','送徐殿院回鄉','林霆龍','宋','宋诗','song-poetry','','[]','三十年來人委靡，如今勁節似秋橫。',64,'全唐诗/poet.song.240000.json','["三十年來人委靡，如今勁節似秋橫。", "三條鯁亮爲時重，一葉翩翾去國輕。", "莘老不還司諫職，廖公應顯出臺名。", "遐衝尚頼精神折，未許林泉得隠聲。"]'),
('ecee3fe3-3b61-4c20-8855-9f8ea0afbfb4','句  其一','趙知軍','宋','宋诗','song-poetry','','[]','戰血肥春草，妖魂附野狐。',12,'全唐诗/poet.song.240000.json','["戰血肥春草，妖魂附野狐。"]'),
('82c56373-37e1-41c5-aab1-49cbf2ee201a','句  其二','趙知軍','宋','宋诗','song-poetry','','[]','風吹沙草落日黄，鴉啄髑髏飛不起。',16,'全唐诗/poet.song.240000.json','["風吹沙草落日黄，鴉啄髑髏飛不起。"]'),
('2c40cd85-4c11-4f69-ba65-3c054ab0dd37','秋步述所見','史衛卿','宋','宋诗','song-poetry','','[]','趁晴收斷薪，破曉循幽浦。',60,'全唐诗/poet.song.240000.json','["趁晴收斷薪，破曉循幽浦。", "山寒樹欲風，雲重天將雨。", "兔奔初種畦，雞拾穫殘畝。", "葉深樵無蹤，水落魚可數。", "幽草不須生，千林秋已素。"]'),
('a96a8c4a-47af-4aa0-b4e7-c9f61a62b8bc','捧檄家山','史衛卿','宋','宋诗','song-poetry','','[]','閒居愧未能，淮幕冷於冰。',48,'全唐诗/poet.song.240000.json','["閒居愧未能，淮幕冷於冰。", "家檄官無俸，山吟客有僧。", "池荒眠鷺石，樹折飲猿藤。", "寥落誰相問，孤明雨夜燈。"]'),
('b64bf08f-68a9-49af-a5c8-6f831b6930c5','春晴','史衛卿','宋','宋诗','song-poetry','','[]','平明晴可愛，眼界一湖春。',48,'全唐诗/poet.song.240000.json','["平明晴可愛，眼界一湖春。", "不見水中鷺，惟多堤上人。", "梅花已白盡，柳色正青新。", "日暮無歌舞，清幽屬野身。"]'),
('e62b39e6-2910-41e1-a8fb-e87b74fe18a3','聽演師琴','史衛卿','宋','宋诗','song-poetry','','[]','禪悟却參琴，山高水復深。',48,'全唐诗/poet.song.240000.json','["禪悟却參琴，山高水復深。", "七絃手共語，萬籟耳無音。", "激烈鬼神淚，發揮天地心。", "秋風時一曲，懷古更傷今。"]'),
('4f36782e-4b43-40f9-a1de-5ef2b91d6ed8','漁父','史衛卿','宋','宋诗','song-poetry','','[]','白頭長是醉，湖海不知年。',48,'全唐诗/poet.song.240000.json','["白頭長是醉，湖海不知年。", "活業惟耕綱，全家衹住船。", "荷花同鷺宿，楊柳得魚穿。", "一笛吹明月，朱門謾管絃。"]'),
('4bb8ff59-1db5-403a-a59e-c5179555e05b','書里中所見','史衛卿','宋','宋诗','song-poetry','','[]','闌干十二纈簾遮，獸棟鱗鱗鼎貴家。',32,'全唐诗/poet.song.240000.json','["闌干十二纈簾遮，獸棟鱗鱗鼎貴家。", "莫道樓臺無地起，滿城秋色半槐花。"]'),
('25687a3d-b7fa-4eb9-9f7a-921964b85f91','所見','史衛卿','宋','宋诗','song-poetry','','[]','齊眉沉醉綺羅叢，心事誰知付去鴻。',32,'全唐诗/poet.song.240000.json','["齊眉沉醉綺羅叢，心事誰知付去鴻。", "不惜千金留粉黛，更無一語怨東風。"]'),
('c9e92f04-dbec-4704-bef3-fc00183d592a','有所見','史衛卿','宋','宋诗','song-poetry','','[]','不著畫羅金縷衣，尋常打扮最相宜。',32,'全唐诗/poet.song.240000.json','["不著畫羅金縷衣，尋常打扮最相宜。", "春風燕子樓前過，飄落梨花雪一枝。"]'),
('f5e358b2-d075-4d40-a70b-041851673f93','冷泉觀放水','史衛卿','宋','宋诗','song-poetry','','[]','溪流平地響晴雷，石上生風捲雪來。',32,'全唐诗/poet.song.240000.json','["溪流平地響晴雷，石上生風捲雪來。", "醉拍闌干衣袖濕，十分身在白雲堆。"]'),
('6a8bca2a-fb76-4ee5-af7d-3dcabf07cddc','西湖山居燈夕','史衛卿','宋','宋诗','song-poetry','','["\u897f\u6e56"]','繁華隔湖水，全似遠宸京。',48,'全唐诗/poet.song.240000.json','["繁華隔湖水，全似遠宸京。", "燈火少年夢，山林此夜情。", "鶴閑梅下立，人靜月中行。", "長願歲時好，吟身見太平。"]'),
('6a776a92-7ab3-4ce0-a812-e07ad6dcb95c','依韻奉和司徒侍中龍興燈夕','史衛卿','宋','宋诗','song-poetry','','[]','寶炬燃紅映百坊，佛燈相照有餘光。',64,'全唐诗/poet.song.240000.json','["寶炬燃紅映百坊，佛燈相照有餘光。", "樽前盡被公孫禮，席上惟無處士狂。", "午夜笙歌歡是伯，幾家簾幕醉成鄉。", "都人猶怕春宵短，共樂何妨舞袖長。"]'),
('e9ce95a5-ba8f-4cab-86b6-0b1bd242dd2c','落花','嚴肅','宋','宋诗','song-poetry','','[]','片片落花飛，隨風去不歸。',24,'全唐诗/poet.song.240000.json','["片片落花飛，隨風去不歸。", "如何臨欲別，不得傍君衣。"]'),
('670d3b61-82ad-4c4d-b893-a8cab12bddb3','怡怡亭','王景雲','宋','宋诗','song-poetry','','[]','老年常聚首，兄弟共怡怡。',48,'全唐诗/poet.song.240000.json','["老年常聚首，兄弟共怡怡。", "並坐閒揮麈，交斟醒設巵。", "雙聲頻檢韻，讓道更敲棋。", "自是天倫樂，嬉遊似少時。"]'),
('20859b16-27ec-48d5-b37f-86bec79bc7fa','怡怡亭','王景華','宋','宋诗','song-poetry','','[]','怡怡亭畔路，兄到弟隨肩。',48,'全唐诗/poet.song.240000.json','["怡怡亭畔路，兄到弟隨肩。", "花徑同調瑟，蘭窗共擘箋。", "看山携老杖，分果憶兒筵。", "底事常相忍，張家未是賢。"]'),
('937c9316-b95a-42c5-b806-12d34af2aaff','釣鼇亭','趙傑之','宋','宋诗','song-poetry','','[]','天地分來萬古多，鰲魚背穩駕山河。',64,'全唐诗/poet.song.240000.json','["天地分來萬古多，鰲魚背穩駕山河。", "亭前見說高人釣，池上那聞漁父歌。", "四面青峰環秀色，一灣綠水漾清波。", "誰能掣斷黄金索，終日持竿怎奈何。"]'),
('f27326f4-9b8d-4727-9bd4-62d785c802b1','白府真君','趙傑之','宋','宋诗','song-poetry','','[]','卓茂當年政術優，治聲終不似賢侯。',32,'全唐诗/poet.song.240000.json','["卓茂當年政術優，治聲終不似賢侯。", "顯幽一致施仁化，廟食中山卒未休。"]'),
('df4b0536-35d1-4b35-9ba7-73173c58f8fb','采薇圖','蔡必薦','宋','宋诗','song-poetry','','[]','西山有薇，美人不移。',40,'全唐诗/poet.song.240000.json','["西山有薇，美人不移。", "西山無薇，美人不歸。", "采薇采薇，山是人非。", "薇滿西山，不生夷齊。"]'),
('901ee68c-5ded-4bd4-9261-faf3d99f30dc','觀葵有感','蔡必薦','宋','宋诗','song-poetry','','["\u5199\u82b1", "\u751f\u6d3b", "\u6292\u6000", "\u82b1"]','昨日一花開，今日一花開。',70,'全唐诗/poet.song.240000.json','["昨日一花開，今日一花開。", "今日花正好，昨日花已老。", "始知人老不如花，可惜落花君莫掃。", "人生不得長少年，莫負床頭沽酒錢。", "得錢向酒家，君不見，戎葵花。"]'),
('8d00681c-6b3f-4fdc-ae44-35004dd30140','寓意漫成','蔡必薦','宋','宋诗','song-poetry','','[]','東鄰老翁富鉅萬，每日關門常獨飯。',82,'全唐诗/poet.song.240000.json','["東鄰老翁富鉅萬，每日關門常獨飯。", "西鄰少年居錢不滿百，每日開筵延上客。", "老翁回頭問少年，君家賓客何駢闐。", "少年答曰翁不知，人生許得幾何時。", "翁看日月如流水，牢鎖黄金與阿誰。"]'),
('d612d43c-e224-469a-9b9f-ca1c818caef8','題江湖偉觀','范晞文','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖何處可消愁，快上人間百尺樓。',64,'全唐诗/poet.song.240000.json','["西湖何處可消愁，快上人間百尺樓。", "千里山川浮王氣，百年形勢壯皇州。", "逋仙宅近梅應古，坡老祠空竹自秋。", "立徧闌干無限意，六橋歌舞懶回頭。"]'),
('9802c1f2-0a4e-4951-9483-292fa52db16e','湖上','范晞文','宋','宋诗','song-poetry','','[]','湖邊多少遊湖者，半在斷橋烟雨間。',32,'全唐诗/poet.song.240000.json','["湖邊多少遊湖者，半在斷橋烟雨間。", "盡逐春風看歌舞，幾人著眼到青山。"]'),
('1582ca9f-90af-46cc-ba97-f3c45a62e5ed','燕山聞鵑','范晞文','宋','宋诗','song-poetry','','[]','燕山三月初三夜，聽得啼鵑第一聲。',32,'全唐诗/poet.song.240000.json','["燕山三月初三夜，聽得啼鵑第一聲。", "同是小樓孤燭下，主人熟睡客驚心。"]'),
('6c3a1547-b480-40a3-83ca-f517c053d183','寄友人張孝忠','上官藻','宋','宋诗','song-poetry','','[]','瀟瀟落葉滿江城，冽地金風變世情。',64,'全唐诗/poet.song.240000.json','["瀟瀟落葉滿江城，冽地金風變世情。", "無日不傷車北渡，有書難寄雁南征。", "曉霜滿地歸心切，夜月懸梁夢不成。", "渴望餘波今已久，何時握手笑相迎。"]'),
('bf7596ae-ca5d-476e-b1f5-a5c223aca9b9','謝程鉅夫學士','吳仲軒','宋','宋诗','song-poetry','','[]','抱疾經年久，何期徵詔臨。',48,'全唐诗/poet.song.240000.json','["抱疾經年久，何期徵詔臨。", "芸窗書已蠹，竹徑葉尤深。", "空返皇華使，難忘鷗鳥心。", "懷君雖感激，衰鬢不勝簪。"]'),
('1fb52301-2d05-4e8f-92cc-fb38d4afee08','竹節亭','張璹','宋','宋诗','song-poetry','','[]','結構華亭歲月深，形如竹節俯山陰。',64,'全唐诗/poet.song.240000.json','["結構華亭歲月深，形如竹節俯山陰。", "規模自壯中山色，基業猶存萬古心。", "窗外豈無猿鶴唳，簷前時有鳳凰吟。", "夜深神鬼驚聞處，月下誰彈一曲琴。"]'),
('4f8588c8-3df3-4791-896d-13a476e5a18d','洴溪橋','趙渥','宋','宋诗','song-poetry','','[]','油井小聚，洴溪之濱。',110,'全唐诗/poet.song.240000.json','["油井小聚，洴溪之濱。", "夏秋雨集，溝澮皆盈。", "衆水所匯，實病於行。", "誰作斯橋，龐君守真。", "甯瘠一己，而利他人。", "此心與橋，爲世通津。", "我觀地水，如車轉輪。", "陵谷變遷，成毀有因。", "橋不足恃，所恃者仁。", "仁者之心，與石不磷。", "矢我銘詩，刻此堅珉。"]'),
('b206bdbf-d8e5-482b-a690-832d7b273c18','化城寺','陳巖','宋','宋诗','song-poetry','','[]','匝徑茸茸菜甲青，透池艷艷藕花明。',32,'全唐诗/poet.song.240000.json','["匝徑茸茸菜甲青，透池艷艷藕花明。", "四方衲子尋幽踐，多少空山振錫聲。"]'),
('2a559977-7d08-49a6-bc4f-42d638292405','化城池','陳巖','宋','宋诗','song-poetry','','[]','簇簇青蓮滿意開，老僧誇說舊栽培。',32,'全唐诗/poet.song.240000.json','["簇簇青蓮滿意開，老僧誇說舊栽培。", "塵埃不涅花心性，淨客原從淨土來。"]'),
('d8f11da1-a3be-4878-93bc-88e431556bdf','半霄亭','陳巖','宋','宋诗','song-poetry','','[]','烟際晴嵐似有無，舉頭相望是雲衢。',32,'全唐诗/poet.song.240000.json','["烟際晴嵐似有無，舉頭相望是雲衢。", "若爲透入雲間路，直渡銀河採白榆。"]'),
('511d0197-d675-4039-824d-1fd4e5b756ba','望江亭','陳巖','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','衮衮長江浸落暉，水流不盡覺雲移。',32,'全唐诗/poet.song.240000.json','["衮衮長江浸落暉，水流不盡覺雲移。", "登高忽動離騷恨，無奈山川苦要詩。"]'),
('37f62573-f188-4e53-be32-1c53537a75b8','地藏塔','陳巖','宋','宋诗','song-poetry','','[]','八十四級山頭石，五百餘年地藏墳。',32,'全唐诗/poet.song.240000.json','["八十四級山頭石，五百餘年地藏墳。", "風撼塔鈴天半語，衆人都向夢中聞。"]'),
('0e6a971d-b63a-42ae-91e9-fb01bff672c6','笑指亭','陳巖','宋','宋诗','song-poetry','','[]','多少人間狹路偏，山川還是舊山川。',32,'全唐诗/poet.song.240000.json','["多少人間狹路偏，山川還是舊山川。", "淡然忘笑兼忘指，嘿嘿真成第一禪。"]'),
('e0bc066a-d099-4f30-b704-60e32ed667a5','李白書堂','陳巖','宋','宋诗','song-poetry','','[]','蘭芷春風滿地香，謫仙曾卧白雲鄉。',32,'全唐诗/poet.song.240000.json','["蘭芷春風滿地香，謫仙曾卧白雲鄉。", "山間精爽今猶在，落月時時見屋梁。"]'),
('9e20f9ff-c964-415d-aaa4-66bbe783f37b','神光嶺','陳巖','宋','宋诗','song-poetry','','[]','眼看恒河幾劫沙，隨身鎖子骨鈎加。',32,'全唐诗/poet.song.240000.json','["眼看恒河幾劫沙，隨身鎖子骨鈎加。", "嶺頭閃閃神光動，無盡燈中轉法華。"]'),
('69594749-06c7-449c-a463-eb3d7d6fd41f','南臺','陳巖','宋','宋诗','song-poetry','','[]','舊日新羅國裏僧，山間散滿百千燈。',32,'全唐诗/poet.song.240000.json','["舊日新羅國裏僧，山間散滿百千燈。", "只將一嘿消諸妄，坐透禪機最上乘。"]'),
('a0a22846-dcae-425e-adbd-318ada39e4c3','晏坐巖','陳巖','宋','宋诗','song-poetry','','[]','掠地霜風黄葉飛，山人晏坐已多時。',32,'全唐诗/poet.song.240000.json','["掠地霜風黄葉飛，山人晏坐已多時。", "但知六鑿俱通透，不省支牀舊有龜。"]'),
('e0836cca-0705-4f18-8f34-557ac784ae7a','白蟮穴','陳巖','宋','宋诗','song-poetry','','[]','炊沙自昔終難飽，坎土于今乃可餐。',32,'全唐诗/poet.song.240000.json','["炊沙自昔終難飽，坎土于今乃可餐。", "翻笑青泥變青石，嵇康無分啜仙丹。"]'),
('42343890-1f52-4534-9c1c-5f7d17df6b9e','龍女泉','陳巖','宋','宋诗','song-poetry','','[]','祖師正渴山頭水，龍女俄分海眼泉。',32,'全唐诗/poet.song.240000.json','["祖師正渴山頭水，龍女俄分海眼泉。", "萬事不離無始劫，千年賸結未來緣。"]'),
('dac9b78c-3fa3-4066-9ae9-ff8816ebab5b','茗地源','陳巖','宋','宋诗','song-poetry','','[]','暖風吹長紫芽莖，人向山頭就水烹。',32,'全唐诗/poet.song.240000.json','["暖風吹長紫芽莖，人向山頭就水烹。", "陸羽儻曾經此地，谷簾安得擅佳名。"]'),
('2b20aa6b-a558-4bb7-8f8f-0370f933551c','東藏源','陳巖','宋','宋诗','song-poetry','','[]','膩雨增多樹色深，惠風吹轉藥苗新。',32,'全唐诗/poet.song.240000.json','["膩雨增多樹色深，惠風吹轉藥苗新。", "一灣水繞旃檀國，流向山前普濟人。"]'),
('f2954678-076f-4619-b751-ff90476b87a0','中峰','陳巖','宋','宋诗','song-poetry','','[]','岪鬰盤紆直拄空，衆峰環繞獨居中。',32,'全唐诗/poet.song.240000.json','["岪鬰盤紆直拄空，衆峰環繞獨居中。", "山頭要看僧禪定，南北東西路各通。"]'),
('9123bc98-05e1-46ee-9b0a-b6bc5b2b5564','會仙峰','陳巖','宋','宋诗','song-poetry','','[]','仙袂飄飄拂翠巔，知微來此宴群仙。',32,'全唐诗/poet.song.240000.json','["仙袂飄飄拂翠巔，知微來此宴群仙。", "人間風雨山間月，始信仙家別有天。"]'),
('b208d465-1d46-4756-aef5-3d10798b8a55','大還嶺','陳巖','宋','宋诗','song-poetry','','[]','龜腸刳盡不緣饑，鶴骨生來豈解肥。',32,'全唐诗/poet.song.240000.json','["龜腸刳盡不緣饑，鶴骨生來豈解肥。", "煉得丹成生羽翼，山中無復趙知微。"]'),
('b8804095-3bca-4c0c-b1a7-77d36cb8164f','斧柯嶺','陳巖','宋','宋诗','song-poetry','','[]','偶爾觀棋忽爛柯，豈知勝負是如何。',32,'全唐诗/poet.song.240000.json','["偶爾觀棋忽爛柯，豈知勝負是如何。", "歸來笑問人間事，恰是人間勝負多。"]'),
('d51a28aa-cae4-4ba5-8237-dc3ee512011f','甘露泉','陳巖','宋','宋诗','song-poetry','','[]','山接靈河兩派長，松間石上瀉天漿。',32,'全唐诗/poet.song.240000.json','["山接靈河兩派長，松間石上瀉天漿。", "幾思吸取清泠味，洗我一生烟火腸。"]'),
('c7ac33c0-c9b1-4ba6-89f1-fea3b39b30b9','澌澌水','陳巖','宋','宋诗','song-poetry','','[]','危柱抨抨曳素絲，水聲還解發天機。',32,'全唐诗/poet.song.240000.json','["危柱抨抨曳素絲，水聲還解發天機。", "風來未定風還住，恍訝山中鼓瑟希。"]'),
('9ba738c7-8a33-4574-9c1e-d5b4c3d13cf2','飲猿潭','陳巖','宋','宋诗','song-poetry','','[]','月照秋空風滿林，孤猿渴飲碧潭深。',32,'全唐诗/poet.song.240000.json','["月照秋空風滿林，孤猿渴飲碧潭深。", "我今忘我兼忘物，兀坐怡然不動心。"]'),
('6bb8f226-8724-4115-90bd-3da541927509','漂溪','陳巖','宋','宋诗','song-poetry','','[]','摇摇曳曳水西流，風定波凝不起漚。',32,'全唐诗/poet.song.240000.json','["摇摇曳曳水西流，風定波凝不起漚。", "傍岸人家星散住，塵埃終莫污沙鷗。"]'),
('f3904466-5d26-4aba-899f-e756cd7d335f','龍池','陳巖','宋','宋诗','song-poetry','','[]','噴激喧豗無已時，驚雷出地怒濤隨。',32,'全唐诗/poet.song.240000.json','["噴激喧豗無已時，驚雷出地怒濤隨。", "水從千仞峰頭過，遇險應成一段奇。"]'),
('b4e1be67-ed98-4d37-9fdf-163a9e819c0c','五龍灣','陳巖','宋','宋诗','song-poetry','','[]','石骨分開四角稜，日華磨透鏡光明。',32,'全唐诗/poet.song.240000.json','["石骨分開四角稜，日華磨透鏡光明。", "水流圓折仍方折，忽作鏗然戛玉聲。"]'),
('6df247f6-7fde-4d12-8fed-0e6d58ab0b3d','千尺泉','陳巖','宋','宋诗','song-poetry','','[]','下臨無地上連天，中有飛流湧滿泉。',32,'全唐诗/poet.song.240000.json','["下臨無地上連天，中有飛流湧滿泉。", "今我不圖今日到，詩成要檄兩龍眠。"]'),
('5c75dc1e-4d3b-4cbc-874e-8434acf5513c','弄珠潭','陳巖','宋','宋诗','song-poetry','','[]','龍抱明珠出岸隈，夜光草木亦昭回。',32,'全唐诗/poet.song.240000.json','["龍抱明珠出岸隈，夜光草木亦昭回。", "叮嚀莫向深潭睡，恐有人從頷底來。"]'),
('3fa87ece-2a6f-4e4d-9ef9-890a90798383','綺霞峰','陳巖','宋','宋诗','song-poetry','','[]','欲識晴嵐態度奇，直須待到夕陽時。',32,'全唐诗/poet.song.240000.json','["欲識晴嵐態度奇，直須待到夕陽時。", "回光倒影山如染，狀出餘霞散綺詩。"]'),
('5de5348a-c102-4ed2-9436-cc1458dcf40e','龍池庵','陳巖','宋','宋诗','song-poetry','','[]','惠崇往矣邈遺蹤，時有風來撼古松。',32,'全唐诗/poet.song.240000.json','["惠崇往矣邈遺蹤，時有風來撼古松。", "想見草庵無恙日，月明池上獨支筇。"]'),
('390700e3-fa9c-49e5-912c-e2513a0cf02d','花塘澗','陳巖','宋','宋诗','song-poetry','','[]','疏巖剔藪空王宅，金碧光中開寶坊。',32,'全唐诗/poet.song.240000.json','["疏巖剔藪空王宅，金碧光中開寶坊。", "日日散花方丈裏，山門流水例沾香。"]'),
('303de2c0-a614-47a5-a64b-ea11c879dfca','鳳皇嶺','陳巖','宋','宋诗','song-poetry','','[]','望望梧桐一剗齊，山深曾是鳳來棲。',32,'全唐诗/poet.song.240000.json','["望望梧桐一剗齊，山深曾是鳳來棲。", "只今吾道非耶是，更有何人歌鳳兮。"]'),
('b00545ef-db25-4eb2-a47f-e5f6a5c19005','碧桃巖','陳巖','宋','宋诗','song-poetry','','[]','自要貪閒非避秦，洞門隔斷世間塵。',32,'全唐诗/poet.song.240000.json','["自要貪閒非避秦，洞門隔斷世間塵。", "山中不置四時歷，開到碧桃知是春。"]'),
('c3ec8134-60cf-4fc5-8f00-a98bf8aa0866','延華觀','陳巖','宋','宋诗','song-poetry','','[]','五百年間岸谷移，邯鄲枕上夢回時。',32,'全唐诗/poet.song.240000.json','["五百年間岸谷移，邯鄲枕上夢回時。", "兔葵燕麥玄都觀，好繼劉郎舊日詩。"]'),
('208f0736-3858-4cbc-8a18-3e4e77434345','浮桃澗','陳巖','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山董鳳曾栽杏，鳳嶺知微亦種桃。',32,'全唐诗/poet.song.240000.json','["廬山董鳳曾栽杏，鳳嶺知微亦種桃。", "怕有人來問前古，澗中不肯放漁舠。"]'),
