('02493dcc-294b-4eb3-8cc7-8250c095b86c','吳氏新城宅','陳巖','宋','宋诗','song-poetry','','[]','溪聲西去疾於雷，山麓雲根翠戶開。',32,'全唐诗/poet.song.240000.json','["溪聲西去疾於雷，山麓雲根翠戶開。", "枉却幽尋三十載，壺天月窟欠曾來。"]'),
('36101ff8-7977-4124-8101-8208818b2a0b','新城精舍','陳巖','宋','宋诗','song-poetry','','[]','朱甍碧瓦粉牆圍，花舫回光洞戶輝。',32,'全唐诗/poet.song.240000.json','["朱甍碧瓦粉牆圍，花舫回光洞戶輝。", "自是故家開第宅，喬林景物兩芳菲。"]'),
('aa6c2fd2-81f8-42fa-96bd-8fdc1c998786','翠光亭','陳巖','宋','宋诗','song-poetry','','[]','呷呷波間錦羽明，地無塵處可幽亭。',32,'全唐诗/poet.song.240000.json','["呷呷波間錦羽明，地無塵處可幽亭。", "喚回天上張公子，來與山家注水經。"]'),
('a1056275-2a95-45da-a2a2-0b88de3880af','源清莊','陳巖','宋','宋诗','song-poetry','','[]','湊入方池一脈泉，泥沙不雜性中天。',32,'全唐诗/poet.song.240000.json','["湊入方池一脈泉，泥沙不雜性中天。", "時時自照清癯影，白露風標是水仙。"]'),
('211c1d36-b687-4b7a-95e5-7379d68eba17','王季文書堂','陳巖','宋','宋诗','song-poetry','','[]','要學騎蟾主簿仙，休官直上九華巔。',32,'全唐诗/poet.song.240000.json','["要學騎蟾主簿仙，休官直上九華巔。", "我來細讀碑間字，風葉時時一颯然。"]'),
('e5d4d34a-eb8f-49e8-b891-c374d2d1ef60','頭陀嶺無相院','陳巖','宋','宋诗','song-poetry','','[]','頭陀嶺下招提境，畫閣闌干幾度凭。',32,'全唐诗/poet.song.240000.json','["頭陀嶺下招提境，畫閣闌干幾度凭。", "遊客驟來還倏去，看山輸與在家僧。"]'),
('c0685dff-01eb-490c-a77b-b6ad4ba0a188','金沙泉','陳巖','宋','宋诗','song-poetry','','[]','金能生水水涵金，本本源源造化心。',32,'全唐诗/poet.song.240000.json','["金能生水水涵金，本本源源造化心。", "幾許碎金隨水出，披沙終日若爲尋。"]'),
('49aa5591-7cf7-4aa7-812b-0b8e0904dcfb','秀綠亭','陳巖','宋','宋诗','song-poetry','','[]','曾看雙峰老子詩，秀攢綠繞妙天機。',32,'全唐诗/poet.song.240000.json','["曾看雙峰老子詩，秀攢綠繞妙天機。", "有人愛此無聲畫，更著幽亭相發揮。"]'),
('af37a412-5290-4def-870e-9c71ab3c192c','雙峰','陳巖','宋','宋诗','song-poetry','','[]','仙洞深沉杳不扃，層巒雙聳插天青。',32,'全唐诗/poet.song.240000.json','["仙洞深沉杳不扃，層巒雙聳插天青。", "矞雲常抱山頭石，曾是前朝嶽降靈。"]'),
