('cd621c5e-7803-4a81-a873-9a26f59102c6','三游洞','陳巖','宋','宋诗','song-poetry','','[]','清風披拂蘚苔痕，洞裏仙鄉萬古春。',32,'全唐诗/poet.song.240000.json','["清風披拂蘚苔痕，洞裏仙鄉萬古春。", "有路盡通塵世客，來遊何獨是三人。"]'),
('1e69ee2f-b5da-4c5e-b872-3a431a2cc5e9','十丈洞','陳巖','宋','宋诗','song-poetry','','[]','水從洞口瀉玻瓈，松檜林中日影低。',32,'全唐诗/poet.song.240000.json','["水從洞口瀉玻瓈，松檜林中日影低。", "勝景略無人避世，始知不是武林溪。"]'),
('0d5e1b40-cc39-4e2a-8c22-cdeca95db0f5','上下華池','陳巖','宋','宋诗','song-poetry','','[]','聽鐘喫飯東西寺，就水烹茶上下池。',32,'全唐诗/poet.song.240000.json','["聽鐘喫飯東西寺，就水烹茶上下池。", "二百年來陳迹在，摩挲苔蘚日西時。"]'),
('c45a9a16-fedf-416f-93c6-0a91c67fe126','合澗','陳巖','宋','宋诗','song-poetry','','[]','澗分南北兩源通，繞轉春山翠幾重。',32,'全唐诗/poet.song.240000.json','["澗分南北兩源通，繞轉春山翠幾重。", "偶爾混然成一派，滔滔東去共朝宗。"]'),
('f9a4828f-3c3f-4c00-83bc-289461b27e52','獨秀峰','陳巖','宋','宋诗','song-poetry','','[]','一山夐出衆山中，日照烟浮紫翠濃。',32,'全唐诗/poet.song.240000.json','["一山夐出衆山中，日照烟浮紫翠濃。", "山不爭高人共仰，幾多丘垤儼相從。"]'),
('5f3b3102-2df7-4b19-b112-e7c816e3cbe1','雙溪','陳巖','宋','宋诗','song-poetry','','[]','二水來從翠嶺頭，相逢澗谷却同流。',32,'全唐诗/poet.song.240000.json','["二水來從翠嶺頭，相逢澗谷却同流。", "冷光如鏡清人骨，探借山間六月秋。"]'),
('4850f3b9-7334-4f40-b4ef-aa5e3f1307b1','清漪潭','陳巖','宋','宋诗','song-poetry','','[]','水出雙溪似鏡平，縈迴遇石自成文。',32,'全唐诗/poet.song.240000.json','["水出雙溪似鏡平，縈迴遇石自成文。", "眼明波上誰相對，只有飛來白鷺群。"]'),
('09c40db8-4074-4b4a-9af5-231da8aee497','清隠巖','陳巖','宋','宋诗','song-poetry','','[]','一生不買真清譽，平日不歌招隠詩。',32,'全唐诗/poet.song.240000.json','["一生不買真清譽，平日不歌招隠詩。", "底事琢山成大字，有名還被衆人知。"]'),
('8fdc9976-2122-4f20-825f-3cbd12453dde','劉世疏庵','陳巖','宋','宋诗','song-poetry','','[]','亂草枯茅町疃場，寒風捲地日荒荒。',32,'全唐诗/poet.song.240000.json','["亂草枯茅町疃場，寒風捲地日荒荒。", "有來提起山庵話，又是先生朽骨香。"]'),
('471b521f-77da-41e2-83ef-f625413c2f30','翠蓋峰','陳巖','宋','宋诗','song-poetry','','[]','烟際亭亭出古崖，幾層翠蓋倚天開。',32,'全唐诗/poet.song.240000.json','["烟際亭亭出古崖，幾層翠蓋倚天開。", "鏗然風向林梢過，知有神仙玉珮來。"]'),
('b91ca9de-08e0-4363-8999-3456e53d2b7c','上雪潭三汲亭','陳巖','宋','宋诗','song-poetry','','[]','水沫拋來驟出奇，滿空灑下雪紛披。',32,'全唐诗/poet.song.240000.json','["水沫拋來驟出奇，滿空灑下雪紛披。", "雲端驚見雙峰面，恰是仙人剪水時。"]'),
('7ce1bd39-d617-4464-99bf-2d4d766cedc4','下雪潭雪浪亭','陳巖','宋','宋诗','song-poetry','','[]','潭面摇光媚日華，水文倒影射簷牙。',32,'全唐诗/poet.song.240000.json','["潭面摇光媚日華，水文倒影射簷牙。", "倚闌如在雲霄上，俯看縈風萬雪花。"]'),
('61e38f31-b8f4-4416-ad8b-710ddc639cd1','瓔珞泉','陳巖','宋','宋诗','song-poetry','','[]','花花結結淨無塵，却笑莊嚴未是真。',32,'全唐诗/poet.song.240000.json','["花花結結淨無塵，却笑莊嚴未是真。", "五色明珠光照水，湛然清淨本來身。"]'),
('8a9f70ae-dbbf-4a64-9508-e922689853d7','廣修院','陳巖','宋','宋诗','song-poetry','','[]','別去招提恰十霜，幾番夢到五峰堂。',32,'全唐诗/poet.song.240000.json','["別去招提恰十霜，幾番夢到五峰堂。", "有懷此地同僧夏，對佛閒燒結愿香。"]'),
('b0e336d3-0fc5-4430-8323-c0531557c4d3','蓮花峰','陳巖','宋','宋诗','song-poetry','','[]','風動雲開淨客顔，三千丈石錦爛斑。',32,'全唐诗/poet.song.240000.json','["風動雲開淨客顔，三千丈石錦爛斑。", "淤泥不是花開處，擢出天河綠水間。"]'),
('25d766de-0b28-4f87-8358-f62588591e71','瀾溪','陳巖','宋','宋诗','song-poetry','','[]','小溪亦有怒濤翻，可但滄溟始足觀。',32,'全唐诗/poet.song.240000.json','["小溪亦有怒濤翻，可但滄溟始足觀。", "世事會心無廣狹，請君來此試觀瀾。"]'),
('d32bbb79-94a5-4908-b471-f1278f71b3c5','濯纓潭','陳巖','宋','宋诗','song-poetry','','[]','山深地僻人稀到，安得滄浪孺子歌。',32,'全唐诗/poet.song.240000.json','["山深地僻人稀到，安得滄浪孺子歌。", "纓上本無塵可濯，莫將止水强揚波。"]'),
('c9a6f8eb-b8b7-4fe5-ade9-21bfc48de53f','安禪峰','陳巖','宋','宋诗','song-poetry','','[]','山頭兀坐已忘年，咫尺孤雲兩角天。',32,'全唐诗/poet.song.240000.json','["山頭兀坐已忘年，咫尺孤雲兩角天。", "但有圓明真實在，是身何往不安禪。"]'),
('0539fae0-1b26-486b-8781-7ad30b7195e6','蓮花庵','陳巖','宋','宋诗','song-poetry','','[]','冷屋棲雲是幾年，嗔人履迹破苔錢。',32,'全唐诗/poet.song.240000.json','["冷屋棲雲是幾年，嗔人履迹破苔錢。", "不辭更入山深處，手種西方社裏蓮。"]'),
('1f3f40ab-80f0-4712-8293-02d63a4c3e7c','福安院','陳巖','宋','宋诗','song-poetry','','[]','門前黄葉斷人行，寂歷山房晝亦扃。',32,'全唐诗/poet.song.240000.json','["門前黄葉斷人行，寂歷山房晝亦扃。", "疏竹矮窗僧兀坐，炷香薰筆自抄經。"]'),
('25f59cfe-fef9-4f32-9525-e31faaf5c31e','雙峰居士書堂','陳巖','宋','宋诗','song-poetry','','[]','夜鶴相催蕙帳眠，歸來領略舊山川。',32,'全唐诗/poet.song.240000.json','["夜鶴相催蕙帳眠，歸來領略舊山川。", "油雲捲入雙峰頂，收得聲名四十年。"]'),
('914ba9b9-16c1-41f9-8a02-eddac60ec4f6','寶陀巖','陳巖','宋','宋诗','song-poetry','','[]','陰磴層崖洞室寬，奇花異草幾多般。',32,'全唐诗/poet.song.240000.json','["陰磴層崖洞室寬，奇花異草幾多般。", "綵雲不動金光起，便作金蓮法界看。"]'),
('9e5f24b8-b879-48f2-ad36-527f6c0ed99f','招賢峰','陳巖','宋','宋诗','song-poetry','','[]','翹翹車乘力招賢，建業山河五十年。',32,'全唐诗/poet.song.240000.json','["翹翹車乘力招賢，建業山河五十年。", "欲問興亡無問處，一聲山鳥忽來前。"]'),
('a47090ea-7b42-439f-b9e2-9af09c001804','高僧石','陳巖','宋','宋诗','song-poetry','','[]','柏根翻動一爐香，白足高僧禮梵王。',32,'全唐诗/poet.song.240000.json','["柏根翻動一爐香，白足高僧禮梵王。", "還了十方行脚債，却來山頂放圓光。"]'),
('a9aba33f-8daa-4cdb-b1a1-c6995a3508b5','西洪嶺','陳巖','宋','宋诗','song-poetry','','[]','衆壑中分嶺勢回，數家茅店傍山開。',32,'全唐诗/poet.song.240000.json','["衆壑中分嶺勢回，數家茅店傍山開。", "長風吹入松梢去，一片笙簧動地來。"]'),
('db3d4a29-aee8-4f97-9b36-9c897c79cbf3','龍安院','陳巖','宋','宋诗','song-poetry','','[]','蔓草叢生伴棘薪，古藤直上繞松身。',32,'全唐诗/poet.song.240000.json','["蔓草叢生伴棘薪，古藤直上繞松身。", "寺前寺後清幽處，山鳥飛來不避人。"]'),
('fb921263-8e63-477a-99c0-9f5ceecf558d','雙泉','陳巖','宋','宋诗','song-poetry','','[]','檻泉湧出不多深，兌澤相資互有心。',32,'全唐诗/poet.song.240000.json','["檻泉湧出不多深，兌澤相資互有心。", "水淨苦嫌塵土污，底須吾欲濯吾襟。"]'),
('9fa8b009-40ae-4f2a-9e81-ff6477891354','派派泉','陳巖','宋','宋诗','song-poetry','','[]','水源同出萬山頭，上半支分各自流。',32,'全唐诗/poet.song.240000.json','["水源同出萬山頭，上半支分各自流。", "曲折繞從山下去，短莎隨地弄輕柔。"]'),
('0de70bbc-9e7c-48d0-ba19-8426327fa919','永安塔','陳巖','宋','宋诗','song-poetry','','[]','心不能安總是魔，亭亭孤塔鎮巖阿。',32,'全唐诗/poet.song.240000.json','["心不能安總是魔，亭亭孤塔鎮巖阿。", "倘無佛力三千行，奈此丘蛇井鼠何。"]'),
('2dc796f1-ff8b-4cab-8183-7cc1f872a6bf','崇聖院','陳巖','宋','宋诗','song-poetry','','[]','山形四抱水來前，中有金蓮色界天。',32,'全唐诗/poet.song.240000.json','["山形四抱水來前，中有金蓮色界天。", "清磬一聲僧定起，松間靈鶴舞蹁躚。"]'),
('e3c2df8e-2d9c-4ce5-8b57-e0c9047a0a7f','逍遥臺','陳巖','宋','宋诗','song-poetry','','[]','拂面溪風灑灑清，輕衫短帽御風行。',32,'全唐诗/poet.song.240000.json','["拂面溪風灑灑清，輕衫短帽御風行。", "逍遥自是天游樂，不結沙鷗水石盟。"]'),
('3d7fe98f-7194-4cfb-9b2b-d2bdf7bb2e6a','翠瀑亭','陳巖','宋','宋诗','song-poetry','','[]','濕翠拋來覺染衣，倚闌兀兀坐移時。',32,'全唐诗/poet.song.240000.json','["濕翠拋來覺染衣，倚闌兀兀坐移時。", "偶因過雨添流水，增重棼絲曳練詩。"]'),
('297c5e3a-9161-4448-840f-0e13c93ccac9','戛玉亭','陳巖','宋','宋诗','song-poetry','','[]','丘中流水度鳴琴，靜與僧房發妙音。',32,'全唐诗/poet.song.240000.json','["丘中流水度鳴琴，靜與僧房發妙音。", "高下抑揚渾不斷，時時寫出昔賢心。"]'),
('6712fdc6-dbb5-4231-b648-900bc962fa50','稻積峰','陳巖','宋','宋诗','song-poetry','','[]','探得松苓足養身，仙家留稻滿倉囷。',32,'全唐诗/poet.song.240000.json','["探得松苓足養身，仙家留稻滿倉囷。", "豈知山下人辛苦，五月青苗已糶新。"]'),
('08119167-a2ed-4b55-b6e8-52c85fa1506b','碧雲峰','陳巖','宋','宋诗','song-poetry','','[]','瘦藤引我上崚嶒，蒼壁如梯石作層。',32,'全唐诗/poet.song.240000.json','["瘦藤引我上崚嶒，蒼壁如梯石作層。", "袖得碧雲無用處，却將分贈住山僧。"]'),
('d49e9831-2903-47dd-bb9c-9b211026894c','煎茶峰','陳巖','宋','宋诗','song-poetry','','[]','春山細摘紫英芽，碧玉甌中散乳花。',32,'全唐诗/poet.song.240000.json','["春山細摘紫英芽，碧玉甌中散乳花。", "六尺禪牀支瘦骨，心安不惱睡中蛇。"]'),
('1087044f-4077-426c-af73-3fe2fa523680','鬬雞石','陳巖','宋','宋诗','song-poetry','','[]','未悟雄冠死結纓，昂然對峙只徒爭。',32,'全唐诗/poet.song.240000.json','["未悟雄冠死結纓，昂然對峙只徒爭。", "山頭化作千年石，盛氣飛憍不再萌。"]'),
('84d859a6-ea58-4b2a-9078-d6eabf5b762b','翠羽池','陳巖','宋','宋诗','song-poetry','','[]','錦雞花鴨爛成文，連雁雙鳬雪羽紛。',32,'全唐诗/poet.song.240000.json','["錦雞花鴨爛成文，連雁雙鳬雪羽紛。", "同免王孫金彈子，飛來飛去一群群。"]'),
('2a2ee969-1f81-4083-b6a2-e94aa8591f2c','李化文書堂','陳巖','宋','宋诗','song-poetry','','[]','世路嶔崎兩鬢絲，山中留客且伸眉。',32,'全唐诗/poet.song.240000.json','["世路嶔崎兩鬢絲，山中留客且伸眉。", "竹林勝踐雖相似，猶恨前賢所欠詩。"]'),
('e84741e7-c34b-471e-89b4-9bc163e6ee67','劉相公寨基','陳巖','宋','宋诗','song-poetry','','[]','苦霧腥雲染寇鋒，萬家鄉井雉罹罿。',32,'全唐诗/poet.song.240000.json','["苦霧腥雲染寇鋒，萬家鄉井雉罹罿。", "山前堆滿縱橫骨，換得將軍不戰功。"]'),
('94e22980-aeee-44b2-850c-93ec9d8ae7fd','九子庵','陳巖','宋','宋诗','song-poetry','','[]','修途百折到山頂，紺宇數間開道場。',32,'全唐诗/poet.song.240000.json','["修途百折到山頂，紺宇數間開道場。", "倦卧儘人身自在，翻愁作夢趁黄粱。"]'),
('09d902cf-0869-4190-aae0-c3aac28ab275','九子峰','陳巖','宋','宋诗','song-poetry','','[]','小大扶携作伴行，歡然戀戀意相傾。',32,'全唐诗/poet.song.240000.json','["小大扶携作伴行，歡然戀戀意相傾。", "信知萬古山頭石，還有人間母子情。"]'),
('23b81d28-b123-4e83-809e-544210be220f','垂雲澗','陳巖','宋','宋诗','song-poetry','','[]','飛瀑奔崖色皎然，飄空上下勢相連。',32,'全唐诗/poet.song.240000.json','["飛瀑奔崖色皎然，飄空上下勢相連。", "看來不是天河水，盡是兜羅片片綿。"]'),
('d7f263ac-9a4f-4711-af21-871bcf8eb247','石照','陳巖','宋','宋诗','song-poetry','','[]','刮垢磨光碧色深，日華穿漏解雲陰。',32,'全唐诗/poet.song.240000.json','["刮垢磨光碧色深，日華穿漏解雲陰。", "十分疑是仙人鏡，照見茫茫萬古心。"]'),
('25b97436-8a11-409c-8dc3-e32222297f96','天井','陳巖','宋','宋诗','song-poetry','','[]','分派天河入地深，斷無射鮒汩泥塵。',32,'全唐诗/poet.song.240000.json','["分派天河入地深，斷無射鮒汩泥塵。", "仙鄉初不諳機事，多少山間抱甕人。"]'),
('51c5a941-04ae-4f4b-b948-8ff48fe5cbef','七布水','陳巖','宋','宋诗','song-poetry','','[]','只緣雨過水傾崖，霍地冰簾數幅開。',32,'全唐诗/poet.song.240000.json','["只緣雨過水傾崖，霍地冰簾數幅開。", "始信人間真實相，盡從無始劫中來。"]'),
('ce62e877-6050-4f67-962b-ed01efe8e3a5','福海院','陳巖','宋','宋诗','song-poetry','','[]','風送香來草木靈，壽松何事不重青。',32,'全唐诗/poet.song.240000.json','["風送香來草木靈，壽松何事不重青。", "日當亭午禪扉靜，藥杵聲中鶴夢醒。"]'),
('4fe538f8-ffd3-435b-9a08-4e8014df0877','卧牛石','陳巖','宋','宋诗','song-poetry','','[]','石犀沉後波濤息，石燕飛時風雨來。',32,'全唐诗/poet.song.240000.json','["石犀沉後波濤息，石燕飛時風雨來。", "堪笑石牛徒解卧，山田無數任蒿萊。"]'),
('7f9f1719-0e30-4402-927f-1c73228ed451','碧霄亭','陳巖','宋','宋诗','song-poetry','','[]','秋風吹上碧霄亭，足躡靈河袖拂星。',32,'全唐诗/poet.song.240000.json','["秋風吹上碧霄亭，足躡靈河袖拂星。", "雲影四垂天接地，恍疑有路到仙扃。"]'),
