('fe05337e-6f2e-49d9-89a0-814ad921cff5','列仙峰','陳巖','宋','宋诗','song-poetry','','[]','笑闖黄冠高切雲，前携後掖互相親。',32,'全唐诗/poet.song.240000.json','["笑闖黄冠高切雲，前携後掖互相親。", "我來歷歷披雲看，試問肩隨是幾人。"]'),
('1d69f504-eaf8-44bd-9f7e-66761e1329ff','玉甑峰','陳巖','宋','宋诗','song-poetry','','[]','茹芝仙客老仙鄉，浄盡人間粒食腸。',32,'全唐诗/poet.song.240000.json','["茹芝仙客老仙鄉，浄盡人間粒食腸。", "玉甑豈能無用處，幾番與世熟黄粱。"]'),
('b8d3dbea-2c97-4309-ab34-e7b282c0c40c','淨巾石','陳巖','宋','宋诗','song-poetry','','[]','炯炯豁開明鏡臺，是中無處著塵埃。',32,'全唐诗/poet.song.240000.json','["炯炯豁開明鏡臺，是中無處著塵埃。", "平生心地常如此，何暇頻頻拂拭來。"]'),
('381e37ea-9b81-4ae8-b864-def0ff637ce3','最勝亭','陳巖','宋','宋诗','song-poetry','','[]','烟收霧斂翠成圍，來助幽亭眼界奇。',32,'全唐诗/poet.song.240000.json','["烟收霧斂翠成圍，來助幽亭眼界奇。", "衲子苦于山索句，稜稜瘦骨不禁詩。"]'),
('fa6511b0-26db-44ca-ab46-b2c08007e6f0','滴翠峰','陳巖','宋','宋诗','song-poetry','','[]','春氣薰空草木浮，綠雲冉冉起山頭。',32,'全唐诗/poet.song.240000.json','["春氣薰空草木浮，綠雲冉冉起山頭。", "嵐光浥翠濃於染，潤入衣襟冷欲秋。"]'),
('e7a94f0b-f265-4a06-b823-451dbbe3441a','天柱庵','陳巖','宋','宋诗','song-poetry','','[]','石壁參天駐冷雲，一聲幽鳥忽驚人。',32,'全唐诗/poet.song.240000.json','["石壁參天駐冷雲，一聲幽鳥忽驚人。", "庵前庵後山如舊，朽柏年來不再春。"]'),
('bd4fcb6e-1cfb-4c39-9cf8-e9f3321d0de2','翠峰庵','陳巖','宋','宋诗','song-poetry','','[]','縛屋山中數十年，薙茅誅棘旋開田。',32,'全唐诗/poet.song.240000.json','["縛屋山中數十年，薙茅誅棘旋開田。", "何須折柳溪邊去，枯木寒林總是禪。"]'),
('3cdffc56-ecff-4e76-a16d-a5039b8d6a71','透碧巖','陳巖','宋','宋诗','song-poetry','','[]','空洞玲瓏萬石攢，中間逗入翠光寒。',32,'全唐诗/poet.song.240000.json','["空洞玲瓏萬石攢，中間逗入翠光寒。", "人來坐對山無語，表裏虛明不礙觀。"]'),
('2089bd26-0903-438e-85b2-ccb67364b1e4','石牌峰','陳巖','宋','宋诗','song-poetry','','[]','山斷空青近玉京，一牌就石琢磨成。',32,'全唐诗/poet.song.240000.json','["山斷空青近玉京，一牌就石琢磨成。", "烟揩霧拭明如鏡，留與游人記姓名。"]'),
('9e502021-4532-4904-b962-690904ea1397','展旗峰','陳巖','宋','宋诗','song-poetry','','[]','山形南去疾如馳，高處展開三丈旗。',32,'全唐诗/poet.song.240000.json','["山形南去疾如馳，高處展開三丈旗。", "山下行人爭指似，龍蛇影動夕陽時。"]'),
('d734f09d-10b9-419a-a969-45f63ffe4e53','梅花峰','陳巖','宋','宋诗','song-poetry','','[]','僵立枯梢带雪霜，至今陰極動潜陽。',32,'全唐诗/poet.song.240000.json','["僵立枯梢带雪霜，至今陰極動潜陽。", "不嫌孤寂無人到，一點春風萬壑香。"]'),
('8526a4a0-6a7d-45ae-a00a-56fa903f11fb','鉢盂峰','陳巖','宋','宋诗','song-poetry','','[]','農家辛苦靳逢年，誰似僧家飽飯眠。',32,'全唐诗/poet.song.240000.json','["農家辛苦靳逢年，誰似僧家飽飯眠。", "留得巾盂爲老伴，豐年常在粥盂邊。"]'),
('e8ec0aad-947d-4fdc-90e9-cbc5bf8d45de','邃谷巖','陳巖','宋','宋诗','song-poetry','','[]','千古嘗留一窖冰，女蘿簳竹鎖寒陰。',32,'全唐诗/poet.song.240000.json','["千古嘗留一窖冰，女蘿簳竹鎖寒陰。", "仙人肯爲遊人出，試問中間若許深。"]'),
