('48b23e0d-753c-4c45-a0a9-da83dff79ac5','香林峰','陳巖','宋','宋诗','song-poetry','','[]','幾許山花照夕陽，不栽不植自芬芳。',32,'全唐诗/poet.song.240000.json','["幾許山花照夕陽，不栽不植自芬芳。", "林梢一點風微起，吹作人間百合香。"]'),
('c2621627-b0e7-463d-a4be-ff0c1e0f7223','煎茶峰','陳巖','宋','宋诗','song-poetry','','[]','緩火烘來活水煎，山頭卓錫取清泉。',32,'全唐诗/poet.song.240000.json','["緩火烘來活水煎，山頭卓錫取清泉。", "品茶嬾檢茶經看，舌本無非有味禪。"]'),
('3dcf6e33-941d-441c-a4a5-8e1db13dd36b','金光洞','陳巖','宋','宋诗','song-poetry','','[]','神剜鬼劃劇幽深，門外藤蘿淺結陰。',32,'全唐诗/poet.song.240000.json','["神剜鬼劃劇幽深，門外藤蘿淺結陰。", "洞裏金仙十年坐，湛然認得本來心。"]'),
('96eeaaf0-a855-4395-a748-545f8e7d19fc','黄石溪','陳巖','宋','宋诗','song-poetry','','[]','平田千畝萬山中，水脈高低處處通。',32,'全唐诗/poet.song.240000.json','["平田千畝萬山中，水脈高低處處通。", "黄石一溪三十里，暖風吹動稻花叢。"]'),
('94c7352b-35a8-4162-a5d1-54180e56b48f','南陽澗','陳巖','宋','宋诗','song-poetry','','[]','人家四散占荒丘，曉夜悲鳴澗水流。',32,'全唐诗/poet.song.240000.json','["人家四散占荒丘，曉夜悲鳴澗水流。", "點點寒鴉來不盡，昏雲頹日古猷州。"]'),
('20acebf0-10f0-49b6-ab3d-3491c1a53328','卧龍庵','陳巖','宋','宋诗','song-poetry','','[]','孔明西去終扶漢，散騎南來莫拯唐。',32,'全唐诗/poet.song.240000.json','["孔明西去終扶漢，散騎南來莫拯唐。", "同是卧龍殊用舍，古今易地兩南陽。"]'),
('d01e6bea-2983-4096-8a42-bac9cd1d6956','古仙峰','陳巖','宋','宋诗','song-poetry','','[]','日薄烟低莽蒼間，古仙相望白雲端。',32,'全唐诗/poet.song.240000.json','["日薄烟低莽蒼間，古仙相望白雲端。", "山中倘有安期棗，覓取歸來當晚餐。"]'),
('ede117c5-7f5d-4573-8e99-130c3fa27c26','古仙洞','陳巖','宋','宋诗','song-poetry','','[]','風裊藤蘿水舞苔，洞門常閉不常開。',32,'全唐诗/poet.song.240000.json','["風裊藤蘿水舞苔，洞門常閉不常開。", "草根滿地皆靈藥，彭祖偓佺曾到來。"]'),
('c47613ba-ed5b-43dd-907a-197cdb0860c3','五臺明智院','陳巖','宋','宋诗','song-poetry','','[]','前岡後隴盡紆餘，嵐影烟光半有無。',32,'全唐诗/poet.song.240000.json','["前岡後隴盡紆餘，嵐影烟光半有無。", "山脚斷邊開古剎，五臺分布似連珠。"]'),
('3c77feb9-7b20-4cc3-970e-ccb7a286c4ea','曹山延壽院','陳巖','宋','宋诗','song-poetry','','[]','三角坳泓一角虧，其間濁水照摩尼。',32,'全唐诗/poet.song.240000.json','["三角坳泓一角虧，其間濁水照摩尼。", "風幡不動爐烟直，正是僧禪定起時。"]'),
('1e0a0114-ff5a-4e7d-b638-1ad58da5c7cc','秀華亭','陳巖','宋','宋诗','song-poetry','','[]','瘦田糝糝豆花明，冷徑毿毿柏葉清。',32,'全唐诗/poet.song.240000.json','["瘦田糝糝豆花明，冷徑毿毿柏葉清。", "何處路通雲際寺，山人指我秀華亭。"]'),
