('0b10d242-a9e6-4ed1-983c-7163d98ea650','龜山崇壽院','陳巖','宋','宋诗','song-poetry','','[]','白雲起處著招提，一嶺嵯峨衆嶺低。',32,'全唐诗/poet.song.240000.json','["白雲起處著招提，一嶺嵯峨衆嶺低。", "多少山間好風景，人來先看蔣公題。"]'),
('3e61dd17-df5a-4501-89bb-f802ab5f5200','白龜泉','陳巖','宋','宋诗','song-poetry','','[]','白龜擺脫泥塗辱，步入金蓮佛道場。',32,'全唐诗/poet.song.241000.json','["白龜擺脫泥塗辱，步入金蓮佛道場。", "玉水迸流山石裂，有靈初不爲刳腸。"]'),
('f3cebfc1-42b8-4eb5-914c-2066c08e096b','靜觀亭','陳巖','宋','宋诗','song-poetry','','[]','打圍行蟻時時戰，觸紙癡蠅日日鑽。',32,'全唐诗/poet.song.241000.json','["打圍行蟻時時戰，觸紙癡蠅日日鑽。", "有客雲山深處卧，靜中回向此心觀。"]'),
('6d1ad305-8bea-4163-bded-5ca9ec3c666d','聖泉院','陳巖','宋','宋诗','song-poetry','','[]','釋子親傳馬祖衣，枯藤來此卓烟霏。',32,'全唐诗/poet.song.241000.json','["釋子親傳馬祖衣，枯藤來此卓烟霏。", "斕斑錦石寒泉底，湛碧中涵五色輝。"]'),
('3a92a429-c23c-4a1a-b4cc-329c6ab76684','覽勝亭','陳巖','宋','宋诗','song-poetry','','[]','亭中妙墨粲于珍，添得一番山色新。',32,'全唐诗/poet.song.241000.json','["亭中妙墨粲于珍，添得一番山色新。", "幽坐看來如看畫，我今欲畫恨無人。"]'),
('3dee3f54-885e-4fe5-b03b-e25019aa14ef','縞溪','陳巖','宋','宋诗','song-poetry','','[]','風信吹凉入鬢清，悠然目送一鷗輕。',32,'全唐诗/poet.song.241000.json','["風信吹凉入鬢清，悠然目送一鷗輕。", "鷗飛不盡天回影，練色波光曳曳明。"]'),
('43b29058-0c5b-4f6e-8ebb-d71365b8967a','觀音巖','陳巖','宋','宋诗','song-poetry','','[]','一性圓時萬境通，三生綺念墮真空。',32,'全唐诗/poet.song.241000.json','["一性圓時萬境通，三生綺念墮真空。", "如今舉眼無非佛，身在光明法界中。"]'),
('80667d29-1051-4b40-994b-897d21f64277','拾寶巖','陳巖','宋','宋诗','song-poetry','','[]','梵王住在光明殿，萬寶真同瓦礫看。',32,'全唐诗/poet.song.241000.json','["梵王住在光明殿，萬寶真同瓦礫看。", "玉塊金沙隨地有，好來擷取入中單。"]'),
('6d32fd12-9542-4812-a164-f6827272f434','望仙祠','陳巖','宋','宋诗','song-poetry','','[]','嵐翠相迎一笑中，窅然想見舊仙蹤。',32,'全唐诗/poet.song.241000.json','["嵐翠相迎一笑中，窅然想見舊仙蹤。", "紛紛雲氣蓬萊近，目斷前山幾十重。"]'),
('fc51ead5-012c-471b-96e4-1c07e96428de','訪山亭','陳巖','宋','宋诗','song-poetry','','[]','又拚十日作山行，去路一程高一程。',32,'全唐诗/poet.song.241000.json','["又拚十日作山行，去路一程高一程。", "三十年遊遊未了，青山應笑白髭生。"]'),
('2bdf03b8-f0e2-4424-b0d2-da1c275fc87f','蜃蟠嶺','陳巖','宋','宋诗','song-poetry','','[]','迤邐岡巒迅下馳，縈回蟠結幾蛟螭。',32,'全唐诗/poet.song.241000.json','["迤邐岡巒迅下馳，縈回蟠結幾蛟螭。", "終然鼓勇歸滄海，只待風雷借便時。"]'),
('ae0bf9e4-aab5-425b-8d14-e72b6efd781f','龍潭利衆院','陳巖','宋','宋诗','song-poetry','','[]','日涵林壑紫光凝，草動花翻氣似蒸。',32,'全唐诗/poet.song.241000.json','["日涵林壑紫光凝，草動花翻氣似蒸。", "勝地剗開鼪鼬逕，數間松屋住殘僧。"]'),
('9a76a0fb-b3ef-41a5-a433-197859d5d034','曹溪','陳巖','宋','宋诗','song-poetry','','[]','近水人家自是奇，水成灣處各開扉。',32,'全唐诗/poet.song.241000.json','["近水人家自是奇，水成灣處各開扉。", "波光一片青銅鏡，無數文禽照影飛。"]'),
('d96ceecb-6609-46a6-919c-59f891cc03d3','黄粒稻','陳巖','宋','宋诗','song-poetry','','[]','紫芒金粒動秋風，三月腰鎌捲地空。',32,'全唐诗/poet.song.241000.json','["紫芒金粒動秋風，三月腰鎌捲地空。", "農事倦時天與力，機舂相繼便論功。"]'),
('4e6ac501-d415-4043-adeb-c03195daf964','金地茶','陳巖','宋','宋诗','song-poetry','','[]','瘦莖尖葉带餘馨，細嚼能令困自醒。',32,'全唐诗/poet.song.241000.json','["瘦莖尖葉带餘馨，細嚼能令困自醒。", "一段山間奇絕事，會須添入品茶經。"]'),
('7305c6c6-a551-4eaa-bd28-347d74caa934','五釵松','陳巖','宋','宋诗','song-poetry','','[]','五股釵松黛色鮮，山家插鬢不成妍。',32,'全唐诗/poet.song.241000.json','["五股釵松黛色鮮，山家插鬢不成妍。", "道人見了都無用，付與雲鬟霧鬢仙。"]'),
('b4b6244a-bb18-47e6-bb71-f8a9d4b076c8','歸去樂','邵定翁','宋','宋诗','song-poetry','','[]','歸去樂，歸去樂。',72,'全唐诗/poet.song.241000.json','["歸去樂，歸去樂。", "山上山花紅灼灼，山下山酒香漠漠。", "折花自插還自酌，說渠萬貫揚州鶴。", "樂莫樂兮此一歸，禽知我知淵明知。", "三者之外知者誰，勸君緘吻藏高枝。"]'),
('bc4b25b5-86fc-451d-9afe-cb582313c6ce','麥飯熟','邵定翁','宋','宋诗','song-poetry','','[]','麥飯熟，兒莫哭，阿爺搗麥麥煮粥。',88,'全唐诗/poet.song.241000.json','["麥飯熟，兒莫哭，阿爺搗麥麥煮粥。", "煨一蝦，配麥粥，飽兒腹。", "去年春梢餔麥田，馱兒走竄青山顛。", "歸來破竈無晨烟，兒孩不知今歲强。", "牀頭貳釜又一囊，儉惜可補兩月糧。", "老夫展拜妻燒香，謝蒼蒼。"]'),
('22231f0f-b22d-40d6-92b2-fa883f58d871','插田','邵定翁','宋','宋诗','song-poetry','','[]','明朝蚤蚤起插田，東方未明雲漫漫。',80,'全唐诗/poet.song.241000.json','["明朝蚤蚤起插田，東方未明雲漫漫。", "阿婆拊床呼阿三，阿三莫學阿五眠。", "汝起□火燒破鐺，麥飯雜菽炮鮝羹，邱嫂拔秧哥去耕。", "田家何待春禽勸，一朝蚤起一年飯。", "飯籮空，愁殺儂。"]'),
('da5adb96-4b78-4c4c-823b-8ec65dc28865','行不上也哥哥','邵定翁','宋','宋诗','song-poetry','','[]','青泥坡，一坡高一坡，毒蟒寄穴虎作窠。',99,'全唐诗/poet.song.241000.json','["青泥坡，一坡高一坡，毒蟒寄穴虎作窠。", "風酸日黯雲嵯峨，抵死欲上將如何。", "上頭莫有牡丹紫玉九袴带，黄金千萬羅。", "高堂阿婆雪皤皤，妻炊扊扅顰翠蛾。", "兒懶失學歲月蹉，縱得金玉喪已多。", "山禽笑汝汝莫呵，行不上也哥哥。"]'),
('c6ad2a3e-6c45-4edb-a74a-16805ef0ef4b','繅車','邵定翁','宋','宋诗','song-poetry','','[]','繅作繅作急急作，東家煮繭玉滿鑊，西家捲絲雪滿籰。',84,'全唐诗/poet.song.241000.json','["繅作繅作急急作，東家煮繭玉滿鑊，西家捲絲雪滿籰。", "汝家蠶遲猶未箔，小滿已過棗花落。", "夏葉食多銀甕薄，待得女繅渠已著。", "懶婦兒，聽禽言，一步落人後，百步輸人先。", "秋風寒，衣衫單。"]'),
('5057a67d-c599-462b-8f30-c1212053a923','提胡盧','邵定翁','宋','宋诗','song-poetry','','[]','提胡盧，既不掛于寂靜之邱墟，又不浮之汗漫之江湖。',140,'全唐诗/poet.song.241000.json','["提胡盧，既不掛于寂靜之邱墟，又不浮之汗漫之江湖。", "又不持之騎龍雨八區，胡爲喚人挈之登酒壚。", "桀紂以烟莽其都，李杜以風沙厥軀。", "前人醉倒後人扶，萬世一醉何年甦。", "矧今斗米抵斗珠，方坊刊章禁私壺。", "杖頭有金何處沽，何況杖頭金又無。", "我瓦盆，三年枯，借姑胡盧復我姑，請姑提取湘江水，去飲三閭楚大夫。"]'),
('13cf8e44-5c62-4423-a693-66ff72bc8269','婆餠焦','邵定翁','宋','宋诗','song-poetry','','[]','婆餠焦，罪在妾，妾不能家家道缺。',116,'全唐诗/poet.song.241000.json','["婆餠焦，罪在妾，妾不能家家道缺。", "冬裘不完夏糧絕，愁得鬢成雪。", "朝看婆鬢兮眼滴血，暮思婆鬢兮心刮鐵。", "草枯東風吹不活，妾哀事姑無歲月。", "行人誤聽賤妾言，謂鬢殊不然，婆鬢不復玄。", "偶焦一餠尚可煎，別煎好餠供婆餐。", "餠焦自擇飣下盤，留取來年補漏天。"]'),
('ea385067-df94-4833-b49a-3bda5b00c936','脫却布袴','邵定翁','宋','宋诗','song-poetry','','[]','前年糶麥得疋布，糠妻一衫儂兩袴。',104,'全唐诗/poet.song.241000.json','["前年糶麥得疋布，糠妻一衫儂兩袴。", "去年縣公索澆賦，剝袴貰錢寄官庫。", "一袴著穿兩膝露，餮虱爺孫浩無數。", "昨朝作勞汗如珠，脫掛田頭老桑樹。", "倉茫失收紅日暮，偷郎不惜持將去。", "脫袴兒，謝汝說，老夫頗亦知時節，無奈吾袴無可脫。"]'),
('3caef9eb-7a96-46f6-9285-b5855fddc057','姑惡','邵定翁','宋','宋诗','song-poetry','','[]','姑惡，姑惡。',122,'全唐诗/poet.song.241000.json','["姑惡，姑惡。", "姑不惡，新婦惡。", "不聞姑聲駡婦錯，但聞婦聲數姑虐。", "汝夫汝夫汝所嚴，汝姑又如天之天。", "高高在上胡可言，縱有可言當自冤。", "以天感天天自還，姜婦愈敬姑復憐。", "胡憤而死魚龍淵，至今誶語春風前。", "姑惡鳥，家私休與外人道。", "道與外人人轉疑，去婦何嘗說姑好。"]'),
('651f0e5c-11ed-4dcd-b2e1-dc2e73750dc6','呂望非熊','邵定翁','宋','宋诗','song-poetry','','[]','呂望非熊，□□□伯與太公。',231,'全唐诗/poet.song.241000.json','["呂望非熊，□□□伯與太公。", "千千歲，無此逢。", "使伯蚤而出獵兮，公方沽酒之匆匆。", "使伯遲而出獵兮，公已埋骨乎東海之東。", "潦倒龍鍾，齒豁頭童。", "誰知而韜略胸，誰知而干戈功。", "邂逅一笑蘆花中，未語肝膈先玲瓏。", "望殺我家白頭翁，我車轆轆公我同，盍歸乎來造我豐。", "公亦當哀人命窮，霜髯一掀許之從。", "畢郢宰木悲我風，嗟嗟往事隨飛鴻。", "宇宙飄忽未有終，波濤洶湧愁拍空。", "鷗邊多少閒英雄，黄馘著書釣夕紅。", "夜半夢起搥蛟龍，豈不欲往烟霧重，西山日斷無來蹤。", "伯之來兮民之福，伯不來兮公何哭。", "鱸魚肥，蓴菜熟。"]'),
('a9db0551-cfde-4aaf-a498-1b6a1bf88f89','錦鏡池','汪灝','宋','宋诗','song-poetry','','[]','誰遣青銅一片懸，萬山如洗息淪漣。',64,'全唐诗/poet.song.241000.json','["誰遣青銅一片懸，萬山如洗息淪漣。", "過雲不礙東西岫，明月能涵上下天。", "影合野棠魚自避，光分水荇鷺相鮮。", "臨流我亦忘歸興，晴翠撲人生紫烟。"]'),
('75bcfa7f-96e7-46a8-bbb6-763a426fe9fb','示故人','杜濬之','宋','宋诗','song-poetry','','[]','在家同匏繫，遊子似籜飛。',84,'全唐诗/poet.song.241000.json','["在家同匏繫，遊子似籜飛。", "昔分參與商，今作塤與箎。", "感子意氣殊，顧我齒髮非。", "茅屋正蕭蕭，野花亦離離。", "無酒水可飲，無飯黍可炊。", "杲杲看朝陽，連連弄夕暉。", "男兒重交好，雪霜以爲期。"]'),
('901f4de7-4f82-4ee6-afcd-694c0acfeb7b','述志','杜濬之','宋','宋诗','song-poetry','','[]','寧往百里步，曲木不可息。',84,'全唐诗/poet.song.241000.json','["寧往百里步，曲木不可息。", "寧忍三日饑，邪蒿不可食。", "雖云食息頃，便分淑與慝。", "志士當暮年，聞道轉歷歷。", "要使此一身，如琢復如滌。", "整冠與納履，微嫌費疏剔。", "未若瓜李地，絕不見吾迹。"]'),
('a7c24221-d5a9-472d-9ffb-e72e89b2d028','書警','杜濬之','宋','宋诗','song-poetry','','[]','食李弗嫌苦，食梅弗嫌酸。',96,'全唐诗/poet.song.241000.json','["食李弗嫌苦，食梅弗嫌酸。", "不爲身所累，且從心所安。", "吾分固云薄，吾志亦非單。", "靜看如山禍，差之一念閒。", "所得甚眇眇，所喪已漫漫。", "百年修不足，一朝容易殘。", "雖處四壁立，如享萬鍾寬。", "靜坐明月窟，濯足清風灘。"]'),
('1eff4b83-e2c8-406b-9b89-2cf506a84e7c','春日携客游武夷','詹本','宋','宋诗','song-poetry','','[]','山脚健枝梧，百里插蒼峭。',72,'全唐诗/poet.song.241000.json','["山脚健枝梧，百里插蒼峭。", "粼粼石可把，曙色坐遠釣。", "風水真笙竽，歷落太古調。", "衣冠带莽蒼，山鬼驚二妙。", "雲月正忘年，花鳥更索笑。", "迴船翠凌亂，吾道付長嘯。"]'),
('5eb0b69d-3776-4b10-98d6-cf0a9532d230','閒中','詹本','宋','宋诗','song-poetry','','[]','萬事問不知，山中一樽酒。',24,'全唐诗/poet.song.241000.json','["萬事問不知，山中一樽酒。", "掃石坐松風，綠陰滿巾袖。"]'),
('408d1726-825c-4418-a110-c21288986390','宿天台','詹本','宋','宋诗','song-poetry','','[]','風泉隔西屋，獨夜寒自生。',48,'全唐诗/poet.song.241000.json','["風泉隔西屋，獨夜寒自生。", "開窗失山色，白雲壓前楹。", "累盡得瀟灑，去住俱不驚。", "鼻息答僧鐘，霜露入殘更。"]'),
('184378f0-efac-40a5-b0a7-ef523d8090b5','池魚','祝慶夫','宋','宋诗','song-poetry','','[]','方池如鑑碧溶溶，錦鯉遊揚逐浪中。',32,'全唐诗/poet.song.241000.json','["方池如鑑碧溶溶，錦鯉遊揚逐浪中。", "竚看三春烟水暖，好觀一躍化神龍。"]'),
('b8a774f0-2a58-4c91-953b-5401de259a7d','庭竹','祝慶夫','宋','宋诗','song-poetry','','[]','庭前修竹長琅玕，任是隆冬不畏寒。',32,'全唐诗/poet.song.241000.json','["庭前修竹長琅玕，任是隆冬不畏寒。", "戛玉篩金承雨露，亭亭青翠拂雲端。"]'),
('173f7e5d-e7ce-4220-a0ec-b7be8f3834ac','句','祝慶夫','宋','宋诗','song-poetry','','[]','冰雪凝難解，風雲慶有時。',12,'全唐诗/poet.song.241000.json','["冰雪凝難解，風雲慶有時。"]'),
('87cb5a0e-a915-461b-a912-ac822903c4ee','題浯溪  其一','李祐孫','宋','宋诗','song-poetry','','[]','明皇何以致顛危，林甫國忠成禍基。',32,'全唐诗/poet.song.241000.json','["明皇何以致顛危，林甫國忠成禍基。", "妃子良心猶不悟，此機惟有九齡知。"]'),
('1011ace7-8d41-4332-8819-0350a190aa86','題浯溪  其二','李祐孫','宋','宋诗','song-poetry','','[]','浯溪崖石與天齊，兩刻中興大業碑。',32,'全唐诗/poet.song.241000.json','["浯溪崖石與天齊，兩刻中興大業碑。", "北向幾多垂白叟，百年不見漢官儀。"]'),
('5c3c36af-17f3-4cdd-8eba-f97f0c274ed1','句  其一','曹良史','宋','宋诗','song-poetry','','[]','雲生畫佛壁，葉落病僧房。',12,'全唐诗/poet.song.241000.json','["雲生畫佛壁，葉落病僧房。"]'),
('fb8740fc-dd34-48e4-b494-775865d6f536','句  其二','曹良史','宋','宋诗','song-poetry','','[]','閑來閉門處，認得讀書聲。',12,'全唐诗/poet.song.241000.json','["閑來閉門處，認得讀書聲。"]'),
('575c7004-b12a-48f6-8e5a-09b974d4d023','句  其三','曹良史','宋','宋诗','song-poetry','','[]','深樹月昏神火出，斷烟雪霽獵人回。',16,'全唐诗/poet.song.241000.json','["深樹月昏神火出，斷烟雪霽獵人回。"]'),
('af6a9cdb-a3b9-4126-9c0b-7cf34f90a921','句  其四','曹良史','宋','宋诗','song-poetry','','[]','牆圍敗屋知無主，風響荒林似有人。',16,'全唐诗/poet.song.241000.json','["牆圍敗屋知無主，風響荒林似有人。"]'),
('050f7f10-b09d-4002-9465-8a08a2c0291f','句  其五','曹良史','宋','宋诗','song-poetry','','[]','駕犢渡溪水，夕陽滿田畈。',12,'全唐诗/poet.song.241000.json','["駕犢渡溪水，夕陽滿田畈。"]'),
('68f120dc-7bea-4f12-814f-004c9462c727','題沈知丞園','壺弢','宋','宋诗','song-poetry','','[]','曲徑芳塘百畝園，更無煩暑礙風烟。',64,'全唐诗/poet.song.241000.json','["曲徑芳塘百畝園，更無煩暑礙風烟。", "留春庭院花如錦，迎月樓臺柳舞綿。", "鄴架插書金屋底，秦箏度曲綠衣前。", "主人宴罷歸來晚，銀燭高燒月午天。"]'),
('89451b61-d7f6-42e9-a64a-b3cdade94179','刻石','歐陽慶甫','宋','宋诗','song-poetry','','[]','地僻人稀能幾家，清泉漱玉石欹斜。',32,'全唐诗/poet.song.241000.json','["地僻人稀能幾家，清泉漱玉石欹斜。", "客來訪我慚無具，洗甑炊香更點茶。"]'),
('73e9b2ed-7efc-4dfb-8223-275d1c9e1ce8','大安舖','魏梅我','宋','宋诗','song-poetry','','[]','又望前村里，深溪快渡槎。',24,'全唐诗/poet.song.241000.json','["又望前村里，深溪快渡槎。", "牛羊半山塢，鷄犬幾人家。"]'),
('9ee6b6c9-5a11-420d-af9b-e3dd1953485a','界牌舖','彭九成','宋','宋诗','song-poetry','','[]','地僻人家早掩關，行人忙逐暮鴉還。',32,'全唐诗/poet.song.241000.json','["地僻人家早掩關，行人忙逐暮鴉還。", "急風花落隔牆樹，暗雨烏啼何處山。"]'),
('7519eea6-733b-421b-8ea4-ac1e42f8dff4','新陽舖','江梅','宋','宋诗','song-poetry','','[]','梅花籬落菜花畦，春水平田釀燕泥。',32,'全唐诗/poet.song.241000.json','["梅花籬落菜花畦，春水平田釀燕泥。", "健事老翁頭雪白，一簑烟雨自扶犁。"]'),
('ecbe1adc-6a8c-4b8f-9017-4a804ceb88fe','舉富舖','安鏖','宋','宋诗','song-poetry','','[]','漠漠烟橫草樹青，依稀風景似蘭亭。',32,'全唐诗/poet.song.241000.json','["漠漠烟橫草樹青，依稀風景似蘭亭。", "小橋疏竹人沽酒，曲徑落花僧掩扃。"]'),
('0b0df741-60dd-4f8d-890b-0e85e4479571','乾溪舖','李次淵','宋','宋诗','song-poetry','','[]','蘆芽抽盡柳花黄，水滿田頭未插秧。',32,'全唐诗/poet.song.241000.json','["蘆芽抽盡柳花黄，水滿田頭未插秧。", "客裏不知春事晚，舉頭驚見楝花香。"]'),
('7c77de73-0c27-4b24-9ed9-52b524bd6bbb','分水舖','李次淵','宋','宋诗','song-poetry','','[]','青山北去連吳會，綠水東流到八閩。',32,'全唐诗/poet.song.241000.json','["青山北去連吳會，綠水東流到八閩。", "何必此中分界限，普天率土盡王臣。"]'),
('c9554d50-ae1a-404e-8fcb-28eaaa74854e','楊莊舖','彭可軒','宋','宋诗','song-poetry','','[]','芳草迢迢去路，垂楊脈脈長亭。',28,'全唐诗/poet.song.241000.json','["芳草迢迢去路，垂楊脈脈長亭。", "野渡半篙水碧，斜陽數點山青。"]'),
('7b8d4586-eadb-48f8-88c5-2fda6e144c51','望仙舖','梅癯兵','宋','宋诗','song-poetry','','[]','一叟搜盆婦絮羹，喜聞官至出相迎。',32,'全唐诗/poet.song.241000.json','["一叟搜盆婦絮羹，喜聞官至出相迎。", "兩三家自爲鄰里，一半田皆無主名。"]'),
('855aa432-98ab-4089-b90e-f3e103415255','興田舖','范雲山','宋','宋诗','song-poetry','','[]','曲坡行盡處，雞犬兩三家。',24,'全唐诗/poet.song.241000.json','["曲坡行盡處，雞犬兩三家。", "十里長亭路，青山道正賒。"]'),
('22e8fc5d-0089-4d5b-b43a-2b4972233575','黄亭舖','翁汝正','宋','宋诗','song-poetry','','[]','落日荒荒下遠蕪，市橋官柳綠扶疏。',32,'全唐诗/poet.song.241000.json','["落日荒荒下遠蕪，市橋官柳綠扶疏。", "沙頭一霎腥風起，沽酒老翁來賣魚。"]'),
('8f532cfc-e68c-4bd1-9c7d-17fc99aeb43b','梅溪舖','翁賜坡','宋','宋诗','song-poetry','','[]','村北村南春水，山前山後人家。',28,'全唐诗/poet.song.241000.json','["村北村南春水，山前山後人家。", "夜來何處飛雨，流出碧桃數花。"]'),
('e99c184c-8461-4307-a2a5-8c7e29e3d561','題壁','羅浮狂客','宋','宋诗','song-poetry','','[]','雲意不知滄海，春光欲上翠微。',28,'全唐诗/poet.song.241000.json','["雲意不知滄海，春光欲上翠微。", "人間一墮千劫，猶愛梅花未歸。"]'),
('f083caea-2a02-4768-9515-042213789dac','却聘','梅國淳','宋','宋诗','song-poetry','','[]','野人不慣服冠裳，散髮披襟興味長。',32,'全唐诗/poet.song.241000.json','["野人不慣服冠裳，散髮披襟興味長。", "他日麒麟應有楦，願留蘇武牧羝羊。"]'),
('2125f93b-52bb-4cb1-b41b-7c457d0e18df','詩一首','黄濴','宋','宋诗','song-poetry','','[]','半濃半淡四山景，快雨快晴三月雷。',32,'全唐诗/poet.song.241000.json','["半濃半淡四山景，快雨快晴三月雷。", "橋影不隨流水去，漁歌偏带夕陽來。"]'),
('55f18cdc-98f4-4246-b718-1451dee8fde6','題鄭介夫祠','黄濴','宋','宋诗','song-poetry','','[]','當年不作南行客，他日應無北狩人。',32,'全唐诗/poet.song.241000.json','["當年不作南行客，他日應無北狩人。", "官似虱微言許大，肉如蟻飽道方伸。"]'),
('89d1301c-b20a-400e-8b80-2671b4d409a8','春秋贊','宋度宗','宋','宋诗','song-poetry','','[]','微顯闡幽，三體五例。',20,'全唐诗/poet.song.241000.json','["微顯闡幽，三體五例。", "嚴乎成言，褒貶一字。"]'),
('4d036012-bd26-42c0-b531-5d5e21e57131','周禮贊','宋度宗','宋','宋诗','song-poetry','','[]','肇建六典，條章煥明。',20,'全唐诗/poet.song.241000.json','["肇建六典，條章煥明。", "萬世之則，太平之基。"]'),
('ccf0fb35-1a29-4257-9e4c-b6803e63962f','日新','宋度宗','宋','宋诗','song-poetry','','[]','大哉盤銘，日新其德。',20,'全唐诗/poet.song.241000.json','["大哉盤銘，日新其德。", "一盟一思，惟湯是則。"]'),
('1f242fad-6215-475f-9739-8be63bb1c3b7','自警  其一','宋度宗','宋','宋诗','song-poetry','','[]','孳孳爲善，無怠講習。',20,'全唐诗/poet.song.241000.json','["孳孳爲善，無怠講習。", "心思唐虞，聖道可入。"]'),
('b4d8a0d7-f94d-4505-b9dc-63acd6d7156b','自警  其二','宋度宗','宋','宋诗','song-poetry','','[]','私既克，理是從。',24,'全唐诗/poet.song.241000.json','["私既克，理是從。", "中則正，公則平。", "操則存，德日新。"]'),
('1ba860f0-acf3-4288-8c82-8f3b3f9489a9','離卦贊','宋度宗','宋','宋诗','song-poetry','','[]','日月麗天，德備中正。',20,'全唐诗/poet.song.241000.json','["日月麗天，德備中正。", "明以繼明，聖而益聖。"]'),
('9fb8312c-0743-41b2-a7b8-fb008f1edf8e','艮卦贊','宋度宗','宋','宋诗','song-poetry','','[]','兼山曰艮，德在知止。',20,'全唐诗/poet.song.241000.json','["兼山曰艮，德在知止。", "君子體之，思不出位。"]'),
('b51b4964-3fd9-48df-82ea-7785e2a4cf7e','晚望','宋度宗','宋','宋诗','song-poetry','','[]','鷗鷺歸烟渚，秋江挾晚晴。',24,'全唐诗/poet.song.241000.json','["鷗鷺歸烟渚，秋江挾晚晴。", "老漁閑艤艇，坐待月華生。"]'),
('b4099bf6-5bce-426e-b499-3a7c24ad09c3','賞春','宋度宗','宋','宋诗','song-poetry','','[]','珠簾翠幕千門曉，麗日和風萬國春。',32,'全唐诗/poet.song.241000.json','["珠簾翠幕千門曉，麗日和風萬國春。", "乍雨乍晴雖莫測，無非天地發生仁。"]'),
('f4c45d91-b506-42c3-92e6-bed093132740','社日雨','宋度宗','宋','宋诗','song-poetry','','[]','風催社日雨霏雰，處處雞豚樂祀神。',32,'全唐诗/poet.song.241000.json','["風催社日雨霏雰，處處雞豚樂祀神。", "見說豐年於此卜，不妨墊濕社翁巾。"]'),
('74a3a83f-2e99-409a-b5a2-ff137331678d','新凉','宋度宗','宋','宋诗','song-poetry','','[]','新凉燈火又相親，遍閲羣書不厭勤。',32,'全唐诗/poet.song.241000.json','["新凉燈火又相親，遍閲羣書不厭勤。", "緩視微吟真樂處，那知宮漏夜將分。"]'),
('c833899f-e799-418a-b932-ac79b031d4f5','授衣','宋度宗','宋','宋诗','song-poetry','','[]','從來人事順天時，九月纔更即授衣。',32,'全唐诗/poet.song.241000.json','["從來人事順天時，九月纔更即授衣。", "可笑索裘臨歲晚，履霜猶自未知幾。"]'),
('c3b1efa6-8947-4638-8eb4-eb5626142744','桂','宋度宗','宋','宋诗','song-poetry','','[]','秋桂庭前霽影凉，萬重深翠護深黄。',32,'全唐诗/poet.song.241000.json','["秋桂庭前霽影凉，萬重深翠護深黄。", "恭迎兩殿臨清賞，壽斚濃浮月殿香。"]'),
('4ee23f89-b857-4829-8484-08bcd6dc9b00','恭和御製賜牟子才韻','宋度宗','宋','宋诗','song-poetry','','[]','視草詞臣地位高，玉堂深夜許焚膏。',64,'全唐诗/poet.song.241000.json','["視草詞臣地位高，玉堂深夜許焚膏。", "文華瑞世呈儀鳳，顧問承恩直禁鼇。", "喜有奇才追宋軾，光膺聖製勝唐綯。", "重修盛典熙朝事，千古青編記寵褒。"]'),
('90115a9b-3bb9-4887-88e6-321e19c12fda','題諸色扇  其一','宋度宗','宋','宋诗','song-poetry','','[]','履霜知地凍，賞雪念民寒。',84,'全唐诗/poet.song.241000.json','["履霜知地凍，賞雪念民寒。", "山嵐迷曉月，海浪起晴雲。", "鷺起蓮邊曉，鷗棲蓼外凉。", "西風欹翠蓋，曉露浥紅裳。", "艷紅酣霽圃，冷翠媚秋池。", "聲幽梧葉雨，香冷菊花風。", "院子供新茗，園丁獻異花。"]'),
('65486dee-c8ab-404f-ad03-8803bb5e83f0','題諸色扇  其二','宋度宗','宋','宋诗','song-poetry','','[]','穠華照水澄秋靜，冷艷欺風醉露凉。',80,'全唐诗/poet.song.241000.json','["穠華照水澄秋靜，冷艷欺風醉露凉。", "一枝翠葉凝秋色，萬粟金英噴古香。", "月篩穠影虛窗靜，秋染繁英淨几香。", "千葉喜容迎曉日，萬鈴黄色映朝霞。", "日麗柳塘鶑語滑，雨收桃岸燕飛忙。"]'),
('861dbcad-f9a4-4e9d-8e93-86500d0f6673','凝華殿帖子','宋度宗','宋','宋诗','song-poetry','','[]','帝德巍巍，溫恭允塞。',20,'全唐诗/poet.song.241000.json','["帝德巍巍，溫恭允塞。", "心傳精微，惟堯是則。"]'),
('35871dec-ee95-4cfe-9e01-d8a9e1fd5dcb','賜陳郁','宋度宗','宋','宋诗','song-poetry','','[]','文窺先漢，詩到盛唐。',37,'全唐诗/poet.song.241000.json','["文窺先漢，詩到盛唐。", "侍余左右，知汝忠良。", "王城雖大如海，政恐一藏而不得藏也。"]'),
('e49a62fd-4123-4b06-a345-3b7619f55ef2','進聖訓','宋度宗','宋','宋诗','song-poetry','','[]','寵頒御墨十行新，天錫光華被小臣。',32,'全唐诗/poet.song.241000.json','["寵頒御墨十行新，天錫光華被小臣。", "家學傳心當謹守，恩深何以報君親。"]'),
('43f40ddf-2afa-4eab-878d-8d106058e5c6','賜狀元張鎮孫以下詩','宋度宗','宋','宋诗','song-poetry','','[]','臨軒再策豈虛文，要語詒謀敢弗遵。',64,'全唐诗/poet.song.241000.json','["臨軒再策豈虛文，要語詒謀敢弗遵。", "昭格天心惟至敬，封培邦本在深仁。", "詳延喜見洋洋對，來譽知爲蹇蹇臣。", "始進便當思遠到，會須華國有儒珍。"]'),
('b8d14ec0-e472-44bd-820a-ad3432f0e53b','句  其一','宋度宗','宋','宋诗','song-poetry','','[]','歸仁由克己，學道在存心。',12,'全唐诗/poet.song.241000.json','["歸仁由克己，學道在存心。"]'),
('c6936ecd-4aa5-4627-b534-31b18fccd67c','句  其二','宋度宗','宋','宋诗','song-poetry','','[]','堯舜傳心惟以一，禹湯受命本乎中。',16,'全唐诗/poet.song.241000.json','["堯舜傳心惟以一，禹湯受命本乎中。"]'),
('0d09fd46-7b9f-48d5-ba07-b3af95753206','送孟和卿平陽尋母','龔孟夔','宋','宋诗','song-poetry','','[]','杜羔念母心最苦，豈意一朝逢澤潞。',160,'全唐诗/poet.song.241000.json','["杜羔念母心最苦，豈意一朝逢澤潞。", "母驚兒貌似乃翁，兒抱母啼淚如雨。", "五十孺慕朱壽昌，刺血寫經毛髮蒼。", "間關同州晚相見，迎侍親輿歸故鄉。", "人生百年一彈指，母恩未報情曷已。", "團圞尊前舞綵衣，大勝世間朱與紫。", "子行萬里涉風沙，誓不見母不還家。", "兒今髮落母應老，道旁看者還咨嗟。", "臨川孟氏號雍睦，家世來此澶淵族。", "婆娑老慕紫荆花，料想春風依舊綠。"]'),
('71637093-0fa7-4435-b2bc-b24b15eec795','嘲賈似道','劉壎','宋','宋诗','song-poetry','','[]','三百年餘歷數更，東南萬里看昇平。',32,'全唐诗/poet.song.241000.json','["三百年餘歷數更，東南萬里看昇平。", "黄金臺上麒麟閣，混一元勳是賈生。"]'),
('f6dee79b-93b0-4fec-979a-a9119611213a','輓蜀帥張公玨','劉壎','宋','宋诗','song-poetry','','[]','玉壘雲浮五十秋，關西虓將勇無儔。',64,'全唐诗/poet.song.241000.json','["玉壘雲浮五十秋，關西虓將勇無儔。", "三吳甑墮猶堅守，八柱唇亡不耐愁。", "瀘水捷收勞騕褭，夔門機伏失兜鍪。", "吾君不負吾甯死，遺恨誰憐快敵讎。"]'),
('b5901bf7-17b0-4b0a-bd09-173ea2f18179','輓綿漢簡諸公','劉壎','宋','宋诗','song-poetry','','[]','綿漢風酸動殺機，北來鐵騎遍驅馳。',64,'全唐诗/poet.song.241000.json','["綿漢風酸動殺機，北來鐵騎遍驅馳。", "幾千里地弓刀運，百萬人家骨肉糜。", "鬼哭神號無限恨，蠅蛄蚋嘬有餘悲。", "平生食祿何從避，留取香名百世垂。"]'),
('465b4737-1d91-456d-9999-95a452ceda31','輓四川制帥陳公','劉壎','宋','宋诗','song-poetry','','[]','狼煙又起錦城邊，帥閫謀疏亦可憐。',64,'全唐诗/poet.song.241000.json','["狼煙又起錦城邊，帥閫謀疏亦可憐。", "先軫元歸應有恨，萇宏血化豈無冤。", "百身莫贖誰三酹，一死真成蓋萬愆。", "遺事如今人不記，綱常猶幸立西川。"]'),
('d4ada8c5-1d93-4325-aac0-9a2bb997d717','補史十忠詩 知潭州湖南安撫使李公芾','劉壎','宋','宋诗','song-poetry','','[]','三已甘退休，十連起遲暮。',120,'全唐诗/poet.song.241000.json','["三已甘退休，十連起遲暮。", "伊誰急求子，流落乃不怒。", "黑雲來如山，殺氣震平楚。", "恭惟君父命，封疆以身護。", "闔門義不辱，呼卒汝善處。", "飛魂隨劍光，自已投火去。", "天泣鬼神愁，地摇山嶽仆。", "吾非莒柱厲，敢以死醜主。", "正自常事耳，命義逃安所。", "沖遠誰與儔，睢陽有張許。"]'),
('1bcfdb5c-9f0b-4542-bf45-7480ef41cad2','補史十忠詩 池州通判權州事趙公','劉壎','宋','宋诗','song-poetry','','[]','若人作何狀，立節乃殊偉。',120,'全唐诗/poet.song.241000.json','["若人作何狀，立節乃殊偉。", "人言此蜀珍，位卑名未起。", "坐分秋浦月，攝此千里寄。", "沙頭風色惡，寒城凜弘峙。", "吾聞開關迎，棄遁亦復耻。", "茲惟城郭臣，大義吾知已。", "間道走帛書，灑血別玉季。", "細君絕可人，雙飛同一死。", "南八彼男兒，此婦乃如此。", "骨朽香不廢，吾詩當清史。"]'),
('2cb2807e-b91c-4451-a7e5-ea99dc736bfb','補史十忠詩 丞相都督信國公文公','劉壎','宋','宋诗','song-poetry','','[]','時平輒棄置，事迫甘前驅。',120,'全唐诗/poet.song.241000.json','["時平輒棄置，事迫甘前驅。", "嗚呼忠義臣，匪直科目儒。", "江寒朔吹急，列城同一趨。", "豈不寄便安，綱常乃當扶。", "移檄倡諸鎮，奮袂躬援枹。", "川决莫我回，萬險棲海隅。", "天乎復不濟，道窮竟成俘。", "一死事乃了，吾頭任糢糊。", "悠悠譏好名，責人無已夫。", "三衢有魁相，投老作尚書。"]'),
('6aadb7de-6305-47bb-8157-3d0161f09da1','補史十忠詩 參政行丞相事陸公秀夫','劉壎','宋','宋诗','song-poetry','','[]','天地無託足，海天同隰光。',120,'全唐诗/poet.song.241000.json','["天地無託足，海天同隰光。", "明知復何爲，不忍隳三綱。", "祼薦覬少延，謳歌寧遠忘。", "或者莒在齊，聊且帝一方。", "竭蹶竟委頓，臣謀非不臧。", "運去天莫留，力盡心彌强。", "終不負吾主，名義天地長。", "懷璽隨龍遊，舉室水中央。", "斯人文華士，乃爾百鍊剛。", "機雲儻通譜，應羞朝洛陽。"]'),
('b0c13f1b-70ac-4670-ac67-6c6a20a5a7e6','補史十忠詩 前左丞相江文忠公萬里弟萬頃','劉壎','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','匡廬雲錦屏，鴻儒産其下。',120,'全唐诗/poet.song.241000.json','["匡廬雲錦屏，鴻儒産其下。", "風神儼如龍，夭矯莫可駕。", "卷懷經濟具，婆娑洛中社。", "怪事玉牀摇，清晝天忽夜。", "突騎從何來，陰風飄屋瓦。", "大臣義有死，欲避吾不暇。", "庭前環止水，萬事付一捨。", "從容友靈均，朝野動悲吒。", "愍章極哀榮，汗簡誰記者。", "倘有南熏書，季方足堪亞。"]'),
('0aab9ef4-447e-440a-a45a-212af218dee1','補史十忠詩 江西制置司都統密公侑','劉壎','宋','宋诗','song-poetry','','[]','臣有置身義，豈計官崇卑。',120,'全唐诗/poet.song.241000.json','["臣有置身義，豈計官崇卑。", "偏將知死忠，不曰天下奇。", "漢節既披靡，失位趨江西。", "閫帳駐臨汝，招徠樂其歸。", "雪寒南浦愁，羽檄蘄濟師。", "一將奮風虎，鼓行亟飈馳。", "踰嶺疾戰苦，裹瘡呼健兒。", "坐縛膝不屈，伏鑕甘如飴。", "小臣禆校耳，職也宜死綏。", "廬州大將在，白首豎降旗。"]'),
('db4a1f2a-d76a-4dc5-8063-7947033e6fab','補史十忠詩 淮東制置使知楊州李公庭芝','劉壎','宋','宋诗','song-poetry','','[]','淮海接風塵，胡乃似鐵壁。',120,'全唐诗/poet.song.241000.json','["淮海接風塵，胡乃似鐵壁。", "卧護有天人，十載藉福力。", "重來人未老，愁絕事如昔。", "苦戰孤城危，痛哭天柱拆。", "夢遊三山上，人倫浮海出。", "突圍志南征，吾欲重建極。", "天弗鑒臣忠，冥冥墮叢棘。", "先軫面如生，萇弘血化碧。", "臣死誰復知，臣忠終不易。", "一將更大事，嚼舌死駡敵。"]'),
('86f8184c-b1f3-4bc2-886a-f27626234a4c','補史十忠詩 樞密閩廣宣撫使陳公','劉壎','宋','宋诗','song-poetry','','[]','淳熙名宰孫，比德粹如玉。',120,'全唐诗/poet.song.241000.json','["淳熙名宰孫，比德粹如玉。", "决科魁偉英，駸駸廌冠肅。", "䫫田煩諫疏，相嗔俄嗾逐。", "補郡仍免歸，黄流已漫陸。", "天族日光薄，力疾支顛覆。", "蹉跎南冠縶，道病死不辱。", "往昔五峰堂，傾蓋語跋燭。", "斯人真妙人，哀哉慳厚祿。", "長揖丙辰魁，各天並黄鵠。", "不有二忠存，千古笑科目。"]'),
('c98df0a5-21ba-4950-92bc-94b302054351','補史十忠詩 少傅樞密使張公世傑','劉壎','宋','宋诗','song-poetry','','[]','士有守節死，豈以責武夫。',120,'全唐诗/poet.song.241000.json','["士有守節死，豈以責武夫。", "武夫尚能奇，消得銀管書。", "何許熊虎英，鐵面美髯鬚。", "護寒久枕戈，赴難甘殞軀。", "金山定活著，志願嗟違初。", "江心集羣策，炎精回一噓。", "間關瘴海嶺，萬死存趙孤。", "時也可奈何，北風散檣烏。", "漂漂竟何之，無乃膏鯨魚。", "渭濱多貴將，反笑斯人迂。"]'),
('3582ae3d-57e1-47c7-b802-041a2619f9ac','補史十忠詩 四川制置使知重慶府張公玨','劉壎','宋','宋诗','song-poetry','','[]','坤維拓提封，形勝古天府。',120,'全唐诗/poet.song.241000.json','["坤維拓提封，形勝古天府。", "血戰五十秋，零落餘八柱。", "江南傳箭急，誰暇此回顧。", "落日古渝城，杖鉞乃甚武。", "天東甑雖墮，吾自强支拄。", "渡瀘躬討逆，歸來戰彌苦。", "蕭條下夔門，機穽伏中路。", "咄咄快敵仇，誰歟掩坏土。", "哀哉關西雄，國亡猶不負。", "同時督軍將，腰金插雙虎。"]'),
('19db122c-4fb7-447e-810e-6f37caf6339e','句  其一','劉壎','宋','宋诗','song-poetry','','[]','羽纛金章映坐狨。',8,'全唐诗/poet.song.241000.json','["羽纛金章映坐狨。"]'),
('8875bcd5-914b-4644-b3b4-ea83764da5d0','句  其二','劉壎','宋','宋诗','song-poetry','','[]','水繞桃源隄上下，花迷金谷路高低。',16,'全唐诗/poet.song.241000.json','["水繞桃源隄上下，花迷金谷路高低。"]'),
('3dcda997-f8e4-4812-92b8-a94cf97bd9ca','遊仙華山','方鳳','宋','宋诗','song-poetry','','[]','仙華矗萬仞，我乃廬其東。',144,'全唐诗/poet.song.241000.json','["仙華矗萬仞，我乃廬其東。", "日夕與山對，今茲踏玲瓏。", "起左信奔鹿，當前任啼狨。", "大嘯崖石裂，一覽天宇空。", "蒼松飽風雨，絕壁挂老龍。", "樵斧不得睨，撫根憩吾躬。", "邈哉軒轅氏，問道由崆峒。", "龍髯一以遠，千載悲遺弓。", "猶傳少女靈，鍊玉于焉宮。", "山林重帝胄，香火明民衷。", "我來重懷古，攬涕臨西風。", "何當刺飛流，一洗磊磈胸。"]'),
('c1f5ba5c-f907-443f-9abd-411b86ab6735','遊寶掌山寺','方鳳','宋','宋诗','song-poetry','','[]','茲辰欲有適，軒車偶來駸。',180,'全唐诗/poet.song.241000.json','["茲辰欲有適，軒車偶來駸。", "劚苔北村南，荒竹晴窗陰。", "接語未及久，相邀指叢林。", "澗行任詰曲，巖眺經嶔崟。", "于時春早暄，生意見草心。", "紅紫寂未動，萬山蒼翠深。", "伊予夙好遊，忽忽老見侵。", "孤興尚衡霍，遐思或巫黔。", "况此近居里，而能盍朋簪。", "裂石發悲嘯，沿流引清斟。", "捫蘿復忘疲，古洞窮幽尋。", "豈無聲利痼，見笑山水淫。", "人生本來浮，世故未易任。", "蘚崖拂前題，俛仰已昔今。", "我法姑用我，睠言屬同襟。"]'),
('fcf7e6c1-fd1a-4a59-b963-e7c36e6d4181','寄柳道傳黄晉卿兩生  其一','方鳳','宋','宋诗','song-poetry','','[]','大火且西逝，赫曦詎能爲。',60,'全唐诗/poet.song.241000.json','["大火且西逝，赫曦詎能爲。", "叢竹覆孤館，綠陰相蔽虧。", "人散衆喧寂，獨鳥嚶鳴隨。", "想見探討餘，層層發新知。", "儻不鄙朽拙，勉哉勤相遺。"]'),
('d4059e58-bfe5-4810-960f-f277530c66bc','寄柳道傳黄晉卿兩生  其二','方鳳','宋','宋诗','song-poetry','','[]','太璞散已久，鴻甄疑未均。',60,'全唐诗/poet.song.241000.json','["太璞散已久，鴻甄疑未均。", "惟有砥礪志，搜剝得其純。", "勿以珪璋質，頑石置勿陳。", "君攬國香蕊，每與荆棘鄰。", "荆棘豈不刺，反以揚素塵。"]'),
('4deb376a-1a03-462d-aaa4-ab985fe46407','寄柳道傳黄晉卿兩生  其三','方鳳','宋','宋诗','song-poetry','','[]','盈盈黄菊叢，栽培費時日。',60,'全唐诗/poet.song.241000.json','["盈盈黄菊叢，栽培費時日。", "依依五絲瓜，引蔓牆籬出。", "于今想新花，于今長秋實。", "花實豈不時，灌溉尚期密。", "毋令根荄傷，委棄等藜蒺。"]'),
('501d1cb8-ea65-4c67-8f1a-46e77fa9300e','寄柳道傳黄晉卿兩生  其四','方鳳','宋','宋诗','song-poetry','','[]','新秋凉氣發，松籟調于喁。',60,'全唐诗/poet.song.241000.json','["新秋凉氣發，松籟調于喁。", "山房良靜閴，文史淡足娛。", "吾心太虛廓，儻然萬象俱。", "大觀物物齊，何事分賢愚。", "遐哉金蘭契，聊用佈區區。"]'),
('6e0eb947-ce7b-431d-836e-ca49c3fd164d','懷龔山人聖予','方鳳','宋','宋诗','song-poetry','','[]','西北有傑閣，岧嶢切雲天。',108,'全唐诗/poet.song.241000.json','["西北有傑閣，岧嶢切雲天。", "綺窗通四望，綽約流蘇懸。", "中有絕代人，端居方盛年。", "被服既殊衆，容采亦鮮妍。", "瑶床置寶瑟，玉軫朱絲絃。", "有時揚妙指，泠泠宮商傳。", "曲終恣仰頫，託契軒農先。", "靡曼諧里耳，大雅誰能憐。", "我欲往從者，淮海生寒烟。"]'),
('0d21654f-aaa3-4d2d-baf9-608fc2b89f07','藥壺山寺步師遠上人韻','方鳳','宋','宋诗','song-poetry','','[]','旭日耀禪林，曈矓晃虛室。',48,'全唐诗/poet.song.241000.json','["旭日耀禪林，曈矓晃虛室。", "觀心得無爲，頗覺詩思逸。", "得句祈疾書，振衣陡焉失。", "持此證空空，一笑墮不律。"]'),
('928e5d9d-ab28-40c5-81bd-01751ccecdf0','寄仇仁近','方鳳','宋','宋诗','song-poetry','','["\u897f\u6e56"]','憶昔三浙湄，匆遽買舟訣。',132,'全唐诗/poet.song.241000.json','["憶昔三浙湄，匆遽買舟訣。", "大海漲波濤，排空銀浪掣。", "時方逢杪秋，凉風正凄絕。", "况復嬰沈疴，殘喘一身孑。", "落日古渡橫，牽衣各嗚咽。", "尚期營歸餘，旋泛山陰雪。", "詎料人事遷，芳春竟五閲。", "寧無雙鯉魚，寒溫敘曲折。", "顧茲悲憤衷，未足陳一切。", "階前金鳳花，當車行復輟。", "閣上西湖光，可似舊澄澈。"]'),
('ad170228-77e7-4f7e-a223-78998df39def','重陽對菊得菊字','方鳳','宋','宋诗','song-poetry','','[]','懷哉止所翁，與我幾觴菊。',96,'全唐诗/poet.song.241000.json','["懷哉止所翁，與我幾觴菊。", "方當舊節來，已作秋原哭。", "會葬有遠朋，風雨此淹宿。", "佳兒敬父執，姻友更敦睦。", "投轄不愧遵，設醴仍爲穆。", "其如插萸遍，不見而翁獨。", "悲歡今昨筵，還往東西轂。", "回首試長望，依依但雲木。"]'),
('72587e65-3d4a-4fee-8fe0-5becf4ba8321','題鄭氏義門','方鳳','宋','宋诗','song-poetry','','[]','人愛渭水清，畢竟河流渾。',288,'全唐诗/poet.song.241000.json','["人愛渭水清，畢竟河流渾。", "不知黄虞世，何處覓旌門。", "旌門縱百世，豈能外彝倫。", "祇因風氣漓，遂表爲義民。", "麟溪有寒泉，西流類拖紳。", "泉聲徧塞耳，亂却牝雞晨。", "夜帳潑煙黑，秋缸吐火紅。", "六世孝友家，元屬書聲中。", "爛銀鋪作榜，綽楔何崔崔。", "戶神似相語，莫遣阿奴來。", "人心一遭蠱，五官皆作魔。", "不賡斯干詩，却聽燃萁歌。", "兄弟本一氣，爲利分汝爾。", "借問嗜利人，千載得不死。", "鴟鴞巢滿林，何地不感惻。", "若非慈烏啼，血淚收不得。", "我身親乃有，况此身外物。", "世人果何思，肝膽每相賊。", "當年朱兩轓，回首血在頤。", "爭如義門鬼，千載不餒而。", "何人非楊椿，如椿能幾人。", "祇緣本心死，所以有緇磷。", "大樹大十圍，枝葉日敷蕃。", "願培百尺土，庇此千歲根。"]'),
('ef915902-1189-4f5d-b9c1-18c3571c9a3b','哭陸丞相秀夫','方鳳','宋','宋诗','song-poetry','','[]','祚微方擁幼，勢極尚扶顛。',48,'全唐诗/poet.song.241000.json','["祚微方擁幼，勢極尚扶顛。", "鼇背舟中國，龍胡水底天。", "鞏存周已晚，蜀盡漢無年。", "獨有丹心皎，長依海日懸。"]'),
('66b0e924-8ae7-4a7e-bee0-c64f3d9f7c55','咏霜葉寄皋羽善父','方鳳','宋','宋诗','song-poetry','','[]','秋盡吳江道，丹楓樹樹奇。',48,'全唐诗/poet.song.241000.json','["秋盡吳江道，丹楓樹樹奇。", "葉爲詩者色，霜乃畫之師。", "望似醉鄉近，疑猶花事遲。", "停雲俄在念，倚杖未歸時。"]'),
('ba59bb8a-2600-4410-a172-b213daa538f8','北山道中','方鳳','宋','宋诗','song-poetry','','[]','拂衣去城市，信步踏晴泥。',48,'全唐诗/poet.song.241000.json','["拂衣去城市，信步踏晴泥。", "草意春風蚤，松陰野日西。", "語長忘路遠，行近覺山低。", "更欲遲來此，穿林聽鳥啼。"]'),
('05b40cb6-8178-4653-ada5-26e0d5b56f10','西鹿田寺聽雨','方鳳','宋','宋诗','song-poetry','','[]','禪棲投倦客，山雨起更闌。',48,'全唐诗/poet.song.241000.json','["禪棲投倦客，山雨起更闌。", "窗葉散幽響，石林生峭寒。", "洞深猶暗瀑，江遠忽飛湍。", "想像雲蘿外，應宜曉色看。"]'),
('a66f8f47-0583-4aab-8df3-28ae1263ec35','同胡汲仲兄弟登香遠樓','方鳳','宋','宋诗','song-poetry','','[]','策杖探幽勝，同登况二難。',48,'全唐诗/poet.song.241000.json','["策杖探幽勝，同登况二難。", "江山雙極目，宇宙一凭欄。", "春色啼鶑破，孤城擁浪寒。", "遥遥烟靄裏，猶作故宮看。"]'),
('a806d27a-dca9-4f29-80ec-83115fc5304d','東甌雪中山茶盛開','方鳳','宋','宋诗','song-poetry','','[]','海色連蓬島，同雲一望迷。',48,'全唐诗/poet.song.241000.json','["海色連蓬島，同雲一望迷。", "寒花空故故，醉酒只悽悽。", "卜世無三兆，傷心有五噫。", "仲宣樓上賦，愁絕不堪題。"]'),
('b2f36411-f3fb-4443-af29-5f46001d35cd','答仇仁近','方鳳','宋','宋诗','song-poetry','','[]','城郭相過嬾，山房翳薜蘿。',48,'全唐诗/poet.song.241000.json','["城郭相過嬾，山房翳薜蘿。", "谷當嘉客遯，阿稱碩人薖。", "竹徑鳴騶斷，芝壇野鹿多。", "松風雲壑冷，掃石待狂歌。"]'),
('5a72279b-3627-487d-b8d8-90a54ed17c95','呈皋羽','方鳳','宋','宋诗','song-poetry','','[]','依依蓮社客，斗酒共相酬。',48,'全唐诗/poet.song.241000.json','["依依蓮社客，斗酒共相酬。", "臭味語中得，榮名杯上浮。", "世情餘百變，吾道合千秋。", "肯信張平子，窮居但四愁。"]'),
('cd4e0fac-bfab-4db3-b102-75ebd6d33ba9','寄吳善父','方鳳','宋','宋诗','song-poetry','','[]','嘖嘖不得意，興懷偏爲君。',48,'全唐诗/poet.song.241000.json','["嘖嘖不得意，興懷偏爲君。", "猶爲乞米帖，不作送窮文。", "縱酒長違俗，揮毫自出羣。", "相思今夜雨，滴瀝未堪聞。"]'),
('1785be53-b08d-465a-9347-394e3716ffd6','次陳浦泉教授渡江韻','方鳳','宋','宋诗','song-poetry','','[]','笑拂湖亭柳，春歸客亦歸。',48,'全唐诗/poet.song.241000.json','["笑拂湖亭柳，春歸客亦歸。", "塔雲連岫暗，颿雨絕江飛。", "老覺遊非壯，癯應遯却肥。", "有詩充古錦，尚不愧林扉。"]'),
('ef2574f9-8351-4f86-803c-14cc4b355eda','宿保安寺','方鳳','宋','宋诗','song-poetry','','[]','捫蘿山逕迥，流水石橋分。',48,'全唐诗/poet.song.241000.json','["捫蘿山逕迥，流水石橋分。", "一雨過秋寺，千峰生暮雲。", "望窮迷野色，沙遠見鷗羣。", "煙靄蒼茫外，寥寥清磬聞。"]'),
('a8a51791-5147-44ce-acf0-e605f1332521','八月十四壽吳良貴','方鳳','宋','宋诗','song-poetry','','[]','四十强而仕，斯言著禮經。',48,'全唐诗/poet.song.241000.json','["四十强而仕，斯言著禮經。", "摶鵬宜運海，振鷺且充庭。", "後夜中秋月，今朝南極星。", "耄夫頻獻酢，留眼看袍青。"]'),
('4dd3fa15-533d-46fb-8c8b-d557a5522847','哭餘之張教授','方鳳','宋','宋诗','song-poetry','','[]','吾憐張仲蔚，青草少人行。',48,'全唐诗/poet.song.241000.json','["吾憐張仲蔚，青草少人行。", "曉帳螢猶濕，空山鶴自驚。", "徒餘八斗望，誰築五言城。", "莽莽孤村外，王孫掛劍情。"]'),
('8c583f75-8a6f-40db-8cb6-4b887aceb8ec','和張子良','方鳳','宋','宋诗','song-poetry','','[]','寤寐溪山好，相過不厭頻。',48,'全唐诗/poet.song.241000.json','["寤寐溪山好，相過不厭頻。", "詩留曾宿客，月照乍歸人。", "率爾呼盤粲，憑誰辨主賓。", "未須陳咫尺，高誼總秋旻。"]'),
('f057faef-ca99-429a-bd9e-407ece7b6dd8','書示同志','方鳳','宋','宋诗','song-poetry','','[]','尚覺浮名累，樵漁寄此身。',48,'全唐诗/poet.song.241000.json','["尚覺浮名累，樵漁寄此身。", "尋盟潛勗德，証業喜知新。", "氣誼生無間，文章合有神。", "毋徒涉城市，出處任風塵。"]'),
('905fb806-2046-4912-ba63-82c0182eaa60','贈樂閒居士','方鳳','宋','宋诗','song-poetry','','[]','市遠塵囂隔，神閒幽事并。',48,'全唐诗/poet.song.241000.json','["市遠塵囂隔，神閒幽事并。", "埽花憐竹影，煮茗訝松聲。", "月與詩如約，琴將鶴互賡。", "冷香生碧落，秋夢不勝清。"]'),
('da14c5f8-77d8-4d20-9ff5-6b3a205e18a6','重陽明日得日字','方鳳','宋','宋诗','song-poetry','','[]','浮生聚塵輕，流景飛羽疾。',48,'全唐诗/poet.song.241000.json','["浮生聚塵輕，流景飛羽疾。", "故人已新阡，舊雨又今日。", "不惜酒飲狂，且須詩縛律。", "一笑復掀髯，天地何終畢。"]'),
('1e95da68-fea4-4b20-8223-51a1341cf122','仙華招隠','方鳳','宋','宋诗','song-poetry','','[]','軒后悲蒼劍，神娥下玉霄。',96,'全唐诗/poet.song.241000.json','["軒后悲蒼劍，神娥下玉霄。", "攀髯初失夢，遺蛻尚凌歊。", "碧墮升棺影，青分産柱苗。", "山精依鹿竹，天雨濕鷄翹。", "有約成孤憤，無人重久要。", "豢龍因姓氏，使鶴誤軒軺。", "冉冉將終老，冥冥不可招。", "無書寄青雀，有恨在中條。"]'),
('cd4dd6d1-5b75-46ca-991c-e5eef4a87e5f','憶同張子長遊北山諸名勝','方鳳','宋','宋诗','song-poetry','','[]','昔與張公子，翩翩訪赤松。',288,'全唐诗/poet.song.241000.json','["昔與張公子，翩翩訪赤松。", "重來踰兩紀，獨去宿孤峰。", "古木蒼陂映，禪房側逕通。", "夕陰千嶂黑，人靜一燈紅。", "幸及軒車會，寧辭杖屨從。", "相看如夢寐，健步愧兒童。", "春盡山仍好，林深澗忽窮。", "天低時墮雨，寺遠偶聞鐘。", "弔古田無鹿，探奇洞有龍。", "幽尋穿䆗窱，高步蹋玲瓏。", "靈草多成藥，疏篁不作叢。", "嵐光疑晻曖，野色在空濛。", "下瞰疑無底，言旋復向東。", "巖阿依斷礎，烟嶂落飛淙。", "細路緣苔磴，危橋跨石谼。", "泉依山曲曲，雲與樹重重。", "巨剎標名嶽，穹垣護畝宮。", "倚欄斜日下，入室老僧逢。", "零落螭頭墨，荒凉馬鬣封。", "不才持薄祿，終古愧高風。", "弛擔雲關裏，傳觴雪峽中。", "追隨尋道侶，述作付文雄。", "急景真流電，浮生尚轉蓬。", "後期觀歲晏，來往意憧憧。"]'),
('1909ee36-d68e-4956-8d23-4adb9e3520ce','仙華山採茶詩','方鳳','宋','宋诗','song-poetry','','[]','軒娥遺瑞草，仙掌撐何年。',192,'全唐诗/poet.song.241000.json','["軒娥遺瑞草，仙掌撐何年。", "苗蕊矗空壁，殊根蟠遠天。", "蒙頭莫可劚，垂脚或爭傳。", "冉冉雪霜飽，亭亭風日蠲。", "危哉梯鳥道，允矣獲龍涎。", "叢蘗雜丹鼎，濕雲伴玉延。", "香真千里擅，苞結三生緣。", "夜莢抽雷後，春焙貢社前。", "一鎗滴瀼露，片碾擣和煙。", "碧澗規模絕，洪州氣味懸。", "滑甘矜紫筍，幽馥訝青蓮。", "既揀兔毫點，應添蟹眼煎。", "松濤生遠韻，風致想真筌。", "七椀賡仝咏，三篇繼羽編。", "醉鄉已失路，摩室將逃禪。", "服食益人壽，何當煮汞鉛。"]'),
('a4c41b92-ba60-4530-ae28-f28bdf3df60a','八景勝概 華柱丹光','方鳳','宋','宋诗','song-poetry','','[]','何年撐空荒，截置珊瑚樹。',24,'全唐诗/poet.song.241000.json','["何年撐空荒，截置珊瑚樹。", "長日燦朝霞，芙蕖挹新露。"]'),
('f181eb3b-3872-4bfd-b86d-504fee0bc173','八景勝概 仙壇靈草','方鳳','宋','宋诗','song-poetry','','[]','葳蕤不記名，絕壁挂縷縷。',24,'全唐诗/poet.song.241000.json','["葳蕤不記名，絕壁挂縷縷。", "果否垂衣年，絲麻績蠭午。"]'),
('4148fa50-0f3c-4e7f-b2c5-888669fbfa4d','八景勝概 中峰嘯月','方鳳','宋','宋诗','song-poetry','','[]','縱身嘗决雲，山月此晶皎。',24,'全唐诗/poet.song.241000.json','["縱身嘗决雲，山月此晶皎。", "疑是七還丹，邠盼吐物表。"]'),
('c4bb92eb-0ffa-4263-9e41-9f7e74af45bf','八景勝概 深穴噓風','方鳳','宋','宋诗','song-poetry','','[]','草木何豐彤，懸崖護丹穴。',24,'全唐诗/poet.song.241000.json','["草木何豐彤，懸崖護丹穴。", "相傳通鼎湖，深窈吹寒冽。"]'),
('942815b9-6b3b-4355-bb70-ba6067eb3a56','八景勝概 劍峽遲鸞','方鳳','宋','宋诗','song-poetry','','[]','峽中候帝子，青鳥空徘徊。',24,'全唐诗/poet.song.241000.json','["峽中候帝子，青鳥空徘徊。", "搔首叩玄律，何當化鶴來。"]'),
('a006b885-634a-4cb2-9d6c-e7fd1f8a5261','八景勝概 卦尖望鼎','方鳳','宋','宋诗','song-poetry','','[]','遥岑誰畫卦，置此荆山鼎。',24,'全唐诗/poet.song.241000.json','["遥岑誰畫卦，置此荆山鼎。", "乍可姹女飛，千秋覘溟涬。"]'),
('28f3f2fd-63d9-4c13-b7b4-019af8e319ed','八景勝概 藥壺閃影','方鳳','宋','宋诗','song-poetry','','[]','紫車貯藥壺，日夕發光怪。',24,'全唐诗/poet.song.241000.json','["紫車貯藥壺，日夕發光怪。", "不道洞府深，翻嫌八荒隘。"]'),
('3b451243-6eb9-41eb-8b14-c09c92345172','八景勝概 龍門飛瀑','方鳳','宋','宋诗','song-poetry','','[]','飛雪濺𥓂砑，流雲當面起。',24,'全唐诗/poet.song.241000.json','["飛雪濺𥓂砑，流雲當面起。", "邂逅綠毛仙，臨流同洗髓。"]'),
('6bb4dc1e-bb4f-4697-b3b8-e4f9ad4962df','三洞','方鳳','宋','宋诗','song-poetry','','[]','金華北山三洞天，垂髫欲往今華顛。',384,'全唐诗/poet.song.241000.json','["金華北山三洞天，垂髫欲往今華顛。", "春風吹衣雨洗屐，瘦筇忽拄蒼山烟。", "山高地平走幽澗，根絡石上森楠楩。", "步從飛橋瞰石洞，崖色閲世知幾年。", "風痕霧迹化異物，龍首昂左尾右旋。", "就中暗穴如蟆頤，急水瀉碧鳴媧絃。", "遡流束炬照徒涉，肩背擦石行拳攣。", "水窮路夷內景得，以炬交燭窮幽玄。", "細紋蹙波湧浪接，皓彩凝雪飛霜鮮。", "大爲獅子虎犀象，瑣碎亦復蜂屯然。", "蜿蜒雙蟠角尾具，一一玉爪拏蒼堅。", "穹龜負甲色深墨，長蛇白質相縈纏。", "鐘能鐘聲鼓能鼓，不假樅簴知誰懸。", "直櫺斜檻藏湢室，短畦長町移原田。", "青雲白霓五色霞，笑畫敗絮留丹鉛。", "中途經過最深窅，伏身低眺洞口泉。", "空明一線隔遠見，秋蟾浴海光嬋娟。", "左巖袈衣頗橫亙，疊摺衆皺垂蹁躚。", "自餘神怪不可極，似鑿非鑿鎸非鎸。", "出登山腰叩中洞，外視石井聞潺潺。", "入深踏險思縋綆，長竿揭炬後且先。", "水簾可俯心爲悼，到此十九歸言遄。", "嗜奇不憚歷磊砢，足以目故差輕便。", "翻身却望水簾處，銀河天落懸吾前。"]'),
('03121e44-4326-495e-aabb-2e24d5aea08d','與皋羽子善遊寶掌山','方鳳','宋','宋诗','song-poetry','','[]','寶掌一山何勝絕，老龍千載事已別。',160,'全唐诗/poet.song.241000.json','["寶掌一山何勝絕，老龍千載事已別。", "巉巖怪石峭森列，矯首三洞蹇奇崛。", "不知何年風雷烈，鑿開混沌此瞥裂。", "高洞攀緣與天接，棲鶻所巢勢嵽嵲。", "隙泉漏滴清且澈，薜蘿爲衣儼陳設。", "中之洞兮巧融結，四達坦明如我闥。", "低山一洞尤寒泬，鏗然谷應合音節。", "共愛孤蟬遠林咽，又疑帝子笙歌徹。", "乘風便覺神飛越，落景徘徊就僧榻。", "好向天風更搜抉，相期夜半踏明月。"]'),
('3fb62f61-c8a6-40fd-9c31-baad0297546d','故宮怨','方鳳','宋','宋诗','song-poetry','','[]','白日欲落何王宮，腥雲頹樹生烈風。',96,'全唐诗/poet.song.241000.json','["白日欲落何王宮，腥雲頹樹生烈風。", "獼猱幾年爭聚族，饑蟒獰猙攫人肉。", "熊豨肆毒夜橫行，刺蛆刲血多飛鼪。", "螢尻吐燄大如鶩，照見女鬼迎新故。", "寒更鴟吻空哀哀，誰能化鶴還歸來。", "山都冶夷總難記，妖狐吹火月墮地。"]'),
('03ae283a-37f5-40cf-a064-20f33f2226bb','題光風霽月樓','方鳳','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','人間底處無風月，知用何時最佳絕。',128,'全唐诗/poet.song.241000.json','["人間底處無風月，知用何時最佳絕。", "芳播崇樓淑氣浮，影涵古桂清輝發。", "向來雅重無極翁，灑落襟懷與此同。", "去之百世猶彷彿，宛見道貌匡廬中。", "誰題品語黄太史，大書四字紫陽子。", "今從建水得此本，如拾蠙珠捲文綺。", "携歸八詠雙溪州，晏然直與造化遊。", "無邊妙處乃萃此，韙矣君家百尺樓。"]'),
('2a8ba722-9d93-4aee-9087-e2a9400a6fe1','鴻門讌同皋羽作','方鳳','宋','宋诗','song-poetry','','[]','項王重瞳氣蓋世，叱咤喑啞萬夫廢。',128,'全唐诗/poet.song.241000.json','["項王重瞳氣蓋世，叱咤喑啞萬夫廢。", "交割河山杯酒中，弱肉眈眈恣虎視。", "帳列爪士吞鯨鼉，神鋒技擊光蕩摩。", "中有一人亦拔劍，是楚是漢舞婆娑。", "須臾壯夫擁盾入，怒目而語眥盡裂。", "項王喣嫗無一言，楚國孤臣淚流血。", "玉玦何勞再三舉，拂衣竟作彭城死。", "沐猴而冠何足云，君看五采成龍文。"]'),
('4f90352b-b291-43b1-a76b-46203f89f1fd','上元陳丞相宅觀燈有作','方鳳','宋','宋诗','song-poetry','','[]','渴龍入夜吼百川，無數鮫珠迸地圓。',99,'全唐诗/poet.song.241000.json','["渴龍入夜吼百川，無數鮫珠迸地圓。", "星斗撼天半欲落，五花琪樹皆生烟。", "烟燈豈不勝花朵，踏歌何人增坎坷。", "風塵淮北馳羽書，金鼓江城賽燈火。", "君不見狄青宣撫荆湖間，上元張樂晏清班。", "忽然稱疾燈未滅，五更已奪崑崙關。"]'),
('8510f785-51aa-475b-b123-60170b7258a7','遼西曲','方鳳','宋','宋诗','song-poetry','','[]','遼西八月邊風急，塞草凝霜刁斗濕。',96,'全唐诗/poet.song.241000.json','["遼西八月邊風急，塞草凝霜刁斗濕。", "旅雁嗷嗷思婦哀，錦機初罷流黄織。", "并州快剪裁作衣，製成千里寄相思。", "巧盤詰曲同心紐，附繡回旋錦字詩。", "詩長字字愁胸臆，紐比連環解難得。", "解難得時君莫諼，啼紅認取封時痕。"]'),
('62173446-5324-412b-b116-1259b936f219','翠微樓對竹會飲','方鳳','宋','宋诗','song-poetry','','[]','縹渺飛樓修竹裏，珠簾半捲清風起。',96,'全唐诗/poet.song.241000.json','["縹渺飛樓修竹裏，珠簾半捲清風起。", "月明十二畫欄空，美人遥隔湘江水。", "夜深吹徹玉參差，引到丹山綵鳳儀。", "還倚仙翁九節杖，翠雲深處望安期。", "楚調歌殘仍擊節，簷外紛紛落蒼雪。", "樓頭醉卧笑元龍，一片歲寒心似鐵。"]'),
('d3df60ee-abd2-47a9-bd44-7a05412a047c','答柳道傳餉笋','方鳳','宋','宋诗','song-poetry','','[]','東家鼎烹矜大嚼，西家呼盧賽乳酪。',144,'全唐诗/poet.song.241000.json','["東家鼎烹矜大嚼，西家呼盧賽乳酪。", "肉食那知儒素風，似君臭味將無同。", "知我山齋少白粲，隨時易辦松花飯。", "佐食投筯毋乃饞，筠籠新掘來幽巖。", "封題遥寄四五尾，歆然解剝出肌理。", "和以芹根及薤芽，醯鹽澹著香無涯。", "黄虀脫粟絕滓膩，得此加餐檢殘笥。", "手把南華讀一過，詩思陡湧如春波。", "題箑酬君君莫笑，胸中成竹諧清調。"]'),
('837e9774-fbf6-4854-8f9a-16c24a2430ed','送吳立夫','方鳳','宋','宋诗','song-poetry','','[]','有人儲書塞中腸，不能奮發爲辭章。',179,'全唐诗/poet.song.241000.json','["有人儲書塞中腸，不能奮發爲辭章。", "亦有英姿限時命，坎坷名不登文場。", "吳子妙年即秀穎，隻字過眼終無忘。", "文如翻水溢萬斛，晝夜不舍流湯湯。", "于今東南聚雋彥，奭然一發能穿楊。", "二十脫穎客毛遂，名登十九能低昂。", "亦如列宿二十八，有捄天畢施之行。", "况子平生志遠遊，塊坐已能窮八荒。", "從茲北上有歷覽，徑到洪河經呂梁。", "青徐平野望不極，半萬里程趨冀方。", "君不見龍門探奇氣益壯，文豪千載同翱翔。"]'),
('fa6b8340-c40d-4b5d-9dad-fb3150dc56da','北山道中','方鳳','宋','宋诗','song-poetry','','[]','起犯春霜一徑寒，清遊乘興約吟鞍。',64,'全唐诗/poet.song.241000.json','["起犯春霜一徑寒，清遊乘興約吟鞍。", "眼中最恨友朋少，塵外頻聞山水寬。", "溪落舊痕枯野埠，樹浮空翠濕危欄。", "巖頭幾處懸冰白，已作羣羊化石看。"]'),
('dafb74cd-55e3-47b5-ab55-76703bc8a69d','客有問金華勝遊者以詩敘其概','方鳳','宋','宋诗','song-poetry','','[]','赤松上下雨霏微，八詠樓頭重拂衣。',64,'全唐诗/poet.song.241000.json','["赤松上下雨霏微，八詠樓頭重拂衣。", "西港晴來汀草長，北巖幽處洞泉飛。", "風敲定磬鹿春過，月滿丹臺鶴夜歸。", "歷覽因知古詞客，盛誇雲夢未全非。"]'),
('c0b08fa2-e581-4f2d-90e8-f392f0b104eb','吳清翁石橋','方鳳','宋','宋诗','song-poetry','','[]','金椎誰奮破山霆，趨石渾疑走六丁。',64,'全唐诗/poet.song.241000.json','["金椎誰奮破山霆，趨石渾疑走六丁。", "間道便須橫螮蝀，長竿先已豎蜻蜓。", "濟川作略君堪紀，吟雪行藏我欲經。", "領取溪山好風月，更看高架翼然亭。"]'),
('278f7239-3287-493d-a8d4-ef03eb75d252','冒雨渡浦陽江','方鳳','宋','宋诗','song-poetry','','[]','癡雲千頃壓江堧，寂寂籃輿破午烟。',64,'全唐诗/poet.song.241000.json','["癡雲千頃壓江堧，寂寂籃輿破午烟。", "樹杪樓臺看近郭，渡頭波浪忽滔天。", "舟依曲港難迴楫，徑轉高陵每得筌。", "誰向龍山誇海國，一聲鐵笛女牆邊。"]'),
('07ac4526-c480-4291-9ef8-d9f9f93a0f61','春日集張元吉兄弟宅','方鳳','宋','宋诗','song-poetry','','[]','銜盃不讓阮家風，况復陽春白雪融。',64,'全唐诗/poet.song.241000.json','["銜盃不讓阮家風，况復陽春白雪融。", "調合西堂琴欲響，情深北海酒難空。", "詩題歷歷諸名跡，酬和年年幾醉翁。", "未盡清狂尚期約，同看燈火月明中。"]'),
('675fc7eb-232d-4a24-b60b-83e46ff6b197','寄梁隆吉','方鳳','宋','宋诗','song-poetry','','[]','羨爾英年早息機，羅衣脫却著荷衣。',64,'全唐诗/poet.song.241000.json','["羨爾英年早息機，羅衣脫却著荷衣。", "黄醪白釀供吟咏，野史稗官漫是非。", "舊事橫看東澗水，新餐誰共北山薇。", "金閨玉樹思君甚，采藥春華歸未歸。"]'),
('3b69d47e-9782-49af-8e4e-1db8dd7c0daf','讀西峰寺壁間詩','方鳳','宋','宋诗','song-poetry','','[]','出郭幽探約里程，竹籬小語忽雲生。',64,'全唐诗/poet.song.241000.json','["出郭幽探約里程，竹籬小語忽雲生。", "寺藏密樹磬聲得，客染流霞暑氣清。", "煮茗每聞松湍落，長苔半與石床平。", "何來老衲吟魂盡，滿壁多題世外情。"]'),
('948311a7-14b1-4dea-ae4b-eb4a726fc202','九日同皋羽子善游白石龍湫用杜老九日藍田韻','方鳳','宋','宋诗','song-poetry','','[]','塵埃隔處地天寬，選勝携觴且笑歡。',64,'全唐诗/poet.song.241000.json','["塵埃隔處地天寬，選勝携觴且笑歡。", "不惜逍遥投杖屐，何妨磅礴解衣冠。", "晴餘嵐重雨猶落，秋老天高酒易寒。", "世事悠悠雙眼外，與君飛瀑醉中看。"]'),
('1f574866-0f3f-408e-bb17-c24a165bc909','止所吳公輓歌辭  其一','方鳳','宋','宋诗','song-poetry','','[]','嶽嶽文豪共識名，歸來風月恣彈評。',64,'全唐诗/poet.song.241000.json','["嶽嶽文豪共識名，歸來風月恣彈評。", "竹階過鶴窺棋局，花院流鶑和樂聲。", "燈酌蕭閒期鄭老，盆歌疏達慕莊生。", "何來排闥緋衣召，天上樓傳白玉成。"]'),
('45fdc18c-edc6-46cb-882f-cc3a10a3c302','止所吳公輓歌辭  其二','方鳳','宋','宋诗','song-poetry','','[]','倦客囊書栖舊林，如蘭交契歲寒心。',64,'全唐诗/poet.song.241000.json','["倦客囊書栖舊林，如蘭交契歲寒心。", "行藏與共盟猶在，生死俄分感獨深。", "喪寶可堪埋白璧，知音端合鑄黄金。", "茱萸遍插明朝是，回首西風淚滿襟。"]'),
('86da9ae2-cb43-4c66-bc3a-6fcbdf4bdce4','吳良貴雪中歸','方鳳','宋','宋诗','song-poetry','','[]','別時黄菊映郊扉，轉眼寒風刮毳衣。',64,'全唐诗/poet.song.241000.json','["別時黄菊映郊扉，轉眼寒風刮毳衣。", "豐瑞正當三白見，修程適自四明歸。", "因思水國銀兼浪，勝看山鄉玉作圍。", "老去羊羔總陳迹，坐氈猶喜客堪依。"]'),
('ff1320a6-70dd-49ba-ab36-ce79a7037d56','吳仲恭翠微樓九日落成和謝皋羽  其一','方鳳','宋','宋诗','song-poetry','','[]','樓成楚菊芳菲候，客湊齊山酩酊期。',64,'全唐诗/poet.song.241000.json','["樓成楚菊芳菲候，客湊齊山酩酊期。", "與俗相追何日了，登高一嘯洗秋悲。", "望窮碧落鴻飛外，歸戀清樽月到時。", "野服從茲近蘿薜，西風塵土莫輕吹。"]'),
('37f7fc1a-2e5a-4323-b856-89301e630b81','吳仲恭翠微樓九日落成和謝皋羽  其二','方鳳','宋','宋诗','song-poetry','','[]','慈竹堂陰長露梢，又添傑閣俯江郊。',64,'全唐诗/poet.song.241000.json','["慈竹堂陰長露梢，又添傑閣俯江郊。", "眼空霞錦疑鴻字，手摘松枝礙鶴巢。", "野月散衣閒弄笛，墟烟隔水見編茅。", "望中尚與漁樵接，若處真能廣絕交。"]'),
('2c02f9d6-5e57-498a-b760-863a261e7e38','贈張叔元鎮帥','方鳳','宋','宋诗','song-poetry','','[]','越東佳氣鬰巃嵷，捉鼻馨名久識公。',176,'全唐诗/poet.song.241000.json','["越東佳氣鬰巃嵷，捉鼻馨名久識公。", "結髮蚤看翔藝苑，濡毫頻見屬詩筒。", "棄書忽學萬人敵，秉鉞尤誇一世雄。", "拔距三千堪敵愾，歌鐘二八陋和戎。", "長驅誓擣燕幽北，大纛旋移浦汭東。", "重鞏河山襄帝力，時垂竹帛勵臣忠。", "東南半壁騰王氣，杞梓全材恃將功。", "鵝鴨幾驚消玉壘，熊羆屢奮壯金墉。", "璽書褒錫恩原厚，節鉞招綏德愈隆。", "羣策更能延俊彥，衆謳先已徧旄童。", "深仁共頌綿瓜瓞，偉績還期勒華嵩。"]'),
('84af934b-097f-4a19-93d2-3e1073b6fc5b','三吳漫遊集唐  其一','方鳳','宋','宋诗','song-poetry','','[]','江上巍巍萬歲樓，今春花鳥作邊愁。',32,'全唐诗/poet.song.241000.json','["江上巍巍萬歲樓，今春花鳥作邊愁。", "傷心欲問南朝事，鳳去臺空江自流。"]'),
('31293d63-2629-43f4-a143-ba22c3be57b5','三吳漫遊集唐  其二','方鳳','宋','宋诗','song-poetry','','[]','願及行春更一年，中流簫鼓振樓船。',32,'全唐诗/poet.song.241000.json','["願及行春更一年，中流簫鼓振樓船。", "不知何處吹蘆管，城外風悲欲暮天。"]'),
('0a5e6823-1918-4e1b-9195-7ba5cb52cef0','三吳漫遊集唐  其三','方鳳','宋','宋诗','song-poetry','','[]','不堪惆悵滿離盃，水碧沙明兩岸苔。',32,'全唐诗/poet.song.241000.json','["不堪惆悵滿離盃，水碧沙明兩岸苔。", "無限塞鴻飛不度，二陵風雨自東來。"]'),
('586c5d8e-76b1-472a-8938-240747303ffd','三吳漫遊集唐  其四','方鳳','宋','宋诗','song-poetry','','[]','孤雲獨鶴共悠悠，別作深宮一段愁。',32,'全唐诗/poet.song.241000.json','["孤雲獨鶴共悠悠，別作深宮一段愁。", "萬乘旌旗何處在，白雲猶似漢時秋。"]'),
('cfefd36e-b908-4671-8340-bd567e42c01e','三吳漫遊集唐  其五','方鳳','宋','宋诗','song-poetry','','[]','華表峨峨有夜霜，海天愁思正茫茫。',32,'全唐诗/poet.song.241000.json','["華表峨峨有夜霜，海天愁思正茫茫。", "遥知漢使蕭關外，泣上龍堆望故鄉。"]'),
('34028ad5-1e47-471d-b7ae-a3528eb7da2e','三吳漫遊集唐  其六','方鳳','宋','宋诗','song-poetry','','[]','塞上風雲接地陰，萬方多難此登臨。',32,'全唐诗/poet.song.241000.json','["塞上風雲接地陰，萬方多難此登臨。", "坐中有老沙場客，霄漢長懸捧日心。"]'),
('cdf7648e-b819-4517-a96b-ca67e5ad6043','三吳漫遊集唐  其七','方鳳','宋','宋诗','song-poetry','','[]','江南江北望烟波，南國浮雲水上多。',32,'全唐诗/poet.song.241000.json','["江南江北望烟波，南國浮雲水上多。", "共說總戎雲鳥陣，中原將帥憶廉頗。"]'),
('e7499754-115a-4590-85bf-45391323930d','三吳漫遊集唐  其八','方鳳','宋','宋诗','song-poetry','','[]','邊風蕭颯動江城，獨上高樓故國情。',32,'全唐诗/poet.song.241000.json','["邊風蕭颯動江城，獨上高樓故國情。", "磧裏征人三十萬，空教弟子學長生。"]'),
('111515d6-5a6f-456f-8632-f8292e966fec','三吳漫遊集唐  其九','方鳳','宋','宋诗','song-poetry','','[]','愁看直北是長安，雲樹深深碧殿寒。',32,'全唐诗/poet.song.241000.json','["愁看直北是長安，雲樹深深碧殿寒。", "心折此時無一寸，夢魂不到關山難。"]'),
('227fcee1-678b-4f5c-808f-3a5d9cd38fa4','三吳漫遊集唐  其一○','方鳳','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭西望楚江分，回首姑蘇是白雲。',32,'全唐诗/poet.song.241000.json','["洞庭西望楚江分，回首姑蘇是白雲。", "今日南湖采薇蕨，何時重謁聖明君。"]'),
('926f78f8-94f8-4f61-a63b-53851eebf9fc','雜詠十首  其一','方鳳','宋','宋诗','song-poetry','','[]','反哺烏曰慈，食母梟名惡。',24,'全唐诗/poet.song.241000.json','["反哺烏曰慈，食母梟名惡。", "如烏莫如梟，人心當自覺。"]'),
('2235f179-ba0f-4c0f-80ee-6348f18520ec','雜詠十首  其二','方鳳','宋','宋诗','song-poetry','','[]','馬舞睨祿山，猴朝識朱溫。',24,'全唐诗/poet.song.241000.json','["馬舞睨祿山，猴朝識朱溫。", "人豈不若獸，變故輒負恩。"]'),
('016c60fb-deb1-440f-a5a9-d6e0b6e3a5c4','雜詠十首  其三','方鳳','宋','宋诗','song-poetry','','[]','鵾鵬奮雲霄，尺鷃棲野草。',24,'全唐诗/poet.song.241000.json','["鵾鵬奮雲霄，尺鷃棲野草。", "物各適其天，夫豈論大小。"]'),
('10246f8c-16f6-472d-b696-492312c8476e','雜詠十首  其四','方鳳','宋','宋诗','song-poetry','','[]','蜂房開戶牖，蟻穴有官守。',24,'全唐诗/poet.song.241000.json','["蜂房開戶牖，蟻穴有官守。", "究竟物皆然，夢幻君知否。"]'),
('c913fe85-74ef-4691-aaa4-cc62ab858c51','雜詠十首  其五','方鳳','宋','宋诗','song-poetry','','[]','小哉蠻觸戰，鄙甚蛙黽怒。',24,'全唐诗/poet.song.241000.json','["小哉蠻觸戰，鄙甚蛙黽怒。", "達人能大觀，本以和平故。"]'),
('e2a94ca1-c8ec-47e1-bf10-cee70097982d','雜詠十首  其六','方鳳','宋','宋诗','song-poetry','','[]','瑞世鳳鳴陽，司晨雞鳴丑。',24,'全唐诗/poet.song.241000.json','["瑞世鳳鳴陽，司晨雞鳴丑。", "呶呶取人憎，亂蟬合緘口。"]'),
('06c55ae1-0485-4df0-820b-e14d9ebc0375','雜詠十首  其七','方鳳','宋','宋诗','song-poetry','','[]','蠶繭每利人，蛛網偏害物。',24,'全唐诗/poet.song.241000.json','["蠶繭每利人，蛛網偏害物。", "利害夐不同，其間僅絲忽。"]'),
('c54e2409-b1af-490f-8b08-d32e26380674','雜詠十首  其八','方鳳','宋','宋诗','song-poetry','','[]','猿啼不窺窗，牛馴常露地。',24,'全唐诗/poet.song.241000.json','["猿啼不窺窗，牛馴常露地。", "伏虎與降龍，此理元無二。"]'),
('7ab6dc76-ee5e-47bb-9f41-920e1abd09bc','雜詠十首  其九','方鳳','宋','宋诗','song-poetry','','[]','解牛中肯綮，相馬外驪黄。',24,'全唐诗/poet.song.241000.json','["解牛中肯綮，相馬外驪黄。", "從知得三昧，意到形自忘。"]'),
('6d7175f4-3180-4e76-905b-25ec7300dae9','雜詠十首  其一○','方鳳','宋','宋诗','song-poetry','','[]','蟻封罅隙地，蛙井咫尺天。',24,'全唐诗/poet.song.241000.json','["蟻封罅隙地，蛙井咫尺天。", "那能致廣大，此道誰爲傳。"]'),
('aa2be7f6-5e31-4ab8-9458-4ebb6353504b','懷古題雪十首 韓王堂雪','方鳳','宋','宋诗','song-poetry','','[]','聖主賢臣千載遇，夜雪皚皚幸其第。',64,'全唐诗/poet.song.241000.json','["聖主賢臣千載遇，夜雪皚皚幸其第。", "直愛榻外非吾家，欲下江南須早計。", "熾炭燒肉錦茵鋪，細君行酒以嫂呼。", "魯論自可相天下，何必區區泥上書。"]'),
('8d82c117-1dd3-4181-85a1-2257e586e34b','懷古題雪十首 伊川門雪','方鳳','宋','宋诗','song-poetry','','[]','定夫中立希賢士，事師河南程叔子。',64,'全唐诗/poet.song.241000.json','["定夫中立希賢士，事師河南程叔子。", "門外雪深三尺絕，假寐覺來猶在此。", "口生鐵石爲肺肝，心欲求道寧知寒。", "他年傳授稱高弟，不愧芳名千萬看。"]'),
('80799b3b-d8f8-409c-b66d-c9542e81df48','懷古題雪十首 蘇武窖雪','方鳳','宋','宋诗','song-poetry','','[]','子卿遠使匈奴國，持節堂堂不肯屈。',64,'全唐诗/poet.song.241000.json','["子卿遠使匈奴國，持節堂堂不肯屈。", "置之深窖死爲神，饑囓氈衣渴飲雪。", "但懷忠赤自通神，未必長伴羝爲群。", "西風吹墮上林雁，白髮歸來有麒麟。"]'),
('aaf428c2-0f10-4404-a8d1-6d836ee7d683','懷古題雪十首 長安落雪','方鳳','宋','宋诗','song-poetry','','[]','朔風瓊粉如篩墮，四望民居絕煙火。',64,'全唐诗/poet.song.241000.json','["朔風瓊粉如篩墮，四望民居絕煙火。", "路無行蹤門反關，珍重先生獨僵卧。", "洛陽令尹舉孝廉，三冬喜愛照河南。", "有志何妨屢遷擢，要以清操除奸貪。"]'),
('e29d35aa-5687-48d3-a478-1ae39b8f735b','懷古題雪十首 李伋郊雪','方鳳','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖無舟波凍合，孤山照人如玉立。',64,'全唐诗/poet.song.241000.json','["西湖無舟波凍合，孤山照人如玉立。", "太守徒行訪隠君，門前凈掃茶煙濕。", "坐談會公幽懷開，寒梅吹香當酒盃。", "隠君平生厭城市，雪霽何妨公再來。"]'),
('124c2885-ef3c-45c2-b5da-9bcf393c649b','懷古題雪十首 韓愈關雪','方鳳','宋','宋诗','song-poetry','','[]','浮屠誕謾唐宗惑，大內王宮迎佛骨。',64,'全唐诗/poet.song.241000.json','["浮屠誕謾唐宗惑，大內王宮迎佛骨。", "披忠諫嬰直逆鱗，遠貶潮陽蛟鱷窟。", "雪寒藍橋道路危，車兒追陪兒女悲。", "覉窮困苦暫時事，朝食南海無終期。"]'),
('57ae3da7-f513-41c7-98b5-23dd8a42a47c','懷古題雪十首 陶穀茶雪','方鳳','宋','宋诗','song-poetry','','[]','馮夷翦水飛九垓，瓊花萬樹先春開。',64,'全唐诗/poet.song.241000.json','["馮夷翦水飛九垓，瓊花萬樹先春開。", "玉堂學士愛清味，取雪烹茶真快哉。", "堪笑嬌娥黨家妓，歌舞但知趨富貴。", "豈知吾儒儉素心，不誇文綺膏粱味。"]'),
('5896ea57-cf6a-4248-bc51-5c83f6776c65','懷古題雪十首 孫康書雪','方鳳','宋','宋诗','song-poetry','','[]','富貴爨炊蠟代薪，貧家讀書夜無燈。',64,'全唐诗/poet.song.241000.json','["富貴爨炊蠟代薪，貧家讀書夜無燈。", "案頭寒雪三光白，欲益披卷未所能。", "長繩難繫青春日，功業良由勤苦得。", "獬冠他日立朝端，寒士聲名滿邦國。"]'),
('e0670291-113e-43bd-b16c-9a98cfb76ac9','懷古題雪十首 李愬懷雪','方鳳','宋','宋诗','song-poetry','','[]','有唐御極天所命，蠢爾孽臣作梟獍。',64,'全唐诗/poet.song.241000.json','["有唐御極天所命，蠢爾孽臣作梟獍。", "克壯謀猷斷乃成，出師不愁天雪盛。", "銜枚夜渡張柴村，西平有子國有孫。", "懸弧不固兵徑入，擒取渠魁獻至尊。"]'),
('d5904f4b-165e-46bf-92c5-d44fe2572e70','觀陽山大石','方鳳','宋','宋诗','song-poetry','','[]','殷勤挾小艇，迤邐登大石。',120,'全唐诗/poet.song.241000.json','["殷勤挾小艇，迤邐登大石。", "怪險若神造，幽闃真鬼宅。", "凌漢龍頭昂，負重龜背磔。", "倒拽萬牛喘，列坐千人窄。", "眇視笑一拳，端拜俯半額。", "憑肩護脛酸，呼酒鎮心忒。", "古壁剝舊題，灰竇礙頹屐。", "甫快雨忽晴，剛醉日欲夕。", "老禪嗜文詞，短卷盈咫尺。", "揮毫神欲飛，雲開萬峰碧。"]'),
('6b3df769-dfc8-482d-8ccc-1dc469645680','寄雲林上人','方鳳','宋','宋诗','song-poetry','','[]','竹杖芒鞋去未能，鞅塵十丈苦相仍。',32,'全唐诗/poet.song.241000.json','["竹杖芒鞋去未能，鞅塵十丈苦相仍。", "去來今了三生事，輸爾寒巖宴坐僧。"]'),
('35d12d8a-22ac-4522-9444-21c40f96bc7a','題春壽堂','方鳳','宋','宋诗','song-poetry','','[]','人皆構堂思奉身，吳氏構堂獨養親。',128,'全唐诗/poet.song.241000.json','["人皆構堂思奉身，吳氏構堂獨養親。", "人皆種花圖炫眸，吳氏樹萱可忘憂。", "慈親鶴髮壽且康，昆弟列羅如雁行。", "旦暮升堂直滫瀡，娛親嬉舞斑衣裳。", "子能順親親顔悅，和氣盈盈藹堂室。", "春風荆樹發條枝，夜雨芝蘭秀芽茁。", "由來孝道通神明，吳氏家世應昌榮。", "他年移孝事君主，定使芳名書信史。"]'),
('ae9d364c-9df7-40ae-a0f8-27d2ba0ddae3','壽東先生','方鳳','宋','宋诗','song-poetry','','[]','黄菊香留晚節中，回頭猶記矢懸蓬。',64,'全唐诗/poet.song.241000.json','["黄菊香留晚節中，回頭猶記矢懸蓬。", "細看南極壽者相，全與東山老子同。", "向日閭里門轉大，此時庠序棟方隆。", "解衣推食雖私感，普爲儒流更祝公。"]'),
('6c6cf9e7-cc1a-43b9-aad4-c34123bbc0e7','寄功父','方鳳','宋','宋诗','song-poetry','','[]','遺風日遠日相疏，七載歸來非故廬。',64,'全唐诗/poet.song.241000.json','["遺風日遠日相疏，七載歸來非故廬。", "烈屋漫思懸艾虎，忠臣空腹葬江魚。", "雲霽志氣消磨後，錦繡園林破碎餘。", "酒盞更須拚酩酊，詩簡聊示寄勤渠。"]'),
('8fd0d143-8232-4dc5-9816-45b1f1bb0817','餞續古贅趙氏','方鳳','宋','宋诗','song-poetry','','[]','年華冠带玉輝輝，本悟秦風出贅扉。',64,'全唐诗/poet.song.241000.json','["年華冠带玉輝輝，本悟秦風出贅扉。", "爲要權宜就家室，不妨暫時別庭幃。", "化推正始餘麟厚，占協和鳴待鳳飛。", "老我相親垂十載，指期觀子共于歸。"]'),
('d09c5c91-a90d-427c-b43b-b3a68a6f0ec4','和陶淵明九日閒居韻','方鳳','宋','宋诗','song-poetry','','[]','小軒開傍小籬東，不但淵明有晉風。',64,'全唐诗/poet.song.241000.json','["小軒開傍小籬東，不但淵明有晉風。", "惟見幽芳爲友發，誰知清興與心同。", "猶憐推檻秋難老，更喜升樽酒不空。", "根本既能深保護，何愁霜雪傲寒冬。"]'),
('32f9c63e-670c-4afd-bdc3-f42a650c9960','述志','方鳳','宋','宋诗','song-poetry','','[]','只因生在胡元世，豈將襤褸換羅衣。',64,'全唐诗/poet.song.241000.json','["只因生在胡元世，豈將襤褸換羅衣。", "壯圖落落還中止，高蹈悠悠且遁肥。", "松竹森然真有味，衣冠整飭不須題。", "優游但效商山客，雲谷叢生薤露稀。"]'),
('149c7ead-f14e-4dc6-8661-c3b75f843cd9','述懷','方鳳','宋','宋诗','song-poetry','','[]','避元困守靜庵眠，雞犬無聲樂自然。',64,'全唐诗/poet.song.241000.json','["避元困守靜庵眠，雞犬無聲樂自然。", "石上清吟蘿月小，松間暢飲蘚花斑。", "幽深最似螺螄洞，巖險何須虎豹關。", "今愧縉紳惟隠晦，誰知四皓在商山。"]'),
('26944ff7-1ffe-475d-825b-49cd5c01c54f','對仙華雪懷','方鳳','宋','宋诗','song-poetry','','["\u897f\u6e56"]','仙華萬仞石離離，山上嶄嶄萬壑危。',64,'全唐诗/poet.song.241000.json','["仙華萬仞石離離，山上嶄嶄萬壑危。", "雪與梅花俱在望，琴携野鶴轉相隨。", "清如和靖西湖夜，興如王猷剡上時。", "我欲酬詩追雅調，寒山鳥迹少于飛。"]'),
('8b016464-a7de-481a-a3ce-3d4e32d77872','句','方鳳','宋','宋诗','song-poetry','','[]','耕鋤曉雨有餘地，應接東風無暇時。',16,'全唐诗/poet.song.241000.json','["耕鋤曉雨有餘地，應接東風無暇時。"]'),
('0d65cef9-5856-4772-b4b5-4636b7594c9a','秋懷  其一','連文鳳','宋','宋诗','song-poetry','','[]','草木一何情，榮悴皆有時。',60,'全唐诗/poet.song.241000.json','["草木一何情，榮悴皆有時。", "颯颯凉風至，一夕失華滋。", "壯士撫蕭晨，慷慨令心悲。", "流光日以邁，西風生別離。", "渺渺愁予懷，此懷誰能知。"]'),
('93a1e6ee-aeef-4c20-9cc0-9f429c30ffd6','秋懷  其二','連文鳳','宋','宋诗','song-poetry','','[]','天高正寥泬，深夜羣動閴。',84,'全唐诗/poet.song.241000.json','["天高正寥泬，深夜羣動閴。", "秋聲從何來，淅瀝復蕭瑟。", "須臾忽澎湃，愁思若悽惻。", "罷琴試靜聽，紛紛鳴四壁。", "有如賈少年，流涕重太息。", "時事已凄凉，俛仰一今昔。", "嗟余復何言，抱此長戚戚。"]'),
('31b0dd92-d0ca-4d79-91ad-c7180f5cff49','秋懷  其三','連文鳳','宋','宋诗','song-poetry','','[]','西北多陰風，日夜吹裳衣。',60,'全唐诗/poet.song.241000.json','["西北多陰風，日夜吹裳衣。", "草蟲動機杼，札札鳴聲悲。", "百憂彌中腸，歡樂復何時。", "今日忽已逝，來日未可知。", "且飲以狂藥，酩酊從所之。"]'),
('b0e07b4d-283b-4a1d-a7e6-590c8f15e629','秋懷  其四','連文鳳','宋','宋诗','song-poetry','','[]','漫漫秋夜長，夜長不能寐。',72,'全唐诗/poet.song.241000.json','["漫漫秋夜長，夜長不能寐。", "抱琴出中庭，月影落在地。", "一彈復再彈，聲澹趣亦至。", "誰家箏笛聲，紛紛亂人思。", "音響何急促，忽忽無古意。", "嗟哉鍾儀心，千古獨憔悴。"]'),
('bf1d1052-2580-4eb7-92b9-a6cc13c3bbdd','秋懷  其五','連文鳳','宋','宋诗','song-poetry','','[]','茫茫秋水波，灼灼芙蓉姿。',60,'全唐诗/poet.song.241000.json','["茫茫秋水波，灼灼芙蓉姿。", "采之不盈匊，及此行樂時。", "陽鳥來南翔，玄鳥將西歸。", "羈旅獨牽營，泯默生窮思。", "美人不可見，長歌以自怡。"]'),
('836c57aa-7ff6-44f3-849c-8f7efe6d11bc','秋懷  其六','連文鳳','宋','宋诗','song-poetry','','[]','季鷹真達士，棄宦歸東吳。',96,'全唐诗/poet.song.241000.json','["季鷹真達士，棄宦歸東吳。", "祿無盈寸榮，盎無升斗儲。", "盤桓吳溪上，所樂只在魚。", "懷組夸鄉里，佩印驕妻孥。", "朝從高鳥翔，莫隨舜華枯。", "富貴豈不好，不能少須臾。", "朔風吹塵沙，出門皆畏途。", "抱影廓獨倚，新榮非良圖。"]'),
('4f2d5987-9081-4022-bcaf-e20429ecfd73','秋懷  其七','連文鳳','宋','宋诗','song-poetry','','[]','陰陰陵上柏，離離陵上草。',96,'全唐诗/poet.song.241000.json','["陰陰陵上柏，離離陵上草。", "樵兒與牧豎，躑躅陵上道。", "蛻骨出榛莽，后土不愛寶。", "衰蟬弔寂寞，寒蟾照枯槁。", "白雲散同漫，西風不敢掃。", "蓋棺千年後，既往不能保。", "人生血肉軀，百年終醜老。", "安得紫微書，遺我一火棗。"]'),
('1a76df64-c26d-4782-afaa-d60deb1c73a8','秋懷  其八','連文鳳','宋','宋诗','song-poetry','','[]','娟娟誰家女，軋軋弄機杼。',48,'全唐诗/poet.song.241000.json','["娟娟誰家女，軋軋弄機杼。", "買絲織未成，催租立當戶。", "下機愁向人，顦顇不敢語。", "泣涕走深山，深山更風雨。"]'),
('3d770cff-63ec-472b-82c0-66281ecda5de','秋雨歎','連文鳳','宋','宋诗','song-poetry','','[]','秋雨何紛紛，百草凍欲爛。',108,'全唐诗/poet.song.241000.json','["秋雨何紛紛，百草凍欲爛。", "曈矓不見日，黤曖猶未旦。", "烟雲雜澒洞，霄壤雨漫漶。", "阡陌何由分，涇渭不復判。", "怒觸老木摧，響急猛獸散。", "平陸魚鼈飛，行客鳥鼠竄。", "田禾藜莠興，斗米衾裯換。", "書生破茅屋，展轉長夜半。", "此時蒼生憂，誰知幾百萬。"]'),
('fdbb9371-05e0-4ce7-9919-8975ab62d788','送張仲實游姑蘇','連文鳳','宋','宋诗','song-poetry','','[]','君本吳下居，復作吳下游。',108,'全唐诗/poet.song.241000.json','["君本吳下居，復作吳下游。", "愛此山水佳，役役不得休。", "卓哉太史公，涉獵縱冥搜。", "往躅誰能追，而有蘇子由。", "寥寥百載後，渺渺皆予愁。", "江南地益卑，士習日益媮。", "此行數百里，不過三兩州。", "歐韓不復作，去去將奚求。", "倘君有所得，歸以發我幽。"]'),
('ccd61b75-1d5b-49cb-9d60-bc7db3cbf12a','智果寺拜東坡參寥遺像次韻','連文鳳','宋','宋诗','song-poetry','','[]','吾愛參寥子，遺偈寄真跡。',168,'全唐诗/poet.song.241000.json','["吾愛參寥子，遺偈寄真跡。", "像貌儼如生，鈎畫宛若昔。", "讀此一代文，令人百慮釋。", "又愛東坡老，仙才逈飄逸。", "吟哦月露章，飛奮風雨筆。", "古寺遺清風，殘碑卧白日。", "我來拜祠下，怡然若私覿。", "和之詩與禪，詩禪機籟寂。", "相對兩忘言，終朝不獲一。", "徘徊走風廊，舂容坐苔石。", "於心適有契，所得不患失。", "禪空詩亦空，觀空莫觀色。", "寥寥百載下，無此二騷客。", "買酒爲招魂，欲招不可得。"]'),
('38042aac-3317-49d9-8fa4-4a7797ab9ee5','送人入北求仕','連文鳳','宋','宋诗','song-poetry','','[]','南方有奇士，湖海聲獵獵。',60,'全唐诗/poet.song.241000.json','["南方有奇士，湖海聲獵獵。", "功名志氣銳，不憚遠跋涉。", "春風一片紙，區區無所挾。", "持此欲取償，易於拾秋葉。", "何以贈君言，勉哉耘其業。"]'),
('19655ae3-4cdf-4c6f-ac1e-fa0cae8b31af','慈烏','連文鳳','宋','宋诗','song-poetry','','[]','步出東南林，啞啞聞哀音。',60,'全唐诗/poet.song.241000.json','["步出東南林，啞啞聞哀音。", "哀音不堪聞，而有反哺心。", "子母誰無情，爾情抑何深。", "昔人稱爾孝，鳥中之曾參。", "人於物最靈，奈何不如禽。"]');
